{
  "name": "Mokytojo Refleksijos Asistentas",
  "description": "Programėlė skirta mokytojams analizuoti mokinių apklausų duomenis ir atlikti gilią pedagoginę refleksiją pagal nustatytą metodiką.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface SurveyRow {
  [key: string]: string;
}

export interface QuestionSummary {
  question: string;
  counts: {
    [answer: string]: number;
  };
  total: number;
  averageScore: number;
}

export interface ReflectionData {
  observations: string;
  strengths: string;
  improvements: string;
  surprises: string;
  heartFeelings: string;
  headThoughts: string;
  actionStop: string;
  actionStart: string;
  actionContinue: string;
  nextSteps: string;
}

export enum AppStep {
  UPLOAD = 'UPLOAD',
  ANALYSIS = 'ANALYSIS',
  REFLECTION = 'REFLECTION',
  REPORT = 'REPORT'
}

export const LIKERT_VALUES: { [key: string]: number } = {
  "Visiškai sutinku": 5,
  "Labiau sutinku": 4,
  "Iš dalies": 3,
  "Labiau nesutinku": 2,
  "Visiškai nesutinku": 1,
  "Visiškai nesutinku.": 1, // Handle possible variations
  "Visiškai sutinku.": 5
};

import { GoogleGenAI, Type } from "@google/genai";
import { QuestionSummary } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAIInsights = async (summaries: QuestionSummary[], openFeedback: string[]) => {
  const prompt = `
    Esi švietimo ekspertas. Tau pateikiama mokinių apklausos apie mokytojo pamokas santrauka. 
    Analizuok šiuos duomenis ir padėk mokytojui atlikti refleksiją.

    DUOMENŲ SANTRAUKA:
    ${JSON.stringify(summaries)}

    ATVIRI KOMENTARAI:
    ${openFeedback.join("\n")}

    Remiantis šiais duomenimis, sugeneruok trumpą įžvalgą šioms kategorijoms lietuvių kalba:
    1. Pagrindinės stiprybės (kur mokiniai labiausiai sutinka, kas jiems patinka).
    2. Tobulintinos sritys (kur įvertinimai žemesni).
    3. Galimi netikėtumai ar dėsningumai.

    Atsakymą pateik JSON formatu.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            strengths: { type: Type.STRING },
            improvements: { type: Type.STRING },
            insights: { type: Type.STRING }
          },
          required: ["strengths", "improvements", "insights"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini AI error:", error);
    return {
      strengths: "Nepavyko sugeneruoti įžvalgų automatiškai.",
      improvements: "Prašome peržiūrėti duomenis rankiniu būdu.",
      insights: ""
    };
  }
};

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [data, setData] = useState<SurveyRow[]>([]);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '',
    strengths: '',
    improvements: '',
    surprises: '',
    heartFeelings: '',
    headThoughts: '',
    actionStop: '',
    actionStart: '',
    actionContinue: '',
    nextSteps: ''
  });

  const handleDataParsed = (rows: SurveyRow[]) => {
    setData(rows);
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;

    const headers = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    // Assuming first column is timestamp, skip it
    headers.slice(1).forEach(header => {
      // Check if it's the open-ended feedback column (usually the last or contains keywords)
      if (header.toLowerCase().includes('idėja') || header.toLowerCase().includes('pasiūlymas') || header.toLowerCase().includes('komentar')) {
        rows.forEach(row => {
          if (row[header] && row[header].trim()) feedback.push(row[header]);
        });
      } else {
        const counts: { [answer: string]: number } = {};
        let sum = 0;
        let validCount = 0;

        rows.forEach(row => {
          const val = row[header];
          if (val) {
            counts[val] = (counts[val] || 0) + 1;
            if (LIKERT_VALUES[val]) {
              sum += LIKERT_VALUES[val];
              validCount++;
            }
          }
        });

        newSummaries.push({
          question: header,
          counts,
          total: rows.length,
          averageScore: validCount > 0 ? sum / validCount : 0
        });
      }
    });

    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, openFeedback, aiInsights]);

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Header */}
      <header className="bg-indigo-700 text-white py-6 shadow-lg mb-8">
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-2">
              <i className="fas fa-chalkboard-teacher"></i>
              Mokytojo Refleksijos Asistentas
            </h1>
            <p className="text-indigo-100 text-sm">Pagal mokinių apklausos rezultatus</p>
          </div>
          {step !== AppStep.UPLOAD && (
            <button 
              onClick={() => { if(confirm('Ar tikrai norite pradėti iš naujo?')) window.location.reload(); }}
              className="text-xs bg-indigo-600 hover:bg-indigo-500 px-3 py-1 rounded transition"
            >
              Pradėti iš naujo
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-4">
        {step === AppStep.UPLOAD && (
          <div className="max-w-2xl mx-auto mt-12">
            <CSVUpload onParsed={handleDataParsed} />
            <div className="mt-8 bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <h3 className="font-semibold text-gray-800 mb-2">Kaip tai veikia?</h3>
              <ul className="text-sm text-gray-600 space-y-2 list-disc pl-5">
                <li>Įkelkite CSV failą, eksportuotą iš Google Forms ar MS Forms.</li>
                <li>Sistema automatiškai sugrupuos atsakymus ir paskaičiuos vidurkius.</li>
                <li>AI padės identifikuoti stiprybes ir tobulintinas sritis.</li>
                <li>Atliksite žingsnis po žingsnio refleksiją pagal metodinę medžiagą.</li>
              </ul>
            </div>
          </div>
        )}

        {step === AppStep.ANALYSIS && (
          <SummaryDashboard 
            summaries={summaries} 
            feedback={openFeedback} 
            aiInsights={aiInsights}
            isAnalyzing={isAnalyzing}
            onNext={() => setStep(AppStep.REFLECTION)} 
          />
        )}

        {step === AppStep.REFLECTION && (
          <ReflectionWizard 
            reflection={reflection} 
            setReflection={setReflection}
            onComplete={() => setStep(AppStep.REPORT)}
            onBack={() => setStep(AppStep.ANALYSIS)}
          />
        )}

        {step === AppStep.REPORT && (
          <div className="max-w-4xl mx-auto bg-white p-8 rounded-2xl shadow-xl border border-indigo-100">
            <div className="flex justify-between items-start mb-8 border-b pb-6">
              <div>
                <h2 className="text-3xl font-bold text-gray-900">Mano Refleksijos Ataskaita</h2>
                <p className="text-gray-500">Parengta: {new Date().toLocaleDateString('lt-LT')}</p>
              </div>
              <button 
                onClick={() => window.print()} 
                className="bg-indigo-600 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-indigo-700 transition shadow-md"
              >
                <i className="fas fa-print"></i> Spausdinti / PDF
              </button>
            </div>

            <section className="space-y-8">
              <div className="grid md:grid-cols-2 gap-6">
                <div className="bg-indigo-50 p-6 rounded-xl">
                  <h3 className="font-bold text-indigo-900 mb-3 flex items-center gap-2">
                    <i className="fas fa-eye"></i> Pastebėjimai
                  </h3>
                  <p className="text-gray-700 whitespace-pre-wrap">{reflection.observations}</p>
                </div>
                <div className="bg-green-50 p-6 rounded-xl">
                  <h3 className="font-bold text-green-900 mb-3 flex items-center gap-2">
                    <i className="fas fa-star"></i> Stiprybės
                  </h3>
                  <p className="text-gray-700 whitespace-pre-wrap">{reflection.strengths}</p>
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-6">
                <div className="bg-amber-50 p-6 rounded-xl">
                  <h3 className="font-bold text-amber-900 mb-3 flex items-center gap-2">
                    <i className="fas fa-chart-line"></i> Tobulinimo sritys
                  </h3>
                  <p className="text-gray-700 whitespace-pre-wrap">{reflection.improvements}</p>
                </div>
                <div className="bg-purple-50 p-6 rounded-xl">
                  <h3 className="font-bold text-purple-900 mb-3 flex items-center gap-2">
                    <i className="fas fa-question-circle"></i> Netikėtumai
                  </h3>
                  <p className="text-gray-700 whitespace-pre-wrap">{reflection.surprises}</p>
                </div>
              </div>

              <div className="bg-red-50 p-6 rounded-xl border border-red-100">
                <h3 className="font-bold text-red-900 mb-3 flex items-center gap-2 text-xl">
                  <i className="fas fa-heart"></i> Kaip jaučiasi ŠIRDIS?
                </h3>
                <p className="text-gray-700 italic text-lg whitespace-pre-wrap">"{reflection.heartFeelings}"</p>
              </div>

              <div className="bg-blue-50 p-6 rounded-xl border border-blue-100">
                <h3 className="font-bold text-blue-900 mb-3 flex items-center gap-2 text-xl">
                  <i className="fas fa-brain"></i> Ką mąsto GALVA?
                </h3>
                <p className="text-gray-700 text-lg whitespace-pre-wrap">{reflection.headThoughts}</p>
              </div>

              <div className="border-t pt-8">
                <h3 className="text-2xl font-bold text-gray-900 mb-6 flex items-center gap-3">
                  <i className="fas fa-rocket text-indigo-600"></i> Veiksmų planas (Imkis veiksmų)
                </h3>
                <div className="grid md:grid-cols-3 gap-6">
                  <div className="border-2 border-red-200 p-5 rounded-xl text-center">
                    <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-3">
                      <i className="fas fa-stop text-red-600"></i>
                    </div>
                    <h4 className="font-bold text-red-700 mb-2 uppercase text-sm tracking-wider">Nustosiu daryti</h4>
                    <p className="text-gray-600 text-sm whitespace-pre-wrap">{reflection.actionStop || "---"}</p>
                  </div>
                  <div className="border-2 border-green-200 p-5 rounded-xl text-center">
                    <div className="w-12 h-12 bg-green-100 rounded-full flex items-center justify-center mx-auto mb-3">
                      <i className="fas fa-play text-green-600"></i>
                    </div>
                    <h4 className="font-bold text-green-700 mb-2 uppercase text-sm tracking-wider">Pradėsiu daryti</h4>
                    <p className="text-gray-600 text-sm whitespace-pre-wrap">{reflection.actionStart || "---"}</p>
                  </div>
                  <div className="border-2 border-indigo-200 p-5 rounded-xl text-center">
                    <div className="w-12 h-12 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-3">
                      <i className="fas fa-sync text-indigo-600"></i>
                    </div>
                    <h4 className="font-bold text-indigo-700 mb-2 uppercase text-sm tracking-wider">Toliau darysiu</h4>
                    <p className="text-gray-600 text-sm whitespace-pre-wrap">{reflection.actionContinue || "---"}</p>
                  </div>
                </div>
              </div>

              <div className="bg-gray-900 text-white p-6 rounded-xl mt-8">
                <h4 className="font-bold mb-2">Mano pasižadėjimas:</h4>
                <p className="text-gray-300 italic">Kaip aš sužinosiu, kad mano mokymo praktika keičiasi?</p>
                <p className="mt-4 text-lg border-l-4 border-indigo-500 pl-4">{reflection.nextSteps || "---"}</p>
              </div>
            </section>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { SurveyRow } from '../types';

interface CSVUploadProps {
  onParsed: (data: SurveyRow[]) => void;
}

const CSVUpload: React.FC<CSVUploadProps> = ({ onParsed }) => {
  const [isDragging, setIsDragging] = useState(false);

  const parseCSV = (text: string) => {
    const lines = text.split(/\r?\n/).filter(line => line.trim());
    if (lines.length < 2) return [];

    // Simple CSV parser handling quotes
    const headers = lines[0].split(',').map(h => h.trim().replace(/^"|"$/g, ''));
    const rows: SurveyRow[] = [];

    for (let i = 1; i < lines.length; i++) {
      const rowData: SurveyRow = {};
      const currentLine = lines[i];

      // More robust split that respects quotes (simplified)
      const values = [];
      let currentVal = '';
      let inQuotes = false;
      for (let char of currentLine) {
        if (char === '"') inQuotes = !inQuotes;
        else if (char === ',' && !inQuotes) {
          values.push(currentVal.trim());
          currentVal = '';
        } else {
          currentVal += char;
        }
      }
      values.push(currentVal.trim());

      headers.forEach((header, idx) => {
        rowData[header] = values[idx] || '';
      });
      rows.push(rowData);
    }

    return rows;
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const text = event.target?.result as string;
        const data = parseCSV(text);
        onParsed(data);
      };
      reader.readAsText(file);
    }
  };

  return (
    <div 
      className={`border-4 border-dashed rounded-3xl p-12 text-center transition-all ${
        isDragging ? 'border-indigo-500 bg-indigo-50' : 'border-gray-300 bg-white'
      }`}
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
      onDrop={(e) => { e.preventDefault(); setIsDragging(false); /* handle drop if needed */ }}
    >
      <div className="w-20 h-20 bg-indigo-100 rounded-full flex items-center justify-center mx-auto mb-6">
        <i className="fas fa-file-csv text-3xl text-indigo-600"></i>
      </div>
      <h2 className="text-2xl font-bold text-gray-800 mb-2">Įkelkite apklausos duomenis</h2>
      <p className="text-gray-500 mb-8">Pasirinkite .csv failą, gautą iš Google Sheets eksporto</p>

      <label className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-8 rounded-xl cursor-pointer transition-colors shadow-lg inline-block">
        Pasirinkti failą
        <input 
          type="file" 
          accept=".csv" 
          className="hidden" 
          onChange={handleFileChange} 
        />
      </label>

      <p className="mt-4 text-xs text-gray-400">Palaikomi tik CSV formato failai su kableliu kaip skirtuku.</p>
    </div>
  );
};

export default CSVUpload;

import React from 'react';
import { QuestionSummary } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface SummaryDashboardProps {
  summaries: QuestionSummary[];
  feedback: string[];
  aiInsights: any;
  isAnalyzing: boolean;
  onNext: () => void;
}

const SummaryDashboard: React.FC<SummaryDashboardProps> = ({ 
  summaries, 
  feedback, 
  aiInsights, 
  isAnalyzing,
  onNext 
}) => {
  const chartData = summaries.map(s => ({
    name: s.question.length > 20 ? s.question.substring(0, 20) + '...' : s.question,
    fullName: s.question,
    avg: parseFloat(s.averageScore.toFixed(2))
  })).sort((a, b) => b.avg - a.avg);

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex justify-between items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
        <div>
          <h2 className="text-xl font-bold text-gray-800">Duomenų Analizė</h2>
          <p className="text-gray-500 text-sm">Iš viso gauta {summaries[0]?.total || 0} atsakymų</p>
        </div>
        <button 
          onClick={onNext}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2 rounded-xl font-bold transition flex items-center gap-2"
        >
          Pereiti prie refleksijos <i className="fas fa-arrow-right"></i>
        </button>
      </div>

      {/* AI Insights Bar */}
      <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl p-6 text-white shadow-xl relative overflow-hidden">
        <div className="relative z-10">
          <h3 className="text-lg font-bold flex items-center gap-2 mb-4">
            <i className="fas fa-magic"></i> AI Įžvalgos
          </h3>
          {isAnalyzing ? (
            <div className="flex items-center gap-3">
              <div className="animate-spin rounded-full h-5 w-5 border-2 border-white border-t-transparent"></div>
              <span>Analizuojami duomenys...</span>
            </div>
          ) : aiInsights ? (
            <div className="grid md:grid-cols-3 gap-6">
              <div className="bg-white/10 p-4 rounded-xl backdrop-blur-sm">
                <h4 className="font-bold text-indigo-100 text-xs uppercase mb-2">Stiprybės</h4>
                <p className="text-sm">{aiInsights.strengths}</p>
              </div>
              <div className="bg-white/10 p-4 rounded-xl backdrop-blur-sm">
                <h4 className="font-bold text-indigo-100 text-xs uppercase mb-2">Tobulintinos sritys</h4>
                <p className="text-sm">{aiInsights.improvements}</p>
              </div>
              <div className="bg-white/10 p-4 rounded-xl backdrop-blur-sm">
                <h4 className="font-bold text-indigo-100 text-xs uppercase mb-2">Įžvalgos</h4>
                <p className="text-sm">{aiInsights.insights}</p>
              </div>
            </div>
          ) : (
            <p>Nepavyko gauti AI įžvalgų. Peržiūrėkite diagramas žemiau.</p>
          )}
        </div>
        <i className="fas fa-brain absolute -bottom-4 -right-4 text-white/10 text-9xl"></i>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">
        {/* Chart Column */}
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
            <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
              <i className="fas fa-chart-bar text-indigo-500"></i> Vidutiniai įvertinimai pagal klausimus
            </h3>
            <div className="h-80">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} layout="vertical" margin={{ left: 20, right: 30 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f0f0f0" />
                  <XAxis type="number" domain={[0, 5]} ticks={[1,2,3,4,5]} hide />
                  <YAxis 
                    dataKey="name" 
                    type="category" 
                    width={150} 
                    tick={{ fontSize: 10, fill: '#6b7280' }} 
                  />
                  <Tooltip 
                    cursor={{fill: '#f3f4f6'}}
                    content={({active, payload}) => {
                      if (active && payload && payload.length) {
                        return (
                          <div className="bg-gray-900 text-white p-3 rounded-lg shadow-xl text-xs max-w-xs">
                            <p className="font-bold mb-1">{payload[0].payload.fullName}</p>
                            <p className="text-indigo-300">Vidurkis: {payload[0].value} / 5</p>
                          </div>
                        );
                      }
                      return null;
                    }}
                  />
                  <Bar dataKey="avg" radius={[0, 4, 4, 0]} barSize={20}>
                    {chartData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.avg > 4 ? '#10b981' : entry.avg > 3 ? '#6366f1' : '#f59e0b'} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="grid md:grid-cols-2 gap-4">
            {summaries.slice(0, 4).map((s, idx) => (
              <div key={idx} className="bg-white p-4 rounded-xl border border-gray-100 flex items-center justify-between">
                <div className="flex-1 pr-4">
                  <p className="text-xs text-gray-500 line-clamp-1">{s.question}</p>
                  <p className="font-bold text-gray-800">Vidurkis: {s.averageScore.toFixed(2)}</p>
                </div>
                <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-bold text-sm ${
                  s.averageScore > 4 ? 'bg-green-500' : s.averageScore > 3 ? 'bg-indigo-500' : 'bg-amber-500'
                }`}>
                  {s.averageScore.toFixed(1)}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Feedback Column */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col max-h-[600px]">
          <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
            <i className="fas fa-comment-dots text-pink-500"></i> Mokinių komentarai
          </h3>
          <div className="overflow-y-auto space-y-4 flex-1 pr-2 custom-scrollbar">
            {feedback.length > 0 ? feedback.map((f, idx) => (
              <div key={idx} className="bg-gray-50 p-4 rounded-xl border-l-4 border-indigo-400">
                <p className="text-sm text-gray-700 italic">"{f}"</p>
              </div>
            )) : (
              <p className="text-gray-400 text-sm text-center py-12">Laisvų komentarų nebuvo pateikta.</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SummaryDashboard;

import React, { useState } from 'react';
import { ReflectionData } from '../types';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  onComplete: () => void;
  onBack: () => void;
}

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kai žiūriu į apklausų rezultatus, ką aš pastebiu?",
      fields: [
        { 
          key: 'observations', 
          label: "Pasižymėk pastebėjimus (nedarydamas išvadų)", 
          placeholder: "Pvz.: Pastebiu, kad 80% mokinių visiškai sutinka su teiginiu apie pagalbą..."
        }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės ir tobulintinos sritys",
      fields: [
        { 
          key: 'strengths', 
          label: "Kurie rezultatai buvo stiprūs / kuriais didžiuojiesi?", 
          placeholder: "Mano stiprybė yra..."
        },
        { 
          key: 'improvements', 
          label: "Kurias tobulintinas sritis matai?", 
          placeholder: "Norėčiau patobulinti..."
        },
        { 
          key: 'surprises', 
          label: "Netikėtumai ir klausimai", 
          placeholder: "Nustebino tai, kad..."
        }
      ]
    },
    {
      title: "3. Galva ir Širdis",
      description: "Pareflektuok savo GALVA ir ŠIRDIMI",
      fields: [
        { 
          key: 'heartFeelings', 
          label: "Kaip jaučiasi tavo ŠIRDIS dėl mokinių atsakymų?", 
          placeholder: "Jaučiuosi įkvėpta / šiek tiek nerimauju dėl...",
          icon: "fa-heart text-red-500"
        },
        { 
          key: 'headThoughts', 
          label: "Ką mąsto tavo GALVA apie šiuos atsakymus?", 
          placeholder: "Racionaliai mąstant, šie duomenys rodo...",
          icon: "fa-brain text-blue-500"
        }
      ]
    },
    {
      title: "4. Veiksmų planas",
      description: "Imkis veiksmų dėl rezultatų",
      fields: [
        { 
          key: 'actionStop', 
          label: "Ką tu nustosi daryti?", 
          placeholder: "Nustosiu per daug laiko skirti...",
          icon: "fa-stop text-red-500"
        },
        { 
          key: 'actionStart', 
          label: "Ką tu pradėsi daryti?", 
          placeholder: "Pradėsiu taikyti naują metodą...",
          icon: "fa-play text-green-500"
        },
        { 
          key: 'actionContinue', 
          label: "Ką tu ir toliau darysi?", 
          placeholder: "Toliau skatinsiu mokinius...",
          icon: "fa-sync text-indigo-500"
        },
        { 
          key: 'nextSteps', 
          label: "Kaip aš sužinosiu, kad mano mokymo praktika keičiasi?", 
          placeholder: "Pokytį matysiu per..."
        }
      ]
    }
  ];

  const handleInputChange = (key: keyof ReflectionData, value: string) => {
    setReflection(prev => ({ ...prev, [key]: value }));
  };

  const next = () => {
    if (currentStep < steps.length - 1) {
      setCurrentStep(currentStep + 1);
      window.scrollTo(0, 0);
    } else {
      onComplete();
    }
  };

  const prev = () => {
    if (currentStep > 0) {
      setCurrentStep(currentStep - 1);
      window.scrollTo(0, 0);
    } else {
      onBack();
    }
  };

  return (
    <div className="max-w-4xl mx-auto animate-fade-in">
      {/* Progress Bar */}
      <div className="flex justify-between mb-8 px-4">
        {steps.map((_, idx) => (
          <div key={idx} className="flex flex-col items-center">
            <div className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-300 ${
              idx <= currentStep ? 'bg-indigo-600 text-white' : 'bg-gray-200 text-gray-500'
            }`}>
              {idx + 1}
            </div>
            <div className={`h-1 w-full mt-2 rounded-full ${idx <= currentStep ? 'bg-indigo-600' : 'bg-gray-200'}`}></div>
          </div>
        ))}
      </div>

      <div className="bg-white p-8 rounded-2xl shadow-lg border border-gray-100">
        <header className="mb-8">
          <h2 className="text-2xl font-bold text-gray-800">{steps[currentStep].title}</h2>
          <p className="text-gray-500">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-8">
          {steps[currentStep].fields.map((field) => (
            <div key={field.key}>
              <label className="block font-bold text-gray-700 mb-2 flex items-center gap-2">
                {field.icon && <i className={`fas ${field.icon}`}></i>}
                {field.label}
              </label>
              <textarea
                value={reflection[field.key as keyof ReflectionData]}
                onChange={(e) => handleInputChange(field.key as keyof ReflectionData, e.target.value)}
                placeholder={field.placeholder}
                className="w-full h-32 p-4 rounded-xl border border-gray-200 focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 transition outline-none resize-none"
              />
            </div>
          ))}
        </div>

        <div className="flex justify-between mt-12 pt-6 border-t border-gray-100">
          <button 
            onClick={prev}
            className="text-gray-500 font-bold hover:text-gray-700 transition px-4 py-2"
          >
            <i className="fas fa-chevron-left mr-2"></i> Atgal
          </button>
          <button 
            onClick={next}
            className="bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3 px-10 rounded-xl transition shadow-lg"
          >
            {currentStep === steps.length - 1 ? 'Pabaigti ir generuoti ataskaitą' : 'Toliau'}
          </button>
        </div>
      </div>

      <div className="mt-8 bg-amber-50 border border-amber-100 p-4 rounded-xl text-amber-800 text-sm flex gap-3">
        <i className="fas fa-lightbulb mt-1"></i>
        <p>Atsakykite nuoširdžiai. Ši refleksija skirta jūsų asmeniniam tobulėjimui ir geresniam ryšiui su mokiniais užmegzti.</p>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React from 'react';
import { QuestionSummary } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell } from 'recharts';

interface SummaryDashboardProps {
  summaries: QuestionSummary[];
  feedback: string[];
  aiInsights: any;
  isAnalyzing: boolean;
  onNext: () => void;
}

const SummaryDashboard: React.FC<SummaryDashboardProps> = ({ 
  summaries, 
  feedback, 
  aiInsights, 
  isAnalyzing,
  onNext 
}) => {
  const chartData = summaries.map(s => ({
    name: s.question.length > 25 ? s.question.substring(0, 25) + '...' : s.question,
    fullName: s.question,
    avg: parseFloat(s.averageScore.toFixed(2))
  })).sort((a, b) => b.avg - a.avg);

  return (
    <div className="space-y-8 animate-slide-up">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white p-6 rounded-2xl shadow-sm border border-gray-100 gap-4">
        <div>
          <h2 className="text-xl font-bold text-gray-800">Duomenų Analizė</h2>
          <p className="text-gray-500 text-sm">Vizualizuoti mokinių atsakymai • {summaries[0]?.total || 0} dalyvių</p>
        </div>
        <button 
          onClick={onNext}
          className="bg-indigo-600 hover:bg-indigo-700 active:scale-95 text-white px-6 py-2.5 rounded-xl font-bold transition-all flex items-center gap-2 shadow-md hover:shadow-lg"
        >
          Pereiti prie refleksijos <i className="fas fa-arrow-right"></i>
        </button>
      </div>

      {/* AI Insights Bar */}
      <div className="bg-gradient-to-br from-indigo-700 via-indigo-600 to-purple-600 rounded-3xl p-8 text-white shadow-xl relative overflow-hidden group">
        <div className="relative z-10">
          <h3 className="text-xl font-bold flex items-center gap-2 mb-6">
            <i className="fas fa-magic animate-pulse-soft"></i> AI Įžvalgos ir Tendencijos
          </h3>
          {isAnalyzing ? (
            <div className="flex flex-col items-center justify-center py-8 gap-4">
              <div className="animate-spin rounded-full h-8 w-8 border-4 border-white/30 border-t-white"></div>
              <span className="text-indigo-100 animate-pulse">Dirbtinis intelektas analizuoja jūsų mokinių atsiliepimus...</span>
            </div>
          ) : aiInsights ? (
            <div className="grid md:grid-cols-3 gap-6">
              {[
                { title: 'Stiprybės', text: aiInsights.strengths, icon: 'fa-thumbs-up', color: 'bg-green-400/20' },
                { title: 'Tobulintinos sritys', text: aiInsights.improvements, icon: 'fa-lightbulb', color: 'bg-amber-400/20' },
                { title: 'Dėsningumai', text: aiInsights.insights, icon: 'fa-brain', color: 'bg-blue-400/20' }
              ].map((item, i) => (
                <div key={i} className={`${item.color} p-5 rounded-2xl backdrop-blur-md border border-white/10 hover:border-white/30 transition-all hover:translate-y-[-2px] duration-300`}>
                  <h4 className="font-bold text-white text-xs uppercase tracking-widest mb-3 flex items-center gap-2">
                    <i className={`fas ${item.icon}`}></i> {item.title}
                  </h4>
                  <p className="text-sm leading-relaxed text-indigo-50">{item.text}</p>
                </div>
              ))}
            </div>
          ) : (
            <p className="text-indigo-100">Nepavyko paruošti AI analizės. Peržiūrėkite diagramas žemiau.</p>
          )}
        </div>
        <i className="fas fa-bolt absolute -bottom-10 -right-10 text-white/5 text-[15rem] transition-transform duration-700 group-hover:scale-110"></i>
      </div>

      <div className="grid lg:grid-cols-3 gap-8">
        {/* Chart Column */}
        <div className="lg:col-span-2 space-y-8">
          <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 transition-shadow hover:shadow-md">
            <h3 className="font-bold text-gray-800 mb-8 flex items-center gap-2">
              <i className="fas fa-chart-bar text-indigo-500"></i> Vidutiniai įvertinimai (1-5)
            </h3>
            <div className="h-[400px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} layout="vertical" margin={{ left: 10, right: 30 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f0f0f0" />
                  <XAxis type="number" domain={[0, 5]} ticks={[1,2,3,4,5]} hide />
                  <YAxis 
                    dataKey="name" 
                    type="category" 
                    width={150} 
                    tick={{ fontSize: 11, fill: '#4b5563', fontWeight: 500 }} 
                    axisLine={false}
                    tickLine={false}
                  />
                  <Tooltip 
                    cursor={{fill: '#f8fafc', radius: 4}}
                    content={({active, payload}) => {
                      if (active && payload && payload.length) {
                        return (
                          <div className="bg-gray-900/95 backdrop-blur-sm text-white p-4 rounded-xl shadow-2xl text-sm border border-white/10 max-w-xs animate-scale-in">
                            <p className="font-bold mb-2 leading-tight">{payload[0].payload.fullName}</p>
                            <div className="flex items-center gap-2">
                              <div className="h-2 w-full bg-white/20 rounded-full overflow-hidden">
                                <div 
                                  className="h-full bg-indigo-400" 
                                  style={{width: `${(payload[0].value as number / 5) * 100}%`}}
                                ></div>
                              </div>
                              <span className="font-mono text-indigo-300 whitespace-nowrap">{payload[0].value} / 5</span>
                            </div>
                          </div>
                        );
                      }
                      return null;
                    }}
                  />
                  <Bar dataKey="avg" radius={[0, 6, 6, 0]} barSize={24}>
                    {chartData.map((entry, index) => (
                      <Cell 
                        key={`cell-${index}`} 
                        fill={entry.avg > 4.2 ? '#10b981' : entry.avg > 3.5 ? '#6366f1' : '#f59e0b'} 
                        className="transition-all duration-500 hover:opacity-80"
                      />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="grid sm:grid-cols-2 gap-4">
            {summaries.slice(0, 4).map((s, idx) => (
              <div key={idx} className="bg-white p-5 rounded-2xl border border-gray-100 flex items-center justify-between group hover:border-indigo-200 transition-all hover:shadow-sm">
                <div className="flex-1 pr-4">
                  <p className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-1">Populiariausias klausimas</p>
                  <p className="text-sm font-medium text-gray-700 line-clamp-1 group-hover:text-indigo-700 transition-colors">{s.question}</p>
                </div>
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-white font-bold shadow-sm transition-transform group-hover:rotate-3 ${
                  s.averageScore > 4 ? 'bg-green-500' : s.averageScore > 3 ? 'bg-indigo-500' : 'bg-amber-500'
                }`}>
                  {s.averageScore.toFixed(1)}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Feedback Column */}
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 flex flex-col max-h-[700px] hover:shadow-md transition-shadow">
          <h3 className="font-bold text-gray-800 mb-6 flex items-center gap-2">
            <i className="fas fa-comment-dots text-pink-500"></i> Atviri komentarai
          </h3>
          <div className="overflow-y-auto space-y-4 flex-1 pr-3 custom-scrollbar">
            {feedback.length > 0 ? feedback.map((f, idx) => (
              <div 
                key={idx} 
                className="bg-gray-50 p-5 rounded-2xl border-l-4 border-indigo-400 hover:bg-white hover:shadow-sm transition-all duration-300 animate-fade-in"
                style={{ animationDelay: `${idx * 0.05}s` }}
              >
                <p className="text-sm text-gray-600 leading-relaxed italic">"{f}"</p>
              </div>
            )) : (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-4">
                <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center text-gray-300 text-2xl">
                  <i className="fas fa-ghost"></i>
                </div>
                <p className="text-gray-400 text-sm">Mokiniai nepaliko papildomų komentarų.</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SummaryDashboard;

import React, { useState, useEffect } from 'react';
import { ReflectionData } from '../types';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  onComplete: () => void;
  onBack: () => void;
}

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas tau krenta į akis žiūrint į duomenis?",
      fields: [
        { 
          key: 'observations', 
          label: "Pasižymėk objektyvius pastebėjimus", 
          placeholder: "Pvz.: Pastebiu didelį atotrūkį tarp klausimų A ir B. Matau, kad dauguma mokinių vertina...",
          icon: "fa-eye text-indigo-500"
        }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, tobulėjimo kryptys ir netikėtumai",
      fields: [
        { 
          key: 'strengths', 
          label: "Kokie rezultatai džiugina?", 
          placeholder: "Didžiuojuosi tuo, kad...",
          icon: "fa-star text-yellow-500"
        },
        { 
          key: 'improvements', 
          label: "Kur matai didžiausią potencialą augti?", 
          placeholder: "Norėčiau skirti daugiau dėmesio...",
          icon: "fa-chart-line text-green-500"
        },
        { 
          key: 'surprises', 
          label: "Kas tave nustebino?", 
          placeholder: "Man buvo netikėta, kad...",
          icon: "fa-bolt text-amber-500"
        }
      ]
    },
    {
      title: "3. Galva ir Širdis",
      description: "Tavo emocinė ir racionali reakcija",
      fields: [
        { 
          key: 'heartFeelings', 
          label: "Kaip tavo ŠIRDIS reaguoja į mokinių žodžius?", 
          placeholder: "Jaučiuosi įvertintas, nes... Kartais pajuntu nerimą dėl...",
          icon: "fa-heart text-rose-500"
        },
        { 
          key: 'headThoughts', 
          label: "Ką apie tai sako tavo GALVA (racionalusis aš)?", 
          placeholder: "Racionaliai vertinant, rezultatai rodo, kad mano strategija...",
          icon: "fa-brain text-blue-500"
        }
      ]
    },
    {
      title: "4. Veiksmų planas",
      description: "Ką darysi kitaip jau rytoj?",
      fields: [
        { 
          key: 'actionStop', 
          label: "Ką nustosi daryti?", 
          placeholder: "Nustosiu...",
          icon: "fa-circle-stop text-red-500"
        },
        { 
          key: 'actionStart', 
          label: "Ką pradėsi daryti?", 
          placeholder: "Pradėsiu...",
          icon: "fa-circle-play text-emerald-500"
        },
        { 
          key: 'actionContinue', 
          label: "Ką tęsi toliau?", 
          placeholder: "Toliau darysiu...",
          icon: "fa-rotate text-sky-500"
        },
        { 
          key: 'nextSteps', 
          label: "Kaip matuosi sėkmę?", 
          placeholder: "Sėkmę matysiu per mokinių įsitraukimą, kai...",
          icon: "fa-bullseye text-indigo-500"
        }
      ]
    }
  ];

  const handleInputChange = (key: keyof ReflectionData, value: string) => {
    setReflection(prev => ({ ...prev, [key]: value }));
  };

  const next = () => {
    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }, 200);
    } else {
      onComplete();
    }
  };

  const prev = () => {
    if (currentStep > 0) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep - 1);
        setAnimating(false);
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }, 200);
    } else {
      onBack();
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4">
      {/* Progress Bar */}
      <div className="flex justify-between mb-12 relative px-2">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-200 -translate-y-1/2 rounded-full -z-10"></div>
        <div 
          className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 rounded-full -z-10 transition-all duration-500"
          style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}
        ></div>

        {steps.map((step, idx) => (
          <div key={idx} className="flex flex-col items-center">
            <button 
              onClick={() => idx < currentStep && setCurrentStep(idx)}
              disabled={idx > currentStep}
              className={`w-10 h-10 rounded-full flex items-center justify-center font-bold text-sm transition-all duration-300 border-4 ${
                idx === currentStep 
                  ? 'bg-white border-indigo-600 text-indigo-600 scale-110 shadow-md' 
                  : idx < currentStep 
                    ? 'bg-indigo-600 border-indigo-600 text-white shadow-sm' 
                    : 'bg-white border-gray-200 text-gray-400'
              }`}
            >
              {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
            </button>
            <span className={`absolute -bottom-7 text-[10px] font-bold uppercase tracking-tighter transition-colors ${
              idx === currentStep ? 'text-indigo-600' : 'text-gray-400'
            }`}>
              {step.title.split('. ')[1]}
            </span>
          </div>
        ))}
      </div>

      <div className={`bg-white p-8 md:p-12 rounded-[2.5rem] shadow-xl border border-gray-100 transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100 translate-y-0'}`}>
        <header className="mb-10 text-center md:text-left">
          <div className="inline-block bg-indigo-50 text-indigo-700 text-xs font-bold px-3 py-1 rounded-full mb-4 uppercase tracking-widest">
            {currentStep + 1} ŽINGSNIS IŠ {steps.length}
          </div>
          <h2 className="text-3xl font-black text-gray-900 mb-2">{steps[currentStep].title}</h2>
          <p className="text-gray-500 text-lg leading-relaxed">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-10">
          {steps[currentStep].fields.map((field) => (
            <div key={field.key} className="group">
              <label className="block font-bold text-gray-800 mb-3 flex items-center gap-3 text-lg transition-colors group-focus-within:text-indigo-600">
                <span className="w-8 h-8 rounded-lg bg-gray-50 flex items-center justify-center group-focus-within:bg-indigo-50 transition-colors">
                  <i className={`fas ${field.icon}`}></i>
                </span>
                {field.label}
              </label>
              <textarea
                value={reflection[field.key as keyof ReflectionData]}
                onChange={(e) => handleInputChange(field.key as keyof ReflectionData, e.target.value)}
                placeholder={field.placeholder}
                className="w-full h-40 p-6 rounded-3xl border-2 border-gray-100 bg-gray-50/50 focus:bg-white focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all outline-none resize-none text-gray-700 leading-relaxed placeholder:text-gray-300"
              />
              <div className="flex justify-end mt-2">
                <span className="text-[10px] text-gray-400 italic">Tavo nuoširdumas yra raktas į augimą</span>
              </div>
            </div>
          ))}
        </div>

        <div className="flex flex-col sm:flex-row justify-between items-center mt-12 pt-8 border-t border-gray-50 gap-4">
          <button 
            onClick={prev}
            className="w-full sm:w-auto text-gray-400 font-bold hover:text-gray-700 transition-all px-6 py-3 rounded-2xl hover:bg-gray-50 active:scale-95"
          >
            <i className="fas fa-chevron-left mr-2"></i> Grįžti
          </button>
          <button 
            onClick={next}
            className="w-full sm:w-auto bg-indigo-600 hover:bg-indigo-700 active:scale-95 text-white font-black py-4 px-12 rounded-2xl transition-all shadow-lg hover:shadow-indigo-500/20"
          >
            {currentStep === steps.length - 1 ? 'Generuoti galutinę ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right ml-2"></i>
          </button>
        </div>
      </div>

      <div className="mt-10 bg-indigo-900 rounded-3xl p-6 text-white flex flex-col md:flex-row items-center gap-6 animate-fade-in shadow-xl">
        <div className="w-16 h-16 rounded-2xl bg-white/10 flex items-center justify-center shrink-0">
          <i className="fas fa-lightbulb text-2xl text-yellow-300"></i>
        </div>
        <div>
          <h4 className="font-bold text-lg mb-1">Kodėl tai svarbu?</h4>
