import React, { useState } from 'react';
import { ReflectionData } from '../types';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  onComplete: () => void;
  onBack: () => void;
}

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas tau krenta į akis žiūrint į duomenis?",
      fields: [
        { 
          key: 'observations', 
          label: "Pasižymėk objektyvius pastebėjimus", 
          placeholder: "Pvz.: Pastebiu didelį atotrūkį tarp klausimų A ir B. Matau, kad dauguma mokinių vertina...",
          icon: "fa-eye text-indigo-500"
        }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, tobulėjimo kryptys ir netikėtumai",
      fields: [
        { 
          key: 'strengths', 
          label: "Kokie rezultatai džiugina?", 
