                <div className="group">
                  <h3 className="font-black text-gray-800 mb-4 flex items-center gap-3 text-xl">
                    <span className="w-8 h-8 rounded-lg bg-purple-50 text-purple-600 flex items-center justify-center"><i className="fas fa-bolt text-sm"></i></span>
                    Netikėtumai
                  </h3>
                  <div className="bg-purple-50/20 p-6 rounded-3xl border border-purple-100/50 group-hover:bg-white group-hover:shadow-md transition-all">
                    <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{reflection.surprises || "Nėra duomenų"}</p>
                  </div>
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-8">
                 <div className="bg-rose-50/30 p-8 rounded-[2rem] border border-rose-100">
                    <h3 className="font-black text-rose-900 mb-4 flex items-center gap-3 text-xl">
