              <i className="fas fa-fire animate-pulse text-yellow-300"></i>
              {streak} dienų refleksijos serija
            </div>
          </div>

          <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 text-xl font-medium leading-relaxed max-w-2xl">{steps[currentStep].description}</p>
          <div className="hidden md:block absolute -top-4 -right-4 opacity-[0.03] pointer-events-none">
            <i className={`fas ${steps[currentStep].fields[0].icon.split(' ')[0]} text-9xl`}></i>
          </div>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const charCount = reflection[field.key as keyof ReflectionData].length;
            return (
              <div key={field.key} className="group relative">
