  [key: string]: string;
}

export interface QuestionSummary {
  question: string;
  counts: {
    [answer: string]: number;
  };
  total: number;
  averageScore: number;
}

export interface ReflectionData {
  observations: string;
  strengths: string;
  improvements: string;
  surprises: string;
  bestPractices: string;
  heartFeelings: string;
  headThoughts: string;
  actionStop: string;
  actionStart: string;
  actionContinue: string;
  nextSteps: string;
}

export enum AppStep {
  UPLOAD = 'UPLOAD',
  ANALYSIS = 'ANALYSIS',
  REFLECTION = 'REFLECTION',
  REPORT = 'REPORT'
}

export const LIKERT_VALUES: { [key: string]: number } = {
  "Visiškai sutinku": 5,
  "Labiau sutinku": 4,
  "Iš dalies": 3,
  "Labiau nesutinku": 2,
  "Visiškai nesutinku": 1,
  "Visiškai nesutinku.": 1, // Handle possible variations
  "Visiškai sutinku.": 5
};

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [data, setData] = useState<SurveyRow[]>([]);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '',
    strengths: '',
    improvements: '',
    surprises: '',
    bestPractices: '',
    heartFeelings: '',
    headThoughts: '',
    actionStop: '',
    actionStart: '',
    actionContinue: '',
    nextSteps: ''
  });

  const handleDataParsed = (rows: SurveyRow[]) => {
    setData(rows);
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;

    const headers = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    // Skip the first column (usually timestamp)
    headers.slice(1).forEach(header => {
      const headerLower = header.toLowerCase();

      // Categorize as feedback if it contains specific keywords
      const isFeedback = headerLower.includes('idėja') || 
                         headerLower.includes('pasiūlymas') || 
                         headerLower.includes('komentar') ||
                         headerLower.includes('atsiliepim');

      if (isFeedback) {
        rows.forEach(row => {
          if (row[header] && row[header].trim()) feedback.push(row[header]);
        });
      } else {
        const counts: { [answer: string]: number } = {};
        let sum = 0;
        let validCount = 0;
        let isActuallyNumeric = false;

        rows.forEach(row => {
          const val = row[header];
          if (val) {
            counts[val] = (counts[val] || 0) + 1;
            if (LIKERT_VALUES[val]) {
              sum += LIKERT_VALUES[val];
              validCount++;
              isActuallyNumeric = true;
            }
          }
        });

        // Only add to summaries if it's a valid Likert question and not just an instruction/non-numeric field
        if (isActuallyNumeric && validCount > 0) {
          newSummaries.push({
            question: header,
            counts,
            total: rows.length,
            averageScore: sum / validCount
          });
        } else if (!isActuallyNumeric && validCount === 0 && header.length > 5 && !headerLower.includes('vardas')) {
          // If it's a long text field that isn't Likert, treat as additional feedback
          rows.forEach(row => {
            if (row[header] && row[header].trim().length > 3) feedback.push(row[header]);
          });
        }
      }
    });

    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, openFeedback, aiInsights]);

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Header */}
      <header className="bg-indigo-700 text-white py-6 shadow-lg mb-8">
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-3">
              <span className="bg-white/20 p-2 rounded-xl backdrop-blur-sm">
                <i className="fas fa-chalkboard-teacher"></i>
              </span>
              Mokytojo refleksija
            </h1>
            <p className="text-indigo-100 text-sm mt-1 ml-12 opacity-80">Metodinė analizė pagal mokinių apklausas</p>
          </div>
          {step !== AppStep.UPLOAD && (
            <button 
              onClick={() => { if(confirm('Ar tikrai norite pradėti iš naujo? Visi neįrašyti duomenys bus prarasti.')) window.location.reload(); }}
              className="text-xs font-bold bg-white/10 hover:bg-white/20 border border-white/30 px-4 py-2 rounded-xl transition-all active:scale-95"
            >
              Pradėti iš naujo
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-4">
        {step === AppStep.UPLOAD && (
          <div className="max-w-2xl mx-auto mt-12 animate-slide-up">
            <CSVUpload onParsed={handleDataParsed} />
            <div className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-4">
              {[
                { icon: 'fa-upload', title: '1. Įkeltas failas', desc: 'Sistema nuskaito .csv duomenis' },
                { icon: 'fa-microchip', title: '2. DI analizė', desc: 'Identifikuojami dėsningumai' },
                { icon: 'fa-pen-fancy', title: '3. Refleksija', desc: 'Pildomas veiksmų planas' }
              ].map((item, i) => (
                <div key={i} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 text-center group hover:border-indigo-200 transition-all">
                  <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center mx-auto mb-3 group-hover:scale-110 transition-transform">
                    <i className={`fas ${item.icon}`}></i>
                  </div>
                  <h4 className="font-bold text-gray-800 text-sm mb-1">{item.title}</h4>
                  <p className="text-[10px] text-gray-400 leading-tight uppercase tracking-wider">{item.desc}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {step === AppStep.ANALYSIS && (
          <SummaryDashboard 
            summaries={summaries} 
            feedback={openFeedback} 
            aiInsights={aiInsights}
            isAnalyzing={isAnalyzing}
            onNext={() => setStep(AppStep.REFLECTION)} 
          />
        )}

        {step === AppStep.REFLECTION && (
          <ReflectionWizard 
            reflection={reflection} 
            setReflection={setReflection}
            onComplete={() => setStep(AppStep.REPORT)}
            onBack={() => setStep(AppStep.ANALYSIS)}
          />
        )}

        {step === AppStep.REPORT && (
          <div className="max-w-4xl mx-auto bg-white p-12 rounded-[3rem] shadow-2xl border border-indigo-50 animate-scale-in print:shadow-none print:border-none print:p-0">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 border-b border-gray-100 pb-10 gap-6">
              <div>
                <span className="text-[10px] font-black uppercase tracking-[0.3em] text-indigo-500 mb-2 block">Pedagoginis dienoraštis</span>
                <h2 className="text-4xl font-black text-gray-900 tracking-tight">Refleksijos Ataskaita</h2>
                <div className="flex items-center gap-4 mt-3">
                  <span className="bg-gray-100 text-gray-600 text-xs px-3 py-1 rounded-full flex items-center gap-2">
                    <i className="far fa-calendar-alt"></i> {new Date().toLocaleDateString('lt-LT')}
                  </span>
                  <span className="bg-indigo-50 text-indigo-600 text-xs px-3 py-1 rounded-full flex items-center gap-2">
                    <i className="fas fa-check-circle"></i> Užbaigta
                  </span>
                </div>
              </div>
              <button 
                onClick={() => window.print()} 
                className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-4 rounded-2xl flex items-center gap-3 transition-all shadow-xl shadow-indigo-200 active:scale-95 print:hidden"
              >
                <i className="fas fa-file-pdf"></i> Išsaugoti PDF
              </button>
            </div>

            <section className="space-y-12">
              <div className="grid md:grid-cols-2 gap-8">
                <div className="group">
                  <h3 className="font-black text-gray-800 mb-4 flex items-center gap-3 text-xl">
                    <span className="w-8 h-8 rounded-lg bg-indigo-50 text-indigo-600 flex items-center justify-center"><i className="fas fa-eye text-sm"></i></span>
                    Pastebėjimai
                  </h3>
                  <div className="bg-gray-50/50 p-6 rounded-3xl border border-gray-100 group-hover:bg-white group-hover:shadow-md transition-all">
                    <p className="text-gray-700 leading-relaxed whitespace-pre-wrap italic">{reflection.observations || "Nėra duomenų"}</p>
                  </div>
                </div>
                <div className="group">
                  <h3 className="font-black text-gray-800 mb-4 flex items-center gap-3 text-xl">
                    <span className="w-8 h-8 rounded-lg bg-emerald-50 text-emerald-600 flex items-center justify-center"><i className="fas fa-star text-sm"></i></span>
                    Mano Stiprybės
                  </h3>
                  <div className="bg-emerald-50/20 p-6 rounded-3xl border border-emerald-100/50 group-hover:bg-white group-hover:shadow-md transition-all">
                    <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{reflection.strengths || "Nėra duomenų"}</p>
                  </div>
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-8">
                <div className="group">
                  <h3 className="font-black text-gray-800 mb-4 flex items-center gap-3 text-xl">
                    <span className="w-8 h-8 rounded-lg bg-amber-50 text-amber-600 flex items-center justify-center"><i className="fas fa-chart-line text-sm"></i></span>
                    Augimo sritys
                  </h3>
                  <div className="bg-amber-50/20 p-6 rounded-3xl border border-amber-100/50 group-hover:bg-white group-hover:shadow-md transition-all">
                    <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{reflection.improvements || "Nėra duomenų"}</p>
                  </div>
                </div>
                <div className="group">
                  <h3 className="font-black text-gray-800 mb-4 flex items-center gap-3 text-xl">
                    <span className="w-8 h-8 rounded-lg bg-purple-50 text-purple-600 flex items-center justify-center"><i className="fas fa-bolt text-sm"></i></span>
                    Netikėtumai
                  </h3>
                  <div className="bg-purple-50/20 p-6 rounded-3xl border border-purple-100/50 group-hover:bg-white group-hover:shadow-md transition-all">
                    <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{reflection.surprises || "Nėra duomenų"}</p>
                  </div>
                </div>
              </div>

              <div className="grid md:grid-cols-1 gap-8">
                <div className="group">
                  <h3 className="font-black text-gray-800 mb-4 flex items-center gap-3 text-xl">
                    <span className="w-8 h-8 rounded-lg bg-blue-50 text-blue-600 flex items-center justify-center"><i className="fas fa-thumbs-up text-sm"></i></span>
                    Geroji patirtis
                  </h3>
                  <div className="bg-blue-50/20 p-6 rounded-3xl border border-blue-100/50 group-hover:bg-white group-hover:shadow-md transition-all">
                    <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{reflection.bestPractices || "Nėra duomenų"}</p>
                  </div>
                </div>
              </div>

              <div className="grid md:grid-cols-2 gap-8">
                 <div className="bg-rose-50/30 p-8 rounded-[2rem] border border-rose-100">
                    <h3 className="font-black text-rose-900 mb-4 flex items-center gap-3 text-xl">
                      <i className="fas fa-heart"></i> Kaip jaučiasi ŠIRDIS?
