export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [streak, setStreak] = useState(0);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Persistence logic for streak
  useEffect(() => {
    const STREAK_KEY = 'teacher_reflection_streak';
    const LAST_DATE_KEY = 'teacher_reflection_last_date';

    const today = new Date().toDateString();
    const lastDate = localStorage.getItem(LAST_DATE_KEY);
    const savedStreak = parseInt(localStorage.getItem(STREAK_KEY) || '0', 10);

    if (lastDate === today) {
      setStreak(savedStreak || 1);
    } else {
      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 1);

      if (lastDate === yesterday.toDateString()) {
        const newStreak = savedStreak + 1;
        setStreak(newStreak);
        localStorage.setItem(STREAK_KEY, newStreak.toString());
        localStorage.setItem(LAST_DATE_KEY, today);
      } else {
        setStreak(1);
        localStorage.setItem(STREAK_KEY, '1');
        localStorage.setItem(LAST_DATE_KEY, today);
      }
    }
  }, []);

  // Handle Auto-save & Navigation Guard
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = '';
    };

    window.addEventListener('beforeunload', handleBeforeUnload);

    const draft = {
      reflection,
      currentStep,
      timestamp: new Date().getTime()
    };
    localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
    setLastSaved(new Date());

    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection, currentStep]);

  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => val === '');
        if (isCurrentlyEmpty && Object.values(parsed.reflection).some(val => val !== '')) {
          setShowResumePrompt(true);
        }
      } catch (e) {
        console.error("Failed to parse draft", e);
      }
    }
  }, []);

  const handleResume = () => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      const parsed = JSON.parse(savedDraft);
      setReflection(parsed.reflection);
      setCurrentStep(parsed.currentStep || 0);
    }
    setShowResumePrompt(false);
  };

  const handleStartFresh = () => {
    localStorage.removeItem(DRAFT_KEY);
    setShowResumePrompt(false);
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas tau krenta į akis žiūrint į duomenis?",
      fields: [
        { 
          key: 'observations', 
          label: "Pasižymėk objektyvius pastebėjimus", 
          placeholder: "Pvz.: Pastebiu didelį atotrūkį tarp klausimų A ir B. Matau, kad dauguma mokinių vertina...",
          icon: "fa-eye text-indigo-500"
        }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, tobulėjimo kryptys ir netikėtumai",
      fields: [
        { 
          key: 'strengths', 
          label: "Kokie rezultatai džiugina?", 
          placeholder: "Didžiuojuosi tuo, kad...",
          icon: "fa-star text-yellow-500"
        },
        { 
          key: 'improvements', 
          label: "Kur matai didžiausią potencialą augti?", 
          placeholder: "Norėčiau skirti daugiau dėmesio...",
          icon: "fa-chart-line text-emerald-500"
        },
        { 
          key: 'surprises', 
          label: "Kas tave nustebino?", 
          placeholder: "Man buvo netikėta, kad...",
          icon: "fa-bolt text-amber-500"
        }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Kokius sėkmingus metodus pastebėjai ar planuoji taikyti?",
      fields: [
        { 
          key: 'bestPractices', 
          label: "Įvardink 2-3 gerąsias praktikas", 
          placeholder: "Pvz.: Individualus grįžtamasis ryšys po kiekvieno testo pasiteisino. Planuoju dažniau naudoti grupines diskusijas...",
          icon: "fa-thumbs-up text-blue-500"
        }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo emocinė ir racionali reakcija",
      fields: [
        { 
          key: 'heartFeelings', 
          label: "Kaip tavo ŠIRDIS reaguoja į mokinių žodžius?", 
          placeholder: "Jaučiuosi įvertintas, nes... Kartais pajuntu nerimą dėl...",
          icon: "fa-heart text-rose-500"
        },
        { 
          key: 'headThoughts', 
          label: "Ką apie tai sako tavo GALVA (racionalusis aš)?", 
          placeholder: "Racionaliai vertinant, rezultatai rodo, kad mano strategija...",
          icon: "fa-brain text-blue-500"
        }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip jau rytoj?",
      fields: [
        { 
          key: 'actionStop', 
          label: "Ką nustosi daryti?", 
          placeholder: "Nustosiu...",
          icon: "fa-circle-stop text-red-500"
        },
        { 
          key: 'actionStart', 
          label: "Ką pradėsi daryti?", 
          placeholder: "Pradėsiu...",
          icon: "fa-circle-play text-emerald-500"
        },
        { 
          key: 'actionContinue', 
          label: "Ką tęsi toliau?", 
          placeholder: "Toliau darysiu...",
          icon: "fa-rotate text-sky-500"
        },
        { 
          key: 'nextSteps', 
          label: "Kaip matuosi sėkmę?", 
          placeholder: "Sėkmę matysiu per mokinių įsitraukimą, kai...",
          icon: "fa-bullseye text-indigo-500"
        }
      ]
    }
  ];

  const handleInputChange = (key: keyof ReflectionData, value: string) => {
    setReflection(prev => ({ ...prev, [key]: value }));
  };

  const next = () => {
    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }, 200);
    } else {
      localStorage.removeItem(DRAFT_KEY);
      onComplete();
    }
  };

  const prev = () => {
    if (currentStep > 0) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep - 1);
        setAnimating(false);
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }, 200);
    } else {
      onBack();
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Resume Progress Dialog */}
      {showResumePrompt && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md animate-fade-in">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl border border-white/20 animate-scale-in text-center">
            <div className="w-20 h-20 bg-indigo-50 rounded-3xl flex items-center justify-center mx-auto mb-6">
              <i className="fas fa-file-signature text-3xl text-indigo-600"></i>
            </div>
            <h3 className="text-2xl font-black text-gray-900 mb-4 tracking-tight">Tęsti nebaigtą darbą?</h3>
            <p className="text-gray-500 font-medium mb-10 leading-relaxed">
              Radome jūsų anksčiau pradėtą refleksijos projektą. Ar norėtumėte tęsti nuo ten, kur sustojote?
            </p>
            <div className="flex flex-col gap-4">
              <button 
                onClick={handleResume}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-indigo-100 active:scale-95"
              >
                Tęsti refleksiją
              </button>
              <button 
                onClick={handleStartFresh}
                className="w-full bg-gray-50 hover:bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl transition-all active:scale-95"
              >
                Pradėti iš naujo
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Main Bar Progress Container */}
      <div className="flex justify-between mb-16 relative px-4 sm:px-10">
        <div className="absolute top-1/2 left-0 w-full h-1.5 bg-gray-100 -translate-y-1/2 rounded-full -z-10"></div>
        <div 
          className="absolute top-1/2 left-0 h-1.5 bg-gradient-to-r from-indigo-500 to-purple-600 -translate-y-1/2 rounded-full -z-10 transition-all duration-700 ease-in-out shadow-[0_0_15px_rgba(99,102,241,0.3)]"
          style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}
        ></div>

        {steps.map((step, idx) => (
          <div key={idx} className="flex flex-col items-center relative">
            <button 
              onClick={() => idx < currentStep && setCurrentStep(idx)}
              disabled={idx > currentStep}
              className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-sm transition-all duration-500 border-2 ${
                idx === currentStep 
                  ? 'bg-white border-indigo-600 text-indigo-600 scale-125 shadow-xl rotate-3' 
                  : idx < currentStep 
                    ? 'bg-gradient-to-br from-indigo-600 to-purple-600 border-transparent text-white shadow-lg' 
                    : 'bg-white border-gray-200 text-gray-300'
              } ${idx < currentStep ? 'cursor-pointer hover:scale-110 active:scale-95' : 'cursor-default'}`}
            >
              {idx < currentStep ? <i className="fas fa-check text-xs"></i> : idx + 1}
            </button>
            <span className={`absolute -bottom-9 text-[11px] font-black uppercase tracking-widest whitespace-nowrap transition-all duration-300 ${
              idx === currentStep ? 'text-indigo-700 opacity-100' : 'text-gray-400 opacity-60'
            }`}>
              {step.title.split('. ')[1]}
            </span>
          </div>
        ))}
      </div>

      {/* Main Content Card */}
      <div className={`bg-gradient-to-b from-white to-gray-50/40 p-8 md:p-14 rounded-[3rem] shadow-2xl border border-white/60 backdrop-blur-sm transition-all duration-500 overflow-hidden ${animating ? 'opacity-0 translate-y-8 scale-95' : 'opacity-100 translate-y-0 scale-100'}`}>

        {/* NEW TANGIBLE PROGRESS INDICATOR WITHIN CONTENT AREA */}
        <div className="flex gap-2 mb-10 overflow-hidden">
          {steps.map((_, idx) => (
            <div 
              key={`bar-${idx}`}
              className={`h-1.5 flex-1 rounded-full transition-all duration-700 ${
                idx === currentStep 
                  ? 'bg-indigo-600 shadow-[0_0_10px_rgba(79,70,229,0.4)] animate-pulse' 
                  : idx < currentStep 
                    ? 'bg-indigo-200' 
                    : 'bg-gray-100'
              }`}
            />
          ))}
        </div>

        <header className="mb-12 text-center md:text-left relative">
          <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 mb-6">
            <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-700 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.2em] shadow-sm border border-indigo-100/50">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-indigo-500"></span>
              </span>
              {currentStep + 1} žingsnis iš {steps.length}
            </div>

            <div className="inline-flex items-center gap-2 bg-gradient-to-r from-orange-500 to-rose-500 text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.2em] shadow-lg shadow-rose-200 border border-white/20 animate-fade-in">
              <i className="fas fa-fire animate-pulse text-yellow-300"></i>
              {streak} dienų refleksijos serija
            </div>
          </div>

          <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 text-xl font-medium leading-relaxed max-w-2xl">{steps[currentStep].description}</p>
          <div className="hidden md:block absolute -top-4 -right-4 opacity-[0.03] pointer-events-none">
            <i className={`fas ${steps[currentStep].fields[0].icon.split(' ')[0]} text-9xl`}></i>
          </div>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const charCount = reflection[field.key as keyof ReflectionData].length;
            return (
              <div key={field.key} className="group relative">
                <div className="flex items-center justify-between mb-4">
                  <label className="font-black text-gray-800 flex items-center gap-4 text-xl tracking-tight transition-all group-focus-within:text-indigo-600 group-focus-within:translate-x-1">
                    <span className={`w-10 h-10 rounded-xl bg-white border border-gray-100 shadow-sm flex items-center justify-center group-focus-within:bg-indigo-600 group-focus-within:text-white transition-all duration-500 group-focus-within:rotate-6`}>
                      <i className={`fas ${field.icon.split(' ')[0]}`}></i>
                    </span>
                    {field.label}
                  </label>
                </div>
                <div className="relative">
                  <textarea
                    value={reflection[field.key as keyof ReflectionData]}
                    onChange={(e) => handleInputChange(field.key as keyof ReflectionData, e.target.value)}
                    placeholder={field.placeholder}
                    className="w-full h-44 p-8 rounded-[2rem] border-2 border-gray-100 bg-white/50 focus:bg-white focus:ring-[12px] focus:ring-indigo-500/5 focus:border-indigo-500/50 focus:shadow-xl transition-all duration-500 outline-none resize-none text-gray-700 text-lg leading-relaxed placeholder:text-gray-300 placeholder:italic"
                  />
                  <div className="absolute bottom-6 right-8 flex items-center gap-3 pointer-events-none">
                    <div className="flex items-center gap-1.5 bg-white/80 backdrop-blur-sm px-3 py-1 rounded-full shadow-sm border border-gray-100">
                      <div className={`h-1.5 w-1.5 rounded-full transition-all duration-300 ${charCount > 0 ? 'bg-indigo-500' : 'bg-gray-200'}`}></div>
                      <span className={`text-[10px] font-black uppercase tracking-widest ${charCount > 0 ? 'text-indigo-600' : 'text-gray-400'}`}>
                        {charCount} simbolių
                      </span>
                    </div>
                    <div className="w-px h-3 bg-gray-200"></div>
                    <span className="text-[10px] font-bold text-gray-300 uppercase tracking-widest">
                      {charCount < 20 ? 'Minimalus dėmesys' : charCount < 100 ? 'Geras gylis' : 'Išsami analizė'}
                    </span>
                  </div>
                </div>
              </div>
            );
          })}
        </div>

        {/* Navigation Actions */}
        <div className="flex flex-col sm:flex-row justify-between items-center mt-16 pt-10 border-t border-gray-100 gap-6">
          <div className="flex flex-col gap-2">
            <button 
              onClick={prev}
              className="group w-full sm:w-auto text-gray-400 font-black hover:text-indigo-600 transition-all px-8 py-4 rounded-2xl hover:bg-indigo-50 active:scale-90 flex items-center justify-center gap-3"
            >
              <i className="fas fa-chevron-left transition-transform group-hover:-translate-x-1"></i> Grįžti
            </button>
            {lastSaved && (
              <div className="flex items-center gap-2 px-8 text-[9px] text-gray-400 font-black uppercase tracking-widest animate-fade-in">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
                Automatiškai išsaugota {lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' })}
              </div>
            )}
          </div>

          <button 
            onClick={next}
            className="w-full sm:w-auto bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 active:scale-95 text-white font-black py-5 px-14 rounded-[1.5rem] transition-all shadow-[0_15px_30px_-10px_rgba(79,70,229,0.4)] hover:shadow-[0_20px_40px_-10px_rgba(79,70,229,0.5)] flex items-center justify-center gap-4 relative overflow-hidden group"
          >
            <span className="relative z-10">{currentStep === steps.length - 1 ? 'Generuoti galutinę ataskaitą' : 'Tęsti toliau'}</span>
            <i className="fas fa-arrow-right relative z-10 transition-transform group-hover:translate-x-1"></i>
            <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
          </button>
        </div>
      </div>

      {/* Footer Info Card */}
      <div className="mt-12 bg-gray-900 rounded-[2.5rem] p-8 text-white flex flex-col md:flex-row items-center gap-8 animate-slide-up shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 blur-[100px] rounded-full pointer-events-none"></div>
        <div className="w-20 h-20 rounded-3xl bg-white/10 flex items-center justify-center shrink-0 shadow-inner backdrop-blur-md">
          <i className="fas fa-lightbulb text-3xl text-yellow-400 animate-pulse"></i>
        </div>
        <div className="text-center md:text-left">
          <h4 className="font-black text-xl mb-2 tracking-tight">Kiekvienas žodis yra tavo augimas</h4>
          <p className="text-indigo-200/80 text-lg leading-relaxed font-medium">Refleksija nėra skirta vertinimui. Tai tavo asmeninis įrankis sustoti, išgirsti mokinius ir suplanuoti pokytį, kuris džiugins tave ir tavo klasę.</p>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState } from 'react';
import { QuestionSummary } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LabelList } from 'recharts';

interface SummaryDashboardProps {
  summaries: QuestionSummary[];
  feedback: string[];
  aiInsights: any;
  isAnalyzing: boolean;
  onNext: () => void;
}

type ChartTheme = 'dynamic' | 'indigo' | 'emerald' | 'rose' | 'amber' | 'slate';

const THEME_COLORS: Record<Exclude<ChartTheme, 'dynamic'>, string> = {
  indigo: '#6366f1',
  emerald: '#10b981',
  rose: '#f43f5e',
  amber: '#f59e0b',
  slate: '#475569'
};

const CustomYAxisTick = (props: any) => {
  const { x, y, payload } = props;
  const text = payload.value;
  const maxLength = 60;
  const displayValue = text.length > maxLength ? text.substring(0, maxLength) + '...' : text;

  return (
    <g transform={`translate(${x},${y})`}>
      <text
        x={-10}
        y={0}
        dy={4}
        textAnchor="end"
        fill="#1f2937"
        fontSize={11}
        fontWeight={600}
        style={{ cursor: 'help' }}
      >
        <title>{text}</title>
        {displayValue}
      </text>
    </g>
  );
};

const SummaryDashboard: React.FC<SummaryDashboardProps> = ({ 
  summaries, 
  feedback, 
  aiInsights, 
  isAnalyzing,
  onNext 
}) => {
  const [activeTheme, setActiveTheme] = useState<ChartTheme>('dynamic');

  const numericSummaries = summaries.filter(s => s.averageScore > 0);

  const chartData = numericSummaries.map(s => ({
    name: s.question,
    fullName: s.question,
    avg: parseFloat(s.averageScore.toFixed(2))
  })).sort((a, b) => b.avg - a.avg);

  const topQuestions = [...numericSummaries].sort((a, b) => b.averageScore - a.averageScore).slice(0, 2);
  const bottomQuestions = [...numericSummaries].sort((a, b) => a.averageScore - b.averageScore).slice(0, 2);

  const globalAverage = numericSummaries.length > 0 
    ? numericSummaries.reduce((acc, s) => acc + s.averageScore, 0) / numericSummaries.length
    : 0;

  const getBarColor = (avg: number) => {
    if (activeTheme === 'dynamic') {
      return avg > 4.2 ? '#10b981' : avg > 3.5 ? '#6366f1' : '#f59e0b';
    }
    return THEME_COLORS[activeTheme];
  };

  return (
    <div className="space-y-10 animate-slide-up pb-12">
      {/* Top Header Section */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 gap-6 transition-all hover:shadow-md">
        <div className="flex items-center gap-6">
          <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex flex-col items-center justify-center text-white shadow-xl shadow-indigo-100 group transition-all">
            <span className="text-2xl font-black">{globalAverage.toFixed(1)}</span>
            <span className="text-[8px] uppercase font-black tracking-widest opacity-80">Vidurkis</span>
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-900 tracking-tight">Rezultatų santrauka</h2>
            <p className="text-gray-500 font-medium mt-1 flex items-center gap-2">
              <i className="fas fa-users text-indigo-400"></i> {summaries[0]?.total || 0} mokiniai dalyvavo apklausoje
            </p>
          </div>
        </div>
        <button 
          onClick={onNext}
          className="bg-indigo-600 hover:bg-indigo-700 active:scale-95 text-white px-10 py-5 rounded-2xl font-black transition-all flex items-center gap-4 shadow-xl shadow-indigo-100 hover:shadow-indigo-200"
        >
          Pradėti refleksiją <i className="fas fa-arrow-right"></i>
        </button>
      </div>

      {/* DI Insights Bar */}
      <div className="bg-gradient-to-br from-indigo-700 via-indigo-600 to-purple-600 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden group">
        <div className="relative z-10">
          <h3 className="text-2xl font-black flex items-center gap-4 mb-8">
            <div className="w-10 h-10 bg-white/10 rounded-xl flex items-center justify-center backdrop-blur-sm">
               <i className="fas fa-magic text-indigo-200 animate-pulse"></i>
            </div>
            DI analizė ir įžvalgos
          </h3>
          {isAnalyzing ? (
            <div className="flex flex-col items-center justify-center py-12 gap-5">
              <div className="relative flex h-10 w-10">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-white opacity-20"></span>
                <div className="animate-spin rounded-full h-10 w-10 border-4 border-white/20 border-t-white"></div>
              </div>
              <span className="text-indigo-100 font-bold tracking-tight text-lg animate-pulse">Generuojami dėsningumai iš mokinių atsakymų...</span>
            </div>
          ) : aiInsights ? (
            <div className="grid md:grid-cols-3 gap-8">
              {[
                { title: 'Stiprybės', text: aiInsights.strengths, icon: 'fa-star', color: 'bg-emerald-400/20' },
                { title: 'Kryptys pokyčiui', text: aiInsights.improvements, icon: 'fa-compass', color: 'bg-amber-400/20' },
                { title: 'Svarbi įžvalga', text: aiInsights.insights, icon: 'fa-lightbulb', color: 'bg-blue-400/20' }
              ].map((item, i) => (
                <div key={i} className={`${item.color} p-6 rounded-[2rem] backdrop-blur-md border border-white/10 hover:border-white/30 transition-all hover:translate-y-[-4px] duration-500`}>
                  <div className="flex items-center gap-3 mb-4">
                     <i className={`fas ${item.icon} text-white/60`}></i>
                     <h4 className="font-black text-white text-xs uppercase tracking-[0.2em]">{item.title}</h4>
                  </div>
                  <p className="text-sm leading-relaxed text-indigo-50 font-medium opacity-90">{item.text}</p>
                </div>
              ))}
            </div>
          ) : (
            <div className="bg-white/5 p-8 rounded-3xl border border-white/10 text-center italic">
              DI analizės nepavyko paruošti automatiškai. Peržiūrėkite grafikus žemiau.
            </div>
          )}
        </div>
        <i className="fas fa-microchip absolute -bottom-20 -right-20 text-white/5 text-[25rem] transition-transform duration-1000 group-hover:scale-110"></i>
      </div>

      <div className="grid lg:grid-cols-1 gap-10">
        {/* Main Chart Section */}
        <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100 transition-shadow hover:shadow-md overflow-hidden">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-12 gap-8">
            <div>
              <h3 className="font-black text-gray-900 text-2xl flex items-center gap-3 tracking-tight">
                <span className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center"><i className="fas fa-chart-line text-sm"></i></span>
                Mokinių įvertinimai pagal teiginius
              </h3>
              <p className="text-gray-400 text-sm mt-1 ml-12">Skalė nuo 1 (visiškai nesutinku) iki 5 (visiškai sutinku)</p>
            </div>

            <div className="flex flex-col items-end gap-3">
              <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">Spalvų schema</span>
              <div className="flex gap-2 bg-gray-50 p-1.5 rounded-2xl border border-gray-100">
                <button 
                  onClick={() => setActiveTheme('dynamic')}
                  title="Pagal balą"
                  className={`w-8 h-8 rounded-xl flex items-center justify-center transition-all ${activeTheme === 'dynamic' ? 'bg-white shadow-md ring-2 ring-indigo-500/20' : 'hover:bg-gray-200'}`}
                >
                  <div className="flex gap-0.5">
                    <div className="w-1.5 h-3 bg-emerald-500 rounded-sm"></div>
                    <div className="w-1.5 h-3 bg-indigo-500 rounded-sm"></div>
                    <div className="w-1.5 h-3 bg-amber-500 rounded-sm"></div>
                  </div>
                </button>
                {(['indigo', 'emerald', 'rose', 'amber', 'slate'] as const).map(theme => (
                  <button 
                    key={theme}
                    onClick={() => setActiveTheme(theme)}
                    title={theme.charAt(0).toUpperCase() + theme.slice(1)}
                    className={`w-8 h-8 rounded-xl transition-all ${activeTheme === theme ? 'ring-4 ring-offset-2 ring-gray-100 scale-110 shadow-lg' : 'hover:scale-105'}`}
