                <CartesianGrid strokeDasharray="5 5" horizontal={true} vertical={false} stroke="#f3f4f6" />
                <XAxis type="number" domain={[0, 5]} ticks={[1,2,3,4,5]} hide />
                <YAxis 
                  dataKey="name" 
                  type="category" 
                  width={350}
                  tick={<CustomYAxisTick />}
                  axisLine={false}
                  tickLine={false}
                />
                <Tooltip 
                  cursor={{fill: '#f8fafc', radius: 12}}
                  content={({active, payload}) => {
                    if (active && payload && payload.length) {
                      const val = payload[0].value as number;
                      const barCol = getBarColor(val);
                      return (
                        <div className="bg-gray-900 text-white p-5 rounded-2xl shadow-2xl text-sm border border-white/10 max-w-sm animate-scale-in">
                          <p className="font-black mb-3 leading-tight text-indigo-200">{payload[0].payload.fullName}</p>
                          <div className="flex items-center gap-4">
