                          <p className="text-[10px] text-gray-400 mt-2 uppercase tracking-widest">Vidutinis balas</p>
                        </div>
                      );
                    }
                    return null;
                  }}
                />
                <Bar dataKey="avg" radius={[0, 10, 10, 0]} barSize={28} animationDuration={1500} animationEasing="ease-out">
                  {chartData.map((entry, index) => (
                    <Cell 
                      key={`cell-${index}`} 
                      fill={getBarColor(entry.avg)} 
                      className="transition-all duration-700 hover:opacity-80"
