            </ResponsiveContainer>
          </div>
        </div>

        {/* Quick Insights Cards & Feedback Combined */}
        <div className="grid lg:grid-cols-2 gap-10">
           {/* Top/Bottom Insights */}
           <div className="space-y-6">
              <h3 className="font-black text-gray-800 text-xl px-4 flex items-center gap-2">
                <i className="fas fa-medal text-yellow-500"></i> Ryškiausi akcentai
              </h3>

              <div className="space-y-4">
                {topQuestions.map((s, idx) => (
                  <div key={`top-${idx}`} className="bg-emerald-50/30 p-6 rounded-3xl border border-emerald-100 flex items-center justify-between group hover:bg-white hover:shadow-lg transition-all duration-300">
                    <div className="flex-1 pr-6">
                      <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-2 flex items-center gap-2">
                        <i className="fas fa-arrow-trend-up"></i> Aukščiausiai įvertinta
                      </p>
                      <p className="text-sm font-bold text-gray-800 leading-snug">{s.question}</p>
                    </div>
                    <div className="w-16 h-16 bg-emerald-500 text-white rounded-2xl flex flex-col items-center justify-center shadow-lg shadow-emerald-100">
                      <span className="text-xl font-black">{s.averageScore.toFixed(1)}</span>
                      <span className="text-[8px] font-black uppercase opacity-80">Balas</span>
                    </div>
                  </div>
                ))}

                {bottomQuestions.map((s, idx) => (
                  <div key={`bottom-${idx}`} className="bg-amber-50/30 p-6 rounded-3xl border border-amber-100 flex items-center justify-between group hover:bg-white hover:shadow-lg transition-all duration-300">
                    <div className="flex-1 pr-6">
                      <p className="text-[10px] font-black text-amber-600 uppercase tracking-widest mb-2 flex items-center gap-2">
                        <i className="fas fa-arrow-trend-down"></i> Žemiausiai įvertinta
                      </p>
                      <p className="text-sm font-bold text-gray-800 leading-snug">{s.question}</p>
                    </div>
                    <div className="w-16 h-16 bg-amber-500 text-white rounded-2xl flex flex-col items-center justify-center shadow-lg shadow-amber-100">
                      <span className="text-xl font-black">{s.averageScore.toFixed(1)}</span>
                      <span className="text-[8px] font-black uppercase opacity-80">Balas</span>
                    </div>
                  </div>
                ))}
              </div>

              <div className="bg-gray-100 p-8 rounded-[2rem] border border-gray-200 mt-8 flex flex-col items-center justify-center text-center">
                <i className="fas fa-info-circle text-gray-400 mb-4 text-2xl"></i>
                <p className="text-gray-500 text-sm font-medium leading-relaxed">
                  Šie rezultatai padeda suprasti, kuriose srityse mokiniai jaučiasi saugiausiai ir kur reikalinga didžiausia parama.
                </p>
              </div>
           </div>

           {/* Feedback Column */}
           <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100 flex flex-col max-h-[700px] hover:shadow-md transition-shadow">
              <h3 className="font-black text-gray-900 mb-8 flex items-center gap-4 text-2xl tracking-tight">
                <span className="w-10 h-10 bg-pink-50 text-pink-500 rounded-xl flex items-center justify-center"><i className="fas fa-comment-dots text-sm"></i></span>
                Atviri komentarai
              </h3>
              <div className="overflow-y-auto space-y-6 flex-1 pr-4 custom-scrollbar">
                {feedback.length > 0 ? feedback.map((f, idx) => (
                  <div 
                    key={idx} 
                    className="bg-gray-50/80 p-6 rounded-3xl border border-gray-100 hover:bg-white hover:shadow-md transition-all duration-500 animate-fade-in relative group"
                    style={{ animationDelay: `${idx * 0.1}s` }}
                  >
                    <p className="text-gray-700 leading-relaxed font-medium italic relative z-10">"{f}"</p>
                    <div className="absolute top-4 right-6 opacity-0 group-hover:opacity-100 transition-opacity">
                      <i className="fas fa-quote-right text-indigo-100 text-2xl"></i>
                    </div>
                  </div>
                )) : (
                  <div className="flex flex-col items-center justify-center h-full text-center p-12 space-y-6 bg-gray-50/50 rounded-[2.5rem] border border-dashed border-gray-200">
                    <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center text-gray-300 text-3xl shadow-sm">
                      <i className="fas fa-comment-slash"></i>
                    </div>
                    <div>
                      <h4 className="font-bold text-gray-400">Komentarų nėra</h4>
                      <p className="text-gray-300 text-xs mt-1 uppercase tracking-widest">Mokiniai nepateikė atvirų atsiliepimų</p>
                    </div>
                  </div>
                )}
              </div>
           </div>
        </div>
      </div>
    </div>
  );
};

