export default ReflectionWizard;

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [data, setData] = useState<SurveyRow[]>([]);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showShareToast, setShowShareToast] = useState(false);
  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '',
    strengths: '',
    improvements: '',
    surprises: '',
    bestPractices: '',
    heartFeelings: '',
    headThoughts: '',
    actionStop: '',
    actionStart: '',
    actionContinue: '',
    nextSteps: ''
  });

  // Handle Shared Link on Mount
  useEffect(() => {
    const hash = window.location.hash;
    if (hash.startsWith('#data=')) {
      try {
        const base64 = hash.replace('#data=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(base64))));
        setReflection(decodedData);
        setStep(AppStep.REPORT);
        // Clear hash so it doesn't interfere with future reloads
        window.history.replaceState(null, '', window.location.pathname);
      } catch (e) {
        console.error("Failed to decode shared data", e);
      }
    }
  }, []);

  // Save to History when report is reached
  useEffect(() => {
    if (step === AppStep.REPORT) {
      const historyKey = 'teacher_reflection_history';
      const existingHistory = JSON.parse(localStorage.getItem(historyKey) || '[]');

      // Prevent duplicate saving of the exact same data
      const isDuplicate = existingHistory.some((item: any) => 
        JSON.stringify(item.data) === JSON.stringify(reflection)
      );

      if (!isDuplicate) {
        const newEntry = {
          id: Date.now(),
          date: new Date().toISOString(),
          data: reflection
        };
        const updatedHistory = [newEntry, ...existingHistory].slice(0, 20); // Keep last 20
        localStorage.setItem(historyKey, JSON.stringify(updatedHistory));
      }
    }
  }, [step, reflection]);

  const handleDataParsed = (rows: SurveyRow[]) => {
    setData(rows);
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;

    const headers = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    headers.slice(1).forEach(header => {
      const headerLower = header.toLowerCase();

      const isFeedback = headerLower.includes('idėja') || 
                         headerLower.includes('pasiūlymas') || 
                         headerLower.includes('komentar') ||
                         headerLower.includes('atsiliepim');

      if (isFeedback) {
        rows.forEach(row => {
          if (row[header] && row[header].trim()) feedback.push(row[header]);
        });
      } else {
        const counts: { [answer: string]: number } = {};
        let sum = 0;
        let validCount = 0;
        let isActuallyNumeric = false;

        rows.forEach(row => {
          const val = row[header];
          if (val) {
            counts[val] = (counts[val] || 0) + 1;
            if (LIKERT_VALUES[val]) {
              sum += LIKERT_VALUES[val];
              validCount++;
              isActuallyNumeric = true;
            }
          }
        });

        if (isActuallyNumeric && validCount > 0) {
          newSummaries.push({
            question: header,
            counts,
            total: rows.length,
            averageScore: sum / validCount
          });
        } else if (!isActuallyNumeric && validCount === 0 && header.length > 5 && !headerLower.includes('vardas')) {
          rows.forEach(row => {
            if (row[header] && row[header].trim().length > 3) feedback.push(row[header]);
          });
        }
      }
    });

    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, openFeedback, aiInsights]);

  const handleShare = () => {
    try {
      const dataString = JSON.stringify(reflection);
      const base64 = btoa(unescape(encodeURIComponent(dataString)));
      const shareUrl = `${window.location.origin}${window.location.pathname}#data=${base64}`;

      navigator.clipboard.writeText(shareUrl).then(() => {
        setShowShareToast(true);
        setTimeout(() => setShowShareToast(false), 3000);
      });
    } catch (e) {
      console.error("Failed to share", e);
      alert("Nepavyko sukurti nuorodos.");
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-12">
      {/* Share Toast */}
      {showShareToast && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-[200] animate-slide-up">
          <div className="bg-gray-900 text-white px-8 py-4 rounded-2xl shadow-2xl flex items-center gap-4 border border-white/10 backdrop-blur-md">
            <div className="w-8 h-8 bg-emerald-500 rounded-full flex items-center justify-center">
              <i className="fas fa-check text-xs"></i>
            </div>
            <span className="font-bold tracking-tight">Nuoroda nukopijuota į iškarpinę!</span>
          </div>
        </div>
      )}

      {/* Header */}
      <header className="bg-indigo-700 text-white py-6 shadow-lg mb-8 print:hidden">
        <div className="container mx-auto px-4 flex justify-between items-center">
          <div>
            <h1 className="text-2xl font-bold flex items-center gap-3">
              <span className="bg-white/20 p-2 rounded-xl backdrop-blur-sm">
                <i className="fas fa-chalkboard-teacher"></i>
              </span>
              Mokytojo refleksija
            </h1>
            <p className="text-indigo-100 text-sm mt-1 ml-12 opacity-80">Metodinė analizė pagal mokinių apklausas</p>
          </div>
          {step !== AppStep.UPLOAD && (
            <button 
              onClick={() => { if(confirm('Ar tikrai norite pradėti iš naujo? Visi neįrašyti duomenys bus prarasti.')) window.location.reload(); }}
              className="text-xs font-bold bg-white/10 hover:bg-white/20 border border-white/30 px-4 py-2 rounded-xl transition-all active:scale-95"
            >
              Pradėti iš naujo
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-4">
        {step === AppStep.UPLOAD && (
          <div className="max-w-2xl mx-auto mt-12 animate-slide-up">
            <CSVUpload onParsed={handleDataParsed} />
            <div className="mt-12 grid grid-cols-1 md:grid-cols-3 gap-4">
              {[
                { icon: 'fa-upload', title: '1. Įkeltas failas', desc: 'Sistema nuskaito .csv duomenis' },
                { icon: 'fa-microchip', title: '2. DI analizė', desc: 'Identifikuojami dėsningumai' },
                { icon: 'fa-pen-fancy', title: '3. Refleksija', desc: 'Pildomas veiksmų planas' }
              ].map((item, i) => (
                <div key={i} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 text-center group hover:border-indigo-200 transition-all">
                  <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center mx-auto mb-3 group-hover:scale-110 transition-transform">
                    <i className={`fas ${item.icon}`}></i>
