                  className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-4 rounded-2xl flex items-center gap-3 transition-all shadow-xl shadow-indigo-200 active:scale-95"
                >
                  <i className="fas fa-file-pdf"></i> Išsaugoti PDF
