                  </h3>
                  <div className="bg-emerald-50/20 p-6 rounded-3xl border border-emerald-100/50 group-hover:bg-white group-hover:shadow-md transition-all">
                    <p className="text-gray-700 leading-relaxed whitespace-pre-wrap">{reflection.strengths || "Nėra duomenų"}</p>
