import React from 'react';
import { QuestionSummary } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LabelList } from 'recharts';

interface SummaryDashboardProps {
  summaries: QuestionSummary[];
  feedback: string[];
  aiInsights: any;
  isAnalyzing: boolean;
  onNext: () => void;
}

const CustomYAxisTick = (props: any) => {
  const { x, y, payload } = props;
  const text = payload.value;
  const maxLength = 45;
  const displayValue = text.length > maxLength ? text.substring(0, maxLength) + '...' : text;

  return (
    <g transform={`translate(${x},${y})`}>
      <text x={-10} y={0} dy={4} textAnchor="end" fill="#4b5563" fontSize={11} fontWeight={500}>
        <title>{text}</title>
        {displayValue}
      </text>
    </g>
  );
};

const SummaryDashboard: React.FC<SummaryDashboardProps> = ({ 
  summaries, 
  feedback, 
  aiInsights, 
  isAnalyzing,
  onNext 
}) => {
  const categories = ['Įsitraukimas', 'Mokymas', 'Klimatas', 'Grįžtamasis ryšys'];

  const getBarColor = (avg: number, isReverse?: boolean) => {
    if (isReverse) {
      return avg > 3.5 ? '#f43f5e' : '#10b981'; // Neigiamiems teiginiams: aukštas balas = raudona
    }
    return avg > 4.2 ? '#10b981' : avg > 3.5 ? '#6366f1' : '#f59e0b';
  };

  return (
    <div className="space-y-8 animate-slide-up pb-12">
      {/* Header */}
      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100 flex flex-col md:flex-row justify-between items-center gap-6">
        <div className="flex items-center gap-5">
          <div className="w-16 h-16 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
            <i className="fas fa-chart-pie text-2xl"></i>
          </div>
          <div>
            <h2 className="text-2xl font-black text-gray-900">Duomenų analizė</h2>
            <p className="text-gray-500 text-sm">Apklausoje dalyvavo {summaries[0]?.total || 0} mokiniai</p>
          </div>
        </div>
        <button 
          onClick={onNext}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-4 rounded-xl font-bold transition-all shadow-md active:scale-95 flex items-center gap-3"
        >
          Pradėti refleksiją <i className="fas fa-arrow-right"></i>
        </button>
      </div>

      {/* DI Insights */}
      <div className="bg-indigo-900 rounded-[2rem] p-8 text-white shadow-xl relative overflow-hidden">
        <h3 className="text-xl font-bold flex items-center gap-3 mb-6 relative z-10">
          <i className="fas fa-magic text-indigo-300"></i> DI Įžvalgos
        </h3>
        {isAnalyzing ? (
          <div className="flex items-center gap-4 py-4 animate-pulse">
            <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
            <span className="font-medium opacity-80">Analizuojami mokinių atsakymai...</span>
          </div>
        ) : aiInsights && (
          <div className="grid md:grid-cols-3 gap-6 relative z-10">
            <div className="bg-white/10 p-5 rounded-2xl backdrop-blur-sm border border-white/10">
              <h4 className="text-[10px] uppercase font-black tracking-widest text-indigo-200 mb-2">Stiprybės</h4>
              <p className="text-sm leading-relaxed">{aiInsights.strengths}</p>
            </div>
            <div className="bg-white/10 p-5 rounded-2xl backdrop-blur-sm border border-white/10">
              <h4 className="text-[10px] uppercase font-black tracking-widest text-indigo-200 mb-2">Tobulintina</h4>
              <p className="text-sm leading-relaxed">{aiInsights.improvements}</p>
            </div>
            <div className="bg-white/10 p-5 rounded-2xl backdrop-blur-sm border border-white/10">
              <h4 className="text-[10px] uppercase font-black tracking-widest text-indigo-200 mb-2">Patarimas</h4>
              <p className="text-sm leading-relaxed">{aiInsights.insights}</p>
            </div>
          </div>
        )}
      </div>

      {/* Grouped Charts */}
      <div className="grid gap-8">
        {categories.map(cat => {
          const catData = summaries
            .filter(s => s.category === cat)
            .map(s => ({
              name: s.question,
              avg: parseFloat(s.averageScore.toFixed(2)),
              isReverse: s.isReverse
            }))
            .sort((a, b) => b.avg - a.avg);

          if (catData.length === 0) return null;

          return (
            <div key={cat} className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100">
              <h3 className="text-lg font-black text-gray-800 mb-6 flex items-center gap-3">
                <span className="w-2 h-6 bg-indigo-500 rounded-full"></span>
                {cat}
              </h3>
              <div className="h-[300px]">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart data={catData} layout="vertical" margin={{ left: 10, right: 40 }}>
                    <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f3f4f6" />
                    <XAxis type="number" domain={[0, 5]} hide />
                    <YAxis 
                      dataKey="name" 
                      type="category" 
                      width={280} 
                      tick={<CustomYAxisTick />} 
                      axisLine={false} 
                      tickLine={false} 
                    />
                    <Tooltip 
                      cursor={{fill: '#f8fafc'}}
                      content={({active, payload}) => {
                        if (active && payload && payload.length) {
                          const data = payload[0].payload;
                          return (
                            <div className="bg-gray-900 text-white p-4 rounded-xl shadow-xl text-xs max-w-xs">
                              <p className="font-bold mb-2">{data.name}</p>
                              <p className="text-indigo-300">Vidurkis: <span className="text-white text-lg">{data.avg}</span></p>
                              {data.isReverse && <p className="text-rose-400 mt-1 text-[10px] font-bold uppercase">Atvirkštinis klausimas</p>}
                            </div>
                          );
                        }
                        return null;
                      }}
                    />
                    <Bar dataKey="avg" radius={[0, 6, 6, 0]} barSize={20}>
                      {catData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={getBarColor(entry.avg, entry.isReverse)} />
                      ))}
                      <LabelList dataKey="avg" position="right" offset={10} style={{ fill: '#6b7280', fontSize: '12px', fontWeight: 'bold' }} />
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>
          );
        })}
      </div>

      {/* Feedback Section */}
      <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-gray-100">
        <h3 className="text-lg font-black text-gray-800 mb-6 flex items-center gap-3">
          <i className="fas fa-comments text-indigo-500"></i> Mokinių balsas
        </h3>
        <div className="grid md:grid-cols-2 gap-4">
          {feedback.length > 0 ? feedback.map((f, i) => (
            <div key={i} className="p-5 bg-gray-50 rounded-2xl border border-gray-100 text-sm italic text-gray-600 leading-relaxed">
              "{f}"
            </div>
          )) : (
            <p className="text-gray-400 text-sm italic">Komentarų nepateikta.</p>
          )}
        </div>
      </div>
    </div>
  );
};

export default SummaryDashboard;

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData, CATEGORY_MAP, REVERSE_QUESTIONS } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showShareToast, setShowShareToast] = useState(false);
  const [history, setHistory] = useState<any[]>([]);

  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '', strengths: '', improvements: '', surprises: '',
    bestPractices: '', heartFeelings: '', headThoughts: '',
    actionStop: '', actionStart: '', actionContinue: '', nextSteps: ''
  });

  useEffect(() => {
    const savedHistory = localStorage.getItem('teacher_reflection_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const hash = window.location.hash;
    if (hash.startsWith('#data=')) {
      try {
        const base64 = hash.replace('#data=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(base64))));
        setReflection(decodedData);
        setStep(AppStep.REPORT);
        window.history.replaceState(null, '', window.location.pathname);
      } catch (e) { console.error(e); }
    }
  }, []);

  const saveToHistory = () => {
    const newEntry = {
      id: Date.now(),
      date: new Date().toISOString(),
      data: reflection,
      summary: summaries.length > 0 ? summaries[0].question.substring(0, 30) + '...' : 'Refleksija'
    };
    const updated = [newEntry, ...history].slice(0, 20);
    setHistory(updated);
    localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
  };

  const handleDataParsed = (rows: SurveyRow[]) => {
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;
    const headers = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    headers.forEach(header => {
      const headerLower = header.toLowerCase();
      const isFeedbackField = headerLower.includes('idėja') || headerLower.includes('pasiūlymas') || headerLower.includes('komentar');

      if (isFeedbackField) {
        rows.forEach(row => { if (row[header]?.trim()) feedback.push(row[header]); });
      } else {
        let sum = 0, validCount = 0, isNumeric = false;
        const counts: { [val: string]: number } = {};

        rows.forEach(row => {
          const val = row[header];
          if (val) {
            counts[val] = (counts[val] || 0) + 1;
            if (LIKERT_VALUES[val]) { sum += LIKERT_VALUES[val]; validCount++; isNumeric = true; }
          }
        });

        if (isNumeric && validCount > 0) {
          // Surandame artimiausią kategoriją pagal raktinį žodį
          const category = Object.keys(CATEGORY_MAP).find(k => header.includes(k)) 
            ? CATEGORY_MAP[Object.keys(CATEGORY_MAP).find(k => header.includes(k))!] 
            : 'Kita';

          newSummaries.push({
            question: header,
            counts,
            total: rows.length,
            averageScore: sum / validCount,
            category,
            isReverse: REVERSE_QUESTIONS.some(q => header.includes(q))
          });
        }
      }
    });

    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, aiInsights]);

  const handleShare = () => {
    const base64 = btoa(unescape(encodeURIComponent(JSON.stringify(reflection))));
    navigator.clipboard.writeText(`${window.location.origin}${window.location.pathname}#data=${base64}`);
    setShowShareToast(true);
    setTimeout(() => setShowShareToast(false), 3000);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {showShareToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-gray-900 text-white px-6 py-3 rounded-xl shadow-2xl animate-slide-up flex items-center gap-3">
          <i className="fas fa-check-circle text-emerald-400"></i> Nuoroda nukopijuota!
        </div>
      )}

      <header className="bg-white border-b border-gray-200 py-6 mb-8 print:hidden">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <i className="fas fa-graduation-cap"></i>
            </div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">Refleksijos Asistentas</h1>
          </div>
          {step !== AppStep.UPLOAD && (
            <button onClick={() => window.location.reload()} className="text-sm font-bold text-gray-500 hover:text-indigo-600 transition-colors">
              Pradėti naują
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-6">
        {step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-center space-y-4">
              <h2 className="text-4xl font-black text-gray-900">Labas! Pasiruošęs augti?</h2>
              <p className="text-gray-500 max-w-lg mx-auto">Įkelk apklausos CSV failą ir mes padėsime tau suprasti mokinių poreikius bei suplanuoti pokytį.</p>
            </div>

            <CSVUpload onParsed={handleDataParsed} />

            {history.length > 0 && (
              <div className="space-y-6">
                <h3 className="text-sm font-black uppercase tracking-widest text-gray-400">Tavo istorija</h3>
                <div className="grid md:grid-cols-2 gap-4">
                  {history.map(item => (
                    <button 
                      key={item.id} 
                      onClick={() => { setReflection(item.data); setStep(AppStep.REPORT); }}
                      className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all text-left flex items-center justify-between group"
                    >
                      <div>
