import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData, CATEGORY_MAP, REVERSE_QUESTIONS } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showShareToast, setShowShareToast] = useState(false);
  const [history, setHistory] = useState<any[]>([]);

  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '', strengths: '', improvements: '', surprises: '',
    bestPractices: '', heartFeelings: '', headThoughts: '',
    actionStop: '', actionStart: '', actionContinue: '', nextSteps: ''
  });

  useEffect(() => {
    const savedHistory = localStorage.getItem('teacher_reflection_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const hash = window.location.hash;
    if (hash.startsWith('#data=')) {
      try {
        const base64 = hash.replace('#data=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(base64))));
        setReflection(decodedData);
        setStep(AppStep.REPORT);
        window.history.replaceState(null, '', window.location.pathname);
      } catch (e) { console.error(e); }
    }
  }, []);

  const saveToHistory = () => {
    const newEntry = {
      id: Date.now(),
      date: new Date().toISOString(),
      data: reflection,
      summary: summaries.length > 0 ? summaries[0].question.substring(0, 30) + '...' : 'Mokslo metų vertinimas'
    };
    const updated = [newEntry, ...history].slice(0, 20);
    setHistory(updated);
    localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
  };

  const handleDataParsed = (rows: SurveyRow[]) => {
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;
    const headers = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    headers.forEach(header => {
      const headerLower = header.toLowerCase();
      const isFeedbackField = headerLower.includes('idėja') || headerLower.includes('pasiūlymas') || headerLower.includes('komentar');

      if (isFeedbackField) {
        rows.forEach(row => { if (row[header]?.trim()) feedback.push(row[header]); });
      } else {
        let sum = 0, validCount = 0, isNumeric = false;
        const counts: { [val: string]: number } = {};

        rows.forEach(row => {
          const val = row[header];
          if (val) {
            counts[val] = (counts[val] || 0) + 1;
            if (LIKERT_VALUES[val]) { sum += LIKERT_VALUES[val]; validCount++; isNumeric = true; }
          }
        });

        if (isNumeric && validCount > 0) {
          // Surandame artimiausią kategoriją pagal raktinį žodį
          const category = Object.keys(CATEGORY_MAP).find(k => header.includes(k)) 
            ? CATEGORY_MAP[Object.keys(CATEGORY_MAP).find(k => header.includes(k))!] 
            : 'Kita';

          newSummaries.push({
            question: header,
            counts,
            total: rows.length,
            averageScore: sum / validCount,
            category,
            isReverse: REVERSE_QUESTIONS.some(q => header.includes(q))
          });
        }
      }
    });

    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, aiInsights]);

  const handleShare = () => {
    const base64 = btoa(unescape(encodeURIComponent(JSON.stringify(reflection))));
    navigator.clipboard.writeText(`${window.location.origin}${window.location.pathname}#data=${base64}`);
    setShowShareToast(true);
    setTimeout(() => setShowShareToast(false), 3000);
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20">
      {showShareToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-gray-900 text-white px-6 py-3 rounded-xl shadow-2xl animate-slide-up flex items-center gap-3">
          <i className="fas fa-check-circle text-emerald-400"></i> Nuoroda nukopijuota!
        </div>
      )}

      <header className="bg-white border-b border-gray-200 py-6 mb-8 print:hidden">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white">
              <i className="fas fa-graduation-cap"></i>
            </div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">Refleksijos pagalbininkas</h1>
          </div>
          {step !== AppStep.UPLOAD && (
            <button onClick={() => window.location.reload()} className="text-sm font-bold text-gray-500 hover:text-indigo-600 transition-colors">
              Pradėti naują
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-6">
        {step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-center space-y-4">
              <h2 className="text-4xl font-black text-gray-900">Mokslo metų vertinimas</h2>
              <p className="text-gray-500 max-w-lg mx-auto">Įkelk apklausos CSV failą ir mes padėsime tau atlikti išsamų mokslo metų vertinimą.</p>
            </div>

            <CSVUpload onParsed={handleDataParsed} />

            {history.length > 0 && (
              <div className="space-y-6">
                <h3 className="text-sm font-black uppercase tracking-widest text-gray-400">Tavo istorija</h3>
                <div className="grid md:grid-cols-2 gap-4">
                  {history.map(item => (
                    <button 
                      key={item.id} 
                      onClick={() => { setReflection(item.data); setStep(AppStep.REPORT); }}
                      className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all text-left flex items-center justify-between group"
                    >
                      <div>
                        <p className="font-bold text-gray-800">{new Date(item.date).toLocaleDateString('lt-LT')}</p>
                        <p className="text-xs text-gray-400 mt-1 truncate max-w-[200px]">{item.summary}</p>
                      </div>
                      <i className="fas fa-arrow-right text-gray-200 group-hover:text-indigo-500 transition-colors"></i>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {step === AppStep.ANALYSIS && <SummaryDashboard summaries={summaries} feedback={openFeedback} aiInsights={aiInsights} isAnalyzing={isAnalyzing} onNext={() => setStep(AppStep.REFLECTION)} />}
        {step === AppStep.REFLECTION && <ReflectionWizard reflection={reflection} setReflection={setReflection} onComplete={() => { saveToHistory(); setStep(AppStep.REPORT); }} onBack={() => setStep(AppStep.ANALYSIS)} />}

        {step === AppStep.REPORT && (
          <div className="max-w-4xl mx-auto bg-white p-12 rounded-[3rem] shadow-xl border border-gray-100 animate-scale-in print:shadow-none print:p-0">
            <div className="flex justify-between items-start mb-12 border-b border-gray-100 pb-10 print:hidden">
              <div>
                <h2 className="text-3xl font-black text-gray-900">Mokslo metų vertinimo rezultatas</h2>
                <p className="text-gray-400 text-sm mt-1">{new Date().toLocaleDateString('lt-LT')}</p>
              </div>
              <div className="flex gap-3">
                <button onClick={handleShare} className="px-5 py-3 rounded-xl border border-gray-200 font-bold hover:bg-gray-50 flex items-center gap-2">
                  <i className="fas fa-link"></i> Dalintis
                </button>
                <button onClick={() => window.print()} className="px-5 py-3 rounded-xl bg-indigo-600 text-white font-bold hover:bg-indigo-700 flex items-center gap-2 shadow-lg shadow-indigo-100">
                  <i className="fas fa-file-pdf"></i> PDF
                </button>
              </div>
            </div>

            <div className="space-y-12">
              <section className="grid md:grid-cols-2 gap-8">
                <div className="space-y-4">
                  <h4 className="text-xs font-black uppercase tracking-widest text-indigo-500">Pastebėjimai</h4>
                  <p className="text-gray-700 leading-relaxed italic">"{reflection.observations || 'Nėra'}"</p>
                </div>
                <div className="space-y-4">
                  <h4 className="text-xs font-black uppercase tracking-widest text-emerald-500">Stiprybės</h4>
                  <p className="text-gray-700 leading-relaxed">{reflection.strengths || 'Nėra'}</p>
                </div>
              </section>

              <section className="bg-gray-50 p-8 rounded-[2rem] space-y-6">
                <h3 className="font-black text-gray-800 text-xl flex items-center gap-3">
                  <i className="fas fa-rocket text-indigo-600"></i> Veiksmų planas kitais mokslo metais
                </h3>
                <div className="grid md:grid-cols-3 gap-6">
                  <div>
                    <h5 className="text-[10px] font-black uppercase text-rose-500 mb-2">Nustosiu</h5>
                    <p className="text-sm text-gray-600">{reflection.actionStop || '-'}</p>
                  </div>
                  <div>
                    <h5 className="text-[10px] font-black uppercase text-emerald-500 mb-2">Pradėsiu</h5>
                    <p className="text-sm text-gray-600">{reflection.actionStart || '-'}</p>
                  </div>
                  <div>
                    <h5 className="text-[10px] font-black uppercase text-indigo-500 mb-2">Tęsiu</h5>
                    <p className="text-sm text-gray-600">{reflection.actionContinue || '-'}</p>
                  </div>
                </div>
              </section>

              <div className="text-center pt-8 border-t border-gray-100">
                <p className="text-xs text-gray-300 font-medium">Sugeneruota su Refleksijos pagalbininku</p>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [streak, setStreak] = useState(0);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number>(0);
  const [recordingDuration, setRecordingDuration] = useState(0);

  // AI Suggestions State
  const [aiSuggestions, setAiSuggestions] = useState<{bestPracticeSuggestions: string[], nextStepSuggestions: string[]}>({
    bestPracticeSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Persistence logic for streak
  useEffect(() => {
    const STREAK_KEY = 'teacher_reflection_streak';
    const LAST_DATE_KEY = 'teacher_reflection_last_date';

    const today = new Date().toDateString();
    const lastDate = localStorage.getItem(LAST_DATE_KEY);
    const savedStreak = parseInt(localStorage.getItem(STREAK_KEY) || '0', 10);

    if (lastDate === today) {
      setStreak(savedStreak || 1);
    } else {
      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 1);

      if (lastDate === yesterday.toDateString()) {
        const newStreak = savedStreak + 1;
        setStreak(newStreak);
        localStorage.setItem(STREAK_KEY, newStreak.toString());
        localStorage.setItem(LAST_DATE_KEY, today);
      } else {
        setStreak(1);
        localStorage.setItem(STREAK_KEY, '1');
        localStorage.setItem(LAST_DATE_KEY, today);
      }
    }
  }, []);

  // Handle Auto-save & Navigation Guard
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = '';
    };

    window.addEventListener('beforeunload', handleBeforeUnload);

    const draft = {
      reflection,
      currentStep,
      timestamp: new Date().getTime()
    };
    localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
    setLastSaved(new Date());

    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection, currentStep]);

  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => val === '');
        if (isCurrentlyEmpty && Object.values(parsed.reflection).some(val => val !== '')) {
          setShowResumePrompt(true);
        }
      } catch (e) {
        console.error("Failed to parse draft", e);
      }
    }
  }, []);

  const handleResume = () => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      const parsed = JSON.parse(savedDraft);
      setReflection(parsed.reflection);
      setCurrentStep(parsed.currentStep || 0);
    }
    setShowResumePrompt(false);
  };

  const handleStartFresh = () => {
    localStorage.removeItem(DRAFT_KEY);
    setShowResumePrompt(false);
  };

  // Audio Recording Functions
  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        await handleAudioProcess(audioBlob, field);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
      setRecordingDuration(0);
      recordingTimerRef.current = window.setInterval(() => {
        setRecordingDuration(prev => prev + 1);
      }, 1000);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Nepavyko pasiekti mikrofono. Prašome patikrinti naršyklės leidimus.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
      if (recordingTimerRef.current) {
        clearInterval(recordingTimerRef.current);
      }
    }
  };

  const handleAudioProcess = async (blob: Blob, field: string) => {
    setIsTranscribing(true);
    try {
      const reader = new FileReader();
      reader.readAsDataURL(blob);
      reader.onloadend = async () => {
        const base64Audio = (reader.result as string).split(',')[1];
        const transcription = await transcribeAudio(base64Audio, 'audio/webm');

        if (transcription) {
          setReflection(prev => ({
            ...prev,
            [field]: prev[field as keyof ReflectionData] 
              ? `${prev[field as keyof ReflectionData]}\n${transcription}` 
              : transcription
          }));
        }
        setIsTranscribing(false);
      };
    } catch (err) {
      console.error("Transcription failed:", err);
      setIsTranscribing(false);
      alert("Nepavyko transkribuoti balso. Bandykite dar kartą.");
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const generateAIPrompts = async () => {
    if (!reflection.observations && !reflection.strengths) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises
      );
      setAiSuggestions(suggestions);
    } catch (e) {
      console.error("Failed to fetch suggestions", e);
    } finally {
      setIsLoadingSuggestions(false);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prev => {
      const currentVal = prev[field];
      const newVal = currentVal 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prev, [field]: newVal };
    });
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas tau krenta į akis žiūrint į mokslo metų duomenis?",
      fields: [
        { 
          key: 'observations', 
          label: "Pasižymėk objektyvius pastebėjimus", 
          placeholder: "Pvz.: Pastebiu didelį atotrūkį tarp klausimų A ir B. Matau, kad dauguma mokinių vertina...",
          icon: "fa-eye text-indigo-500"
        }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, tobulėjimo kryptys ir netikėtumai",
      fields: [
        { 
          key: 'strengths', 
          label: "Kokie mokslo metų rezultatai džiugina?", 
          placeholder: "Didžiuojuosi tuo, kad...",
          icon: "fa-star text-yellow-500"
        },
        { 
          key: 'improvements', 
          label: "Kur matai didžiausią potencialą augti kitais metais?", 
          placeholder: "Norėčiau skirti daugiau dėmesio...",
          icon: "fa-chart-line text-emerald-500"
        },
        { 
          key: 'surprises', 
          label: "Kas tave nustebino šiais metais?", 
          placeholder: "Man buvo netikėta, kad...",
          icon: "fa-bolt text-amber-500"
        }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Kokius sėkmingus metodus pastebėjai šiais mokslo metais?",
      fields: [
        { 
          key: 'bestPractices', 
          label: "Įvardink 2-3 gerąsias praktikas", 
          placeholder: "Pvz.: Individualus grįžtamasis ryšys po kiekvieno testo pasiteisino. Planuoju dažniau naudoti grupines diskusijas...",
          icon: "fa-thumbs-up text-blue-500",
          suggestionsKey: 'bestPracticeSuggestions'
        }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo emocinė ir racionali reakcija į mokslo metus",
      fields: [
        { 
          key: 'heartFeelings', 
          label: "Kaip tavo ŠIRDIS reaguoja į mokinių žodžius?", 
          placeholder: "Jaučiuosi įvertintas, nes... Kartais pajuntu nerimą dėl...",
          icon: "fa-heart text-rose-500"
        },
        { 
          key: 'headThoughts', 
          label: "Ką apie tai sako tavo GALVA (racionalusis aš)?", 
          placeholder: "Racionaliai vertinant, rezultatai rodo, kad mano strategija...",
          icon: "fa-brain text-blue-500"
        }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais mokslo metais?",
      fields: [
        { 
          key: 'actionStop', 
          label: "Ką nustosi daryti?", 
          placeholder: "Nustosiu...",
          icon: "fa-circle-stop text-red-500"
        },
        { 
          key: 'actionStart', 
          label: "Ką pradėsi daryti?", 
          placeholder: "Pradėsiu...",
          icon: "fa-circle-play text-emerald-500"
        },
        { 
          key: 'actionContinue', 
          label: "Ką tęsi toliau?", 
          placeholder: "Toliau darysiu...",
          icon: "fa-rotate text-sky-500"
        },
        { 
          key: 'nextSteps', 
          label: "Kaip matuosi sėkmę kitais metais?", 
          placeholder: "Sėkmę matysiu per mokinių įsitraukimą, kai...",
          icon: "fa-bullseye text-indigo-500",
          suggestionsKey: 'nextStepSuggestions'
        }
      ]
    }
  ];

  const handleInputChange = (key: keyof ReflectionData, value: string) => {
    setReflection(prev => ({ ...prev, [key]: value }));
  };

  const next = async () => {
    if (currentStep < steps.length - 1) {
      if (currentStep === 1) {
        generateAIPrompts();
      }

      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }, 200);
    } else {
      localStorage.removeItem(DRAFT_KEY);
      onComplete();
    }
  };

  const prev = () => {
    if (currentStep > 0) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep - 1);
        setAnimating(false);
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }, 200);
    } else {
      onBack();
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Resume Progress Dialog */}
      {showResumePrompt && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md animate-fade-in">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl border border-white/20 animate-scale-in text-center">
            <div className="w-20 h-20 bg-indigo-50 rounded-3xl flex items-center justify-center mx-auto mb-6">
              <i className="fas fa-file-signature text-3xl text-indigo-600"></i>
            </div>
            <h3 className="text-2xl font-black text-gray-900 mb-4 tracking-tight">Tęsti nebaigtą darbą?</h3>
            <p className="text-gray-500 font-medium mb-10 leading-relaxed">
              Radome jūsų anksčiau pradėtą mokslo metų vertinimą. Ar norėtumėte tęsti nuo ten, kur sustojote?
            </p>
            <div className="flex flex-col gap-4">
              <button 
                onClick={handleResume}
                className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-black py-4 rounded-2xl transition-all shadow-xl shadow-indigo-100 active:scale-95"
              >
                Tęsti vertinimą
              </button>
              <button 
                onClick={handleStartFresh}
                className="w-full bg-gray-50 hover:bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl transition-all active:scale-95"
              >
                Pradėti iš naujo
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Main Bar Progress Container */}
      <div className="flex justify-between mb-16 relative px-4 sm:px-10">
        <div className="absolute top-1/2 left-0 w-full h-1.5 bg-gray-100 -translate-y-1/2 rounded-full -z-10"></div>
        <div 
          className="absolute top-1/2 left-0 h-1.5 bg-gradient-to-r from-indigo-500 to-purple-600 -translate-y-1/2 rounded-full -z-10 transition-all duration-700 ease-in-out shadow-[0_0_15px_rgba(99,102,241,0.3)]"
          style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}
        ></div>

        {steps.map((step, idx) => (
          <div key={idx} className="flex flex-col items-center relative">
            <button 
              onClick={() => idx < currentStep && setCurrentStep(idx)}
              disabled={idx > currentStep}
              className={`w-12 h-12 rounded-2xl flex items-center justify-center font-bold text-sm transition-all duration-500 border-2 ${
                idx === currentStep 
                  ? 'bg-white border-indigo-600 text-indigo-600 scale-125 shadow-xl rotate-3' 
                  : idx < currentStep 
                    ? 'bg-gradient-to-br from-indigo-600 to-purple-600 border-transparent text-white shadow-lg' 
                    : 'bg-white border-gray-200 text-gray-300'
              } ${idx < currentStep ? 'cursor-pointer hover:scale-110 active:scale-95' : 'cursor-default'}`}
            >
              {idx < currentStep ? <i className="fas fa-check text-xs"></i> : idx + 1}
            </button>
            <span className={`absolute -bottom-9 text-[11px] font-black uppercase tracking-widest whitespace-nowrap transition-all duration-300 ${
              idx === currentStep ? 'text-indigo-700 opacity-100' : 'text-gray-400 opacity-60'
            }`}>
              {step.title.split('. ')[1]}
            </span>
          </div>
        ))}
      </div>

      {/* Main Content Card */}
      <div className={`bg-gradient-to-b from-white to-gray-50/40 p-8 md:p-14 rounded-[3rem] shadow-2xl border border-white/60 backdrop-blur-sm transition-all duration-500 overflow-hidden ${animating ? 'opacity-0 translate-y-8 scale-95' : 'opacity-100 translate-y-0 scale-100'}`}>

        <div className="flex gap-2 mb-10 overflow-hidden">
          {steps.map((_, idx) => (
            <div 
              key={`bar-${idx}`}
              className={`h-1.5 flex-1 rounded-full transition-all duration-700 ${
                idx === currentStep 
                  ? 'bg-indigo-600 shadow-[0_0_10px_rgba(79,70,229,0.4)] animate-pulse' 
                  : idx < currentStep 
                    ? 'bg-indigo-200' 
                    : 'bg-gray-100'
              }`}
            />
          ))}
        </div>

        <header className="mb-12 text-center md:text-left relative">
          <div className="flex flex-wrap items-center justify-center md:justify-start gap-3 mb-6">
            <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-700 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.2em] shadow-sm border border-indigo-100/50">
              <span className="relative flex h-2 w-2">
                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
                <span className="relative inline-flex rounded-full h-2 w-2 bg-indigo-500"></span>
              </span>
              {currentStep + 1} žingsnis iš {steps.length}
            </div>

            <div className="inline-flex items-center gap-2 bg-gradient-to-r from-orange-500 to-rose-500 text-white text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-[0.2em] shadow-lg shadow-rose-200 border border-white/20 animate-fade-in">
              <i className="fas fa-fire animate-pulse text-yellow-300"></i>
              {streak} dienų refleksijos serija
            </div>
          </div>

          <h2 className="text-4xl font-black text-gray-900 mb-4 tracking-tight leading-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 text-xl font-medium leading-relaxed max-w-2xl">{steps[currentStep].description}</p>
          <div className="hidden md:block absolute -top-4 -right-4 opacity-[0.03] pointer-events-none">
            <i className={`fas ${steps[currentStep].fields[0].icon.split(' ')[0]} text-9xl`}></i>
          </div>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const charCount = reflection[field.key as keyof ReflectionData].length;
            const isFieldRecording = isRecording && recordingField === field.key;

            const fieldSuggestions = field.suggestionsKey ? (aiSuggestions as any)[field.suggestionsKey] || [] : [];

            return (
              <div key={field.key} className="group relative">
                <div className="flex items-center justify-between mb-4">
                  <label className="font-black text-gray-800 flex items-center gap-4 text-xl tracking-tight transition-all group-focus-within:text-indigo-600 group-focus-within:translate-x-1">
                    <span className={`w-10 h-10 rounded-xl bg-white border border-gray-100 shadow-sm flex items-center justify-center group-focus-within:bg-indigo-600 group-focus-within:text-white transition-all duration-500 group-focus-within:rotate-6`}>
                      <i className={`fas ${field.icon.split(' ')[0]}`}></i>
                    </span>
                    {field.label}
                  </label>

                  <div className="flex items-center gap-2">
                    {isFieldRecording && (
                      <span className="text-rose-500 text-xs font-black animate-pulse flex items-center gap-2 mr-2">
                        <i className="fas fa-circle text-[8px]"></i> RAŠOMA: {formatDuration(recordingDuration)}
                      </span>
                    )}
                    <button
                      onClick={() => isFieldRecording ? stopRecording() : startRecording(field.key)}
                      disabled={isTranscribing || (isRecording && recordingField !== field.key)}
                      className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all duration-300 shadow-md active:scale-90 ${
                        isFieldRecording 
                          ? 'bg-rose-500 text-white animate-pulse shadow-rose-200' 
                          : 'bg-white text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 border border-gray-100'
                      }`}
                      title={isFieldRecording ? "Sustabdyti įrašymą" : "Diktuoti balsu"}
                    >
                      <i className={`fas ${isFieldRecording ? 'fa-stop' : 'fa-microphone'}`}></i>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea
                    value={reflection[field.key as keyof ReflectionData]}
                    onChange={(e) => handleInputChange(field.key as keyof ReflectionData, e.target.value)}
                    placeholder={field.placeholder}
                    disabled={isTranscribing && recordingField === field.key}
                    className={`w-full h-44 p-8 rounded-[2rem] border-2 border-gray-100 bg-white/50 focus:bg-white focus:ring-[12px] focus:ring-indigo-500/5 focus:border-indigo-500/50 focus:shadow-xl transition-all duration-500 outline-none resize-none text-gray-700 text-lg leading-relaxed placeholder:text-gray-300 placeholder:italic ${
                      isTranscribing && recordingField === field.key ? 'opacity-60 cursor-wait' : ''
                    }`}
                  />

                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 flex items-center justify-center bg-white/20 backdrop-blur-[2px] rounded-[2rem]">
                      <div className="bg-white/90 px-6 py-4 rounded-2xl shadow-xl flex items-center gap-4 border border-gray-100">
                        <div className="animate-spin rounded-full h-5 w-5 border-2 border-indigo-600 border-t-transparent"></div>
                        <span className="text-sm font-black text-indigo-600 uppercase tracking-widest">Paverčiama tekstu...</span>
                      </div>
                    </div>
                  )}

                  <div className="absolute bottom-6 right-8 flex items-center gap-3 pointer-events-none">
                    <div className="flex items-center gap-1.5 bg-white/80 backdrop-blur-sm px-3 py-1 rounded-full shadow-sm border border-gray-100">
                      <div className={`h-1.5 w-1.5 rounded-full transition-all duration-300 ${charCount > 0 ? 'bg-indigo-500' : 'bg-gray-200'}`}></div>
                      <span className={`text-[10px] font-black uppercase tracking-widest ${charCount > 0 ? 'text-indigo-600' : 'text-gray-400'}`}>
                        {charCount} simbolių
                      </span>
                    </div>
                    <div className="w-px h-3 bg-gray-200"></div>
                    <span className="text-[10px] font-bold text-gray-300 uppercase tracking-widest">
                      {charCount < 20 ? 'Minimalus dėmesys' : charCount < 100 ? 'Geras gylis' : 'Išsami analizė'}
                    </span>
                  </div>
                </div>

                {/* AI Suggestions Display with Add Button */}
                {fieldSuggestions.length > 0 && !isRecording && (
                  <div className="mt-8 animate-fade-in">
                    <div className="flex items-center gap-3 mb-5 px-2">
                      <i className="fas fa-magic text-indigo-400 text-xs"></i>
                      <span className="text-[10px] font-black uppercase tracking-[0.2em] text-gray-400">DI Mentoriaus idėjos tau:</span>
                      {isLoadingSuggestions && <div className="animate-spin h-3 w-3 border-2 border-indigo-400 border-t-transparent rounded-full ml-auto"></div>}
                    </div>
                    <div className="grid gap-3">
                      {fieldSuggestions.map((suggestion: string, idx: number) => (
                        <div
                          key={idx}
                          className="bg-white/60 hover:bg-white p-5 rounded-[1.5rem] border border-gray-100 shadow-sm transition-all flex items-center justify-between gap-6 group hover:shadow-md hover:border-indigo-100/50"
                        >
                          <p className="text-gray-700 text-sm leading-relaxed font-medium">{suggestion}</p>
                          <button
                            onClick={() => insertSuggestion(field.key as keyof ReflectionData, suggestion)}
                            className="bg-indigo-600 hover:bg-indigo-700 text-white px-5 py-2.5 rounded-xl text-xs font-black flex items-center gap-2 transition-all active:scale-90 shrink-0 shadow-lg shadow-indigo-100 hover:shadow-indigo-200"
                          >
                            <i className="fas fa-plus"></i> Pridėti
                          </button>
                        </div>
                      ))}
                    </div>
                  </div>
                )}

                {isLoadingSuggestions && field.suggestionsKey && fieldSuggestions.length === 0 && (
                  <div className="mt-4 px-4 py-3 bg-gray-50 rounded-2xl border border-gray-100 flex items-center gap-3 animate-pulse">
                     <div className="w-2 h-2 bg-indigo-400 rounded-full"></div>
                     <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">Ruošiami individualūs pasiūlymai...</span>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        <div className="flex flex-col sm:flex-row justify-between items-center mt-16 pt-10 border-t border-gray-100 gap-6">
          <div className="flex flex-col gap-2">
            <button 
              onClick={prev}
              className="group w-full sm:w-auto text-gray-400 font-black hover:text-indigo-600 transition-all px-8 py-4 rounded-2xl hover:bg-indigo-50 active:scale-90 flex items-center justify-center gap-3"
            >
              <i className="fas fa-chevron-left transition-transform group-hover:-translate-x-1"></i> Grįžti
            </button>
            {lastSaved && (
              <div className="flex items-center gap-2 px-8 text-[9px] text-gray-400 font-black uppercase tracking-widest animate-fade-in">
                <span className="w-1.5 h-1.5 bg-emerald-500 rounded-full animate-pulse"></span>
                Automatiškai išsaugota {lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' })}
              </div>
            )}
          </div>

          <button 
            onClick={next}
            disabled={isRecording || isTranscribing}
            className={`w-full sm:w-auto bg-gradient-to-r from-indigo-600 to-purple-600 hover:from-indigo-700 hover:to-purple-700 active:scale-95 text-white font-black py-5 px-14 rounded-[1.5rem] transition-all shadow-[0_15px_30px_-10px_rgba(79,70,229,0.4)] hover:shadow-[0_20px_40px_-10px_rgba(79,70,229,0.5)] flex items-center justify-center gap-4 relative overflow-hidden group ${
              (isRecording || isTranscribing) ? 'opacity-50 cursor-not-allowed' : ''
            }`}
          >
            <span className="relative z-10">{currentStep === steps.length - 1 ? 'Generuoti galutinę ataskaitą' : 'Tęsti toliau'}</span>
            <i className="fas fa-arrow-right relative z-10 transition-transform group-hover:translate-x-1"></i>
            <div className="absolute inset-0 bg-white/20 translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
          </button>
        </div>
      </div>

      <div className="mt-12 bg-gray-900 rounded-[2.5rem] p-8 text-white flex flex-col md:flex-row items-center gap-8 animate-slide-up shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-500/10 blur-[100px] rounded-full pointer-events-none"></div>
        <div className="w-20 h-20 rounded-3xl bg-white/10 flex items-center justify-center shrink-0 shadow-inner backdrop-blur-md">
          <i className="fas fa-lightbulb text-3xl text-yellow-400 animate-pulse"></i>
        </div>
        <div className="text-center md:text-left">
          <h4 className="font-black text-xl mb-2 tracking-tight">Kiekvienas žodis yra tavo augimas</h4>
          <p className="text-indigo-200/80 text-lg leading-relaxed font-medium">Refleksija nėra skirta vertinimui. Tai tavo asmeninis įrankis sustoti, išgirsti mokinius ir suplanuoti pokytį, kuris džiugins tave ir tavo klasę.</p>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [streak, setStreak] = useState(0);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number>(0);
  const [recordingDuration, setRecordingDuration] = useState(0);

  // AI Suggestions State
  const [aiSuggestions, setAiSuggestions] = useState<{bestPracticeSuggestions: string[], nextStepSuggestions: string[]}>({
    bestPracticeSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Persistence logic for streak
  useEffect(() => {
    const STREAK_KEY = 'teacher_reflection_streak';
    const LAST_DATE_KEY = 'teacher_reflection_last_date';

    const today = new Date().toDateString();
    const lastDate = localStorage.getItem(LAST_DATE_KEY);
    const savedStreak = parseInt(localStorage.getItem(STREAK_KEY) || '0', 10);

    if (lastDate === today) {
      setStreak(savedStreak || 1);
    } else {
      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 1);

      if (lastDate === yesterday.toDateString()) {
        const newStreak = savedStreak + 1;
        setStreak(newStreak);
        localStorage.setItem(STREAK_KEY, newStreak.toString());
        localStorage.setItem(LAST_DATE_KEY, today);
      } else {
        setStreak(1);
        localStorage.setItem(STREAK_KEY, '1');
        localStorage.setItem(LAST_DATE_KEY, today);
      }
    }
  }, []);

  // Handle Auto-save & Navigation Guard
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = '';
    };

    window.addEventListener('beforeunload', handleBeforeUnload);

    const draft = {
      reflection,
      currentStep,
      timestamp: new Date().getTime()
    };
    localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
    setLastSaved(new Date());

    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection, currentStep]);

  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => val === '');
        if (isCurrentlyEmpty && Object.values(parsed.reflection).some(val => val !== '')) {
          setShowResumePrompt(true);
        }
      } catch (e) {
        console.error("Failed to parse draft", e);
      }
    }
  }, []);

  const handleResume = () => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      const parsed = JSON.parse(savedDraft);
      setReflection(parsed.reflection);
      setCurrentStep(parsed.currentStep || 0);
    }
    setShowResumePrompt(false);
  };

  const handleStartFresh = () => {
    localStorage.removeItem(DRAFT_KEY);
    setShowResumePrompt(false);
  };

  // Audio Recording Functions
  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => {
        if (event.data.size > 0) {
          audioChunksRef.current.push(event.data);
        }
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        await handleAudioProcess(audioBlob, field);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
      setRecordingDuration(0);
      recordingTimerRef.current = window.setInterval(() => {
        setRecordingDuration(prev => prev + 1);
      }, 1000);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      alert("Nepavyko pasiekti mikrofono. Prašome patikrinti naršyklės leidimus.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
      if (recordingTimerRef.current) {
        clearInterval(recordingTimerRef.current);
      }
    }
  };

  const handleAudioProcess = async (blob: Blob, field: string) => {
    setIsTranscribing(true);
    try {
      const reader = new FileReader();
      reader.readAsDataURL(blob);
      reader.onloadend = async () => {
        const base64Audio = (reader.result as string).split(',')[1];
        const transcription = await transcribeAudio(base64Audio, 'audio/webm');

        if (transcription) {
          setReflection(prev => {
            const currentText = prev[field as keyof ReflectionData];
            const updatedText = currentText 
              ? `${currentText.trim()}\n${transcription}` 
              : transcription;
            return { ...prev, [field]: updatedText };
          });
        }
        setIsTranscribing(false);
      };
    } catch (err) {
      console.error("Transcription failed:", err);
      setIsTranscribing(false);
      alert("Nepavyko transkribuoti balso. Bandykite dar kartą.");
    }
  };

  const formatDuration = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const generateAIPrompts = async () => {
    if (!reflection.observations && !reflection.strengths) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises
      );
      setAiSuggestions(suggestions);
    } catch (e) {
      console.error("Failed to fetch suggestions", e);
    } finally {
      setIsLoadingSuggestions(false);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prev => {
      const currentVal = prev[field];
      const newVal = currentVal 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prev, [field]: newVal };
    });
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
