          >
            Reflektuoti <i className="fas fa-arrow-right"></i>
          </button>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col justify-center items-center text-center">
          {isAnalyzing ? (
