            </>
          )}
        </div>
      </div>

      {/* DI Deep Analysis Section */}
      <div className="bg-indigo-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-96 h-96 bg-white/5 blur-[100px] rounded-full -mr-20 -mt-20"></div>
        <h3 className="text-xl font-black flex items-center gap-4 mb-8 relative z-10">
          <i className="fas fa-wand-magic-sparkles text-indigo-300"></i> Išmaniosios įžvalgos
        </h3>

        {isAnalyzing ? (
          <div className="flex items-center gap-6 py-8 relative z-10">
            <div className="w-10 h-10 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
            <div>
              <p className="font-black text-lg">DI gilinasi į mokinių mintis...</p>
              <p className="text-indigo-300/80 text-sm">Tai gali užtrukti iki 15 sekundžių</p>
