        ) : aiInsights && (
          <div className="space-y-10 relative z-10">
            <div className="grid md:grid-cols-2 gap-8">
              <div className="bg-white/10 p-6 rounded-[2rem] border border-white/10 backdrop-blur-md">
                <h4 className="text-[10px] uppercase font-black tracking-widest text-indigo-200 mb-4 flex items-center gap-2">
                  <i className="fas fa-check-circle"></i> Stipriosios vietos
                </h4>
                <p className="text-sm leading-relaxed text-indigo-50">{aiInsights.strengths}</p>
              </div>
              <div className="bg-white/10 p-6 rounded-[2rem] border border-white/10 backdrop-blur-md">
                <h4 className="text-[10px] uppercase font-black tracking-widest text-indigo-200 mb-4 flex items-center gap-2">
                  <i className="fas fa-arrow-alt-circle-up"></i> Tobulintinos sritys
