            </div>

            {/* Thematic Analysis - Deep visualization for text answers */}
            <div>
              <h4 className="text-[10px] uppercase font-black tracking-widest text-indigo-200 mb-6 flex items-center gap-2">
                <i className="fas fa-tags"></i> Teminė mokinių minčių analizė
