              <div className="grid md:grid-cols-3 gap-6">
                {aiInsights.themes?.map((theme: any, idx: number) => (
                  <div key={idx} className="bg-white/5 p-6 rounded-[1.5rem] border border-white/5 hover:bg-white/10 transition-all group">
