                          if (active && payload && payload.length) {
                            const data = payload[0].payload;
                            return (
                              <div className="bg-gray-900 text-white p-5 rounded-2xl shadow-2xl text-xs max-w-sm border border-white/10">
                                <p className="font-black mb-3 text-sm">{data.name}</p>
