                            );
                          }
                          return null;
                        }}
                      />
                      <Bar dataKey="avg" radius={[0, 10, 10, 0]} barSize={24}>
                        {catData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={getBarColor(entry.avg, entry.isReverse)} />
                        ))}
                        <LabelList dataKey="avg" position="right" offset={15} style={{ fill: '#475569', fontSize: '13px', fontWeight: '900' }} />
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
