                <button onClick={handlePDFDownload} className="flex-1 md:flex-none px-8 py-5 rounded-2xl bg-indigo-600 text-white font-black text-sm hover:bg-indigo-700 flex items-center justify-center gap-3 shadow-xl shadow-indigo-100 transition-all active:scale-95">
                  <i className="fas fa-file-pdf text-lg"></i> Išsaugoti PDF
                </button>
              </div>
            </div>

            <div className="space-y-16">
              <section className="grid md:grid-cols-2 gap-12">
