                    <h4 className="text-xs font-black uppercase tracking-[0.2em] text-indigo-500">Pastebėjimai</h4>
                  </div>
                  <p className="text-gray-700 leading-relaxed font-medium italic text-xl bg-gray-50/50 p-6 rounded-[2rem] border border-gray-100/50">"{reflection.observations || 'Nėra pastebėjimų.'}"</p>
