const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [streak, setStreak] = useState(0);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number>(0);
  const [recordingDuration, setRecordingDuration] = useState(0);

  // Quick Emotions Menu
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas'];

  // AI Suggestions State
  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  useEffect(() => {
    const STREAK_KEY = 'teacher_reflection_streak';
    const LAST_DATE_KEY = 'teacher_reflection_last_date';
    const today = new Date().toDateString();
    const lastDate = localStorage.getItem(LAST_DATE_KEY);
    const savedStreak = parseInt(localStorage.getItem(STREAK_KEY) || '0', 10);

    if (lastDate === today) {
      setStreak(savedStreak || 1);
    } else {
      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 1);
      if (lastDate === yesterday.toDateString()) {
        const newStreak = savedStreak + 1;
        setStreak(newStreak);
        localStorage.setItem(STREAK_KEY, newStreak.toString());
        localStorage.setItem(LAST_DATE_KEY, today);
      } else {
        setStreak(1);
        localStorage.setItem(STREAK_KEY, '1');
        localStorage.setItem(LAST_DATE_KEY, today);
      }
    }
  }, []);

  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = '';
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    const draft = { reflection, currentStep, timestamp: new Date().getTime() };
    localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
    setLastSaved(new Date());
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection, currentStep]);

  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => val === '');
        if (isCurrentlyEmpty && Object.values(parsed.reflection).some(val => val !== '')) {
          setShowResumePrompt(true);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  // Trigger AI suggestions when entering specific steps
  useEffect(() => {
    if (currentStep > 0) {
      generateAIPrompts();
    }
  }, [currentStep]);

  const generateAIPrompts = async () => {
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises
      );
      setAiSuggestions(suggestions);
    } catch (e) { console.error(e); } finally { setIsLoadingSuggestions(false); }
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (event) => { if (event.data.size > 0) audioChunksRef.current.push(event.data); };
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        setIsTranscribing(true);
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          const transcription = await transcribeAudio(base64Audio, 'audio/webm');
          if (transcription) {
            setReflection(prev => ({ ...prev, [field]: prev[field as keyof ReflectionData] ? `${prev[field as keyof ReflectionData].trim()}\n${transcription}` : transcription }));
          }
          setIsTranscribing(false);
        };
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
      setRecordingDuration(0);
      recordingTimerRef.current = window.setInterval(() => setRecordingDuration(prev => prev + 1), 1000);
    } catch (err) { alert("Nepavyko pasiekti mikrofono."); }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
      if (recordingTimerRef.current) clearInterval(recordingTimerRef.current);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prev => {
      const currentVal = prev[field];
      const newVal = currentVal ? `${currentVal.trim()}\n• ${suggestion}` : `• ${suggestion}`;
      return { ...prev, [field]: newVal };
    });
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu didelį atotrūkį...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai",
      fields: [
        { key: 'strengths', label: "Kas džiugina?", placeholder: "Didžiuojuosi tuo...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Kur augti?", placeholder: "Norėčiau skirti...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Buvo netikėta...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Grįžtamasis ryšys pasiteisino...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Sėkmę matysiu per...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {showResumePrompt && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4">Tęsti nebaigtą darbą?</h3>
            <div className="flex flex-col gap-4">
              <button onClick={() => { const d = JSON.parse(localStorage.getItem(DRAFT_KEY)!); setReflection(d.reflection); setCurrentStep(d.currentStep); setShowResumePrompt(false); }} className="bg-indigo-600 text-white font-black py-4 rounded-2xl">Tęsti</button>
              <button onClick={() => { localStorage.removeItem(DRAFT_KEY); setShowResumePrompt(false); }} className="bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl">Iš naujo</button>
            </div>
          </div>
        </div>
      )}

      {/* Progress */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-rose-50 text-rose-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            <i className="fas fa-fire animate-pulse"></i> {streak} dienų serija
          </div>
          <h2 className="text-3xl font-black text-gray-900">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => (
            <div key={field.key} className="space-y-4">
              <div className="flex items-center justify-between">
                <label className="font-black text-gray-800 flex items-center gap-3">
                  <i className={`fas ${field.icon} text-indigo-500`}></i> {field.label}
                </label>
                <div className="flex gap-2">
                  {field.hasEmotions && (
                    <div className="relative">
                      <button onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} className="w-10 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center hover:bg-rose-100 transition-all shadow-sm">
                        <i className="fas fa-face-smile"></i>
                      </button>
                      {showEmotionsMenu && (
                        <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-3 w-48 animate-fade-in">
                          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-2 px-2">Pasirinkite nuotaiką:</p>
                          {emotionsList.map(emo => (
                            <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-50 rounded-lg font-medium transition-all">{emo}</button>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                  <button onClick={() => isRecording && recordingField === field.key ? stopRecording() : startRecording(field.key)} className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isRecording && recordingField === field.key ? 'bg-rose-500 text-white animate-pulse' : 'bg-gray-50 text-gray-400 hover:text-indigo-600'}`}>
                    <i className={`fas ${isRecording && recordingField === field.key ? 'fa-stop' : 'fa-microphone'}`}></i>
                  </button>
                </div>
              </div>
              <div className="relative">
                <textarea value={(reflection as any)[field.key]} onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} placeholder={field.placeholder} className="w-full h-32 p-6 rounded-3xl border-2 border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50 focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none resize-none font-medium text-gray-700"></textarea>
                {isTranscribing && recordingField === field.key && <div className="absolute inset-0 bg-white/60 backdrop-blur-sm rounded-3xl flex items-center justify-center font-black text-indigo-600 text-xs tracking-widest uppercase">Perrašoma...</div>}
              </div>

              {/* AI Suggestions for this field */}
              {field.suggestionsKey && aiSuggestions[field.suggestionsKey]?.length > 0 && (
                <div className="bg-indigo-50/50 p-6 rounded-[2rem] border border-indigo-100/50 space-y-4">
                  <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                    <i className="fas fa-magic"></i> Mentoriaus pasiūlymai
                  </div>
                  <div className="grid gap-2">
                    {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                      <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-xs bg-white p-3 rounded-xl border border-indigo-100/30 hover:border-indigo-300 hover:shadow-md transition-all text-gray-600 leading-relaxed group">
                        <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500"></i> {s}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>

        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={prev} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>
          <button onClick={() => { if (currentStep < steps.length - 1) { setAnimating(true); setTimeout(() => { setCurrentStep(currentStep + 1); setAnimating(false); }, 200); } else onComplete(); }} className="bg-indigo-600 text-white font-black px-12 py-5 rounded-2xl shadow-xl hover:shadow-indigo-100 transition-all active:scale-95 flex items-center gap-3">
            {currentStep === steps.length - 1 ? 'Baigti' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData, CATEGORY_MAP, REVERSE_QUESTIONS } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showShareToast, setShowShareToast] = useState(false);
  const [history, setHistory] = useState<any[]>([]);

  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '', strengths: '', improvements: '', surprises: '',
    bestPractices: '', heartFeelings: '', headThoughts: '',
    actionStop: '', actionStart: '', actionContinue: '', nextSteps: ''
  });

  useEffect(() => {
    const savedHistory = localStorage.getItem('teacher_reflection_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const hash = window.location.hash;
    if (hash.startsWith('#data=')) {
      try {
        const base64 = hash.replace('#data=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(base64))));
        setReflection(decodedData);
        setStep(AppStep.REPORT);
        window.history.replaceState(null, '', window.location.pathname);
      } catch (e) { console.error(e); }
    }
  }, []);

  const saveToHistory = () => {
    const newEntry = {
      id: Date.now(),
      date: new Date().toISOString(),
      data: reflection,
      summary: summaries.length > 0 ? summaries[0].question.substring(0, 30) + '...' : 'Mokslo metų vertinimas'
    };
    const updated = [newEntry, ...history].slice(0, 20);
    setHistory(updated);
    localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
  };

  const handleDataParsed = (rows: SurveyRow[]) => {
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const cleanHeader = (header: string): string => {
    const match = header.match(/\[(.*?)\]/);
    if (match && match[1]) return match[1].trim();
    return header.replace(/^Prašome atsakyti į klausimus nuoširdžiai, taip, kaip manote ir jaučiatės\.\s*/i, '').trim();
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;
    const rawHeaders = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    rawHeaders.forEach(rawHeader => {
      if (rawHeader.toLowerCase().includes('laiko žymė')) return;
      const cleanedHeader = cleanHeader(rawHeader);
      const headerLower = rawHeader.toLowerCase();
      const isFeedbackField = headerLower.includes('idėja') || headerLower.includes('pasiūlymas') || headerLower.includes('komentar') || headerLower.includes('kodėl') || headerLower.includes('manote') || headerLower.includes('jaučiatės');

      let sum = 0, validCount = 0, isNumeric = false;
      const counts: { [val: string]: number } = {};

      rows.forEach(row => {
        const val = row[rawHeader]?.trim();
        if (val) {
          counts[val] = (counts[val] || 0) + 1;
          const normalizedVal = val.endsWith('.') ? val.slice(0, -1) : val;
          if (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]) { 
            sum += (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]); 
            validCount++; 
            isNumeric = true; 
          }
        }
      });

      if (isNumeric && validCount > 0) {
        const categoryKey = Object.keys(CATEGORY_MAP).find(k => cleanedHeader.toLowerCase().includes(k.toLowerCase()) || rawHeader.toLowerCase().includes(k.toLowerCase()));
        const category = categoryKey ? CATEGORY_MAP[categoryKey] : 'Kita';
        newSummaries.push({
          question: cleanedHeader,
          counts,
          total: rows.length,
          averageScore: sum / validCount,
          category,
          isReverse: REVERSE_QUESTIONS.some(q => cleanedHeader.toLowerCase().includes(q.toLowerCase()))
        });
      } else {
        rows.forEach(row => { 
          const val = row[rawHeader]?.trim();
          if (val && val.length > 5 && !LIKERT_VALUES[val] && !LIKERT_VALUES[val.slice(0, -1)]) feedback.push(val); 
        });
      }
    });
    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, aiInsights, openFeedback]);

  const handleShare = () => {
    const dataString = JSON.stringify(reflection);
    const base64 = btoa(unescape(encodeURIComponent(dataString)));
    const url = `${window.location.origin}${window.location.pathname}#data=${base64}`;
    navigator.clipboard.writeText(url).then(() => {
      setShowShareToast(true);
      setTimeout(() => setShowShareToast(false), 3000);
    });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 selection:bg-indigo-100">
      {showShareToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[200] bg-gray-900 text-white px-8 py-4 rounded-2xl shadow-2xl animate-slide-up flex items-center gap-4 border border-white/10">
          <i className="fas fa-check-circle text-emerald-400"></i> Nuoroda nukopijuota sėkmingai!
        </div>
      )}

      <header className="bg-white border-b border-gray-100 py-6 mb-8 print:hidden">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><i className="fas fa-graduation-cap"></i></div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">Refleksijos pagalbininkas</h1>
          </div>
          {step !== AppStep.UPLOAD && <button onClick={() => window.location.reload()} className="text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-indigo-600">Nauja analizė</button>}
        </div>
      </header>

      <main className="container mx-auto px-6">
        {step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-center space-y-4">
              <h2 className="text-5xl font-black text-gray-900 tracking-tight">Mokslo metų analizė</h2>
              <p className="text-gray-500 max-w-lg mx-auto text-lg font-medium">Įkelk apklausos rezultatus ir leisk DI mentorystei nukreipti tavo augimą.</p>
            </div>
            <CSVUpload onParsed={handleDataParsed} />
            {history.length > 0 && (
              <div className="space-y-4">
                <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 px-2">Istorija</h3>
                <div className="grid md:grid-cols-2 gap-4">
                  {history.map(item => (
                    <button key={item.id} onClick={() => { setReflection(item.data); setStep(AppStep.REPORT); }} className="bg-white p-6 rounded-[2rem] border border-gray-100 text-left flex items-center justify-between group hover:shadow-xl hover:border-indigo-100 transition-all">
                      <div><p className="font-black text-gray-800 text-lg">{new Date(item.date).toLocaleDateString('lt-LT')}</p><p className="text-xs text-gray-400 mt-1 uppercase font-bold tracking-wider">{item.summary}</p></div>
                      <i className="fas fa-chevron-right text-gray-200 group-hover:text-indigo-500 transition-all"></i>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {step === AppStep.ANALYSIS && <SummaryDashboard summaries={summaries} feedback={openFeedback} aiInsights={aiInsights} isAnalyzing={isAnalyzing} onNext={() => setStep(AppStep.REFLECTION)} />}

        {step === AppStep.REFLECTION && <ReflectionWizard reflection={reflection} setReflection={setReflection} onComplete={() => { saveToHistory(); setStep(AppStep.REPORT); }} onBack={() => setStep(AppStep.ANALYSIS)} />}

        {step === AppStep.REPORT && (
          <div className="max-w-4xl mx-auto bg-white p-10 md:p-16 rounded-[4rem] shadow-2xl animate-scale-in print:shadow-none print:p-0">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16 border-b border-gray-100 pb-12 print:hidden gap-6">
              <div>
                <h2 className="text-4xl font-black text-gray-900">Refleksijos rezultatas</h2>
                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs mt-2">{new Date().toLocaleDateString('lt-LT')}</p>
              </div>
              <div className="flex gap-3 w-full md:w-auto">
                <button onClick={handleShare} className="flex-1 px-6 py-4 rounded-2xl border-2 border-indigo-50 text-indigo-600 font-black text-sm flex items-center justify-center gap-2 transition-all active:scale-95"><i className="fas fa-share"></i> Dalintis</button>
                <button onClick={() => window.print()} className="flex-1 px-6 py-4 rounded-2xl bg-indigo-600 text-white font-black text-sm flex items-center justify-center gap-2 shadow-xl shadow-indigo-100 transition-all active:scale-95"><i className="fas fa-file-pdf"></i> Atsisiųsti PDF</button>
              </div>
            </div>

            <div className="space-y-16">
              <section className="grid md:grid-cols-2 gap-12">
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">Pastebėjimai</h4><p className="text-gray-700 italic text-xl">"{reflection.observations || '-'}"</p></div>
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-500">Stiprybės</h4><p className="text-gray-700 text-xl font-medium">{reflection.strengths || '-'}</p></div>
              </section>

              <section className="bg-slate-900 text-white p-12 rounded-[3rem] space-y-10 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-500/10 blur-[100px] rounded-full"></div>
                <h3 className="font-black text-2xl flex items-center gap-4 relative z-10"><i className="fas fa-rocket text-indigo-400"></i> Veiksmų planas</h3>
                <div className="grid md:grid-cols-3 gap-10 relative z-10 text-indigo-50/80">
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-rose-400 border-b border-rose-400/20 pb-2">Nustosiu</h5><p className="text-sm">{reflection.actionStop || '-'}</p></div>
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-emerald-400 border-b border-emerald-400/20 pb-2">Pradėsiu</h5><p className="text-sm">{reflection.actionStart || '-'}</p></div>
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-indigo-400 border-b border-indigo-400/20 pb-2">Tęsiu</h5><p className="text-sm">{reflection.actionContinue || '-'}</p></div>
                </div>
                <div className="pt-8 border-t border-white/5 relative z-10 text-indigo-50/80">
                  <h5 className="text-[10px] font-black uppercase text-indigo-300 mb-2">Sėkmės matavimas</h5>
                  <p className="text-sm">{reflection.nextSteps || '-'}</p>
                </div>
              </section>

              <section className="grid md:grid-cols-2 gap-12">
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase text-gray-400">Geroji patirtis</h4><p className="text-gray-700">{reflection.bestPractices || '-'}</p></div>
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase text-gray-400">Emocinis fonas</h4><p className="text-gray-700">{reflection.heartFeelings} {reflection.headThoughts}</p></div>
              </section>

              <div className="text-center pt-10 border-t border-gray-100"><p className="text-[9px] text-gray-300 font-black uppercase tracking-[0.4em]">Refleksijos pagalbininkas • Profesinis augimas</p></div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [streak, setStreak] = useState(0);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number>(0);
  const [recordingDuration, setRecordingDuration] = useState(0);

  // Quick Emotions Menu
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas'];

  // AI Suggestions State
  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  useEffect(() => {
    const STREAK_KEY = 'teacher_reflection_streak';
    const LAST_DATE_KEY = 'teacher_reflection_last_date';
    const today = new Date().toDateString();
    const lastDate = localStorage.getItem(LAST_DATE_KEY);
    const savedStreak = parseInt(localStorage.getItem(STREAK_KEY) || '0', 10);

    if (lastDate === today) {
      setStreak(savedStreak || 1);
    } else {
      const yesterday = new Date();
      yesterday.setDate(yesterday.getDate() - 1);
      if (lastDate === yesterday.toDateString()) {
        const newStreak = savedStreak + 1;
        setStreak(newStreak);
        localStorage.setItem(STREAK_KEY, newStreak.toString());
        localStorage.setItem(LAST_DATE_KEY, today);
      } else {
        setStreak(1);
        localStorage.setItem(STREAK_KEY, '1');
        localStorage.setItem(LAST_DATE_KEY, today);
      }
    }
  }, []);

  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = '';
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    const draft = { reflection, currentStep, timestamp: new Date().getTime() };
    localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
    setLastSaved(new Date());
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection, currentStep]);

  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => val === '');
        if (isCurrentlyEmpty && Object.values(parsed.reflection).some(val => val !== '')) {
          setShowResumePrompt(true);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  // Trigger AI suggestions when entering specific steps
  useEffect(() => {
    if (currentStep > 0) {
      generateAIPrompts();
    }
  }, [currentStep]);

  const generateAIPrompts = async () => {
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises
      );
      setAiSuggestions(suggestions);
    } catch (e) { console.error(e); } finally { setIsLoadingSuggestions(false); }
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (event) => { if (event.data.size > 0) audioChunksRef.current.push(event.data); };
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        setIsTranscribing(true);
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          const transcription = await transcribeAudio(base64Audio, 'audio/webm');
          if (transcription) {
            setReflection(prevRef => ({ ...prevRef, [field]: prevRef[field as keyof ReflectionData] ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription}` : transcription }));
          }
          setIsTranscribing(false);
        };
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
      setRecordingDuration(0);
      recordingTimerRef.current = window.setInterval(() => setRecordingDuration(prevDur => prevDur + 1), 1000);
    } catch (err) { alert("Nepavyko pasiekti mikrofono."); }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
      if (recordingTimerRef.current) clearInterval(recordingTimerRef.current);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal ? `${currentVal.trim()}\n• ${suggestion}` : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  // Fix: Defined the missing 'prev' function to handle navigating to the previous step or exit the wizard
  const prev = () => {
    if (currentStep > 0) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep - 1);
        setAnimating(false);
      }, 200);
    } else {
      onBack();
    }
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu didelį atotrūkį...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai",
      fields: [
        { key: 'strengths', label: "Kas džiugina?", placeholder: "Didžiuojuosi tuo...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Kur augti?", placeholder: "Norėčiau skirti...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Buvo netikėta...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Grįžtamasis ryšys pasiteisino...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Sėkmę matysiu per...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {showResumePrompt && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4">Tęsti nebaigtą darbą?</h3>
            <div className="flex flex-col gap-4">
              <button onClick={() => { const d = JSON.parse(localStorage.getItem(DRAFT_KEY)!); setReflection(d.reflection); setCurrentStep(d.currentStep); setShowResumePrompt(false); }} className="bg-indigo-600 text-white font-black py-4 rounded-2xl">Tęsti</button>
              <button onClick={() => { localStorage.removeItem(DRAFT_KEY); setShowResumePrompt(false); }} className="bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl">Iš naujo</button>
            </div>
          </div>
        </div>
      )}

      {/* Progress */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-rose-50 text-rose-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            <i className="fas fa-fire animate-pulse"></i> {streak} dienų serija
          </div>
          <h2 className="text-3xl font-black text-gray-900">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => (
            <div key={field.key} className="space-y-4">
              <div className="flex items-center justify-between">
                <label className="font-black text-gray-800 flex items-center gap-3">
                  <i className={`fas ${field.icon} text-indigo-500`}></i> {field.label}
                </label>
                <div className="flex gap-2">
                  {field.hasEmotions && (
                    <div className="relative">
                      <button onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} className="w-10 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center hover:bg-rose-100 transition-all shadow-sm">
                        <i className="fas fa-face-smile"></i>
                      </button>
                      {showEmotionsMenu && (
                        <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-3 w-48 animate-fade-in">
                          <p className="text-[10px] font-black uppercase tracking-widest text-gray-400 mb-2 px-2">Pasirinkite nuotaiką:</p>
                          {emotionsList.map(emo => (
                            <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-sm hover:bg-gray-50 rounded-lg font-medium transition-all">{emo}</button>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                  <button onClick={() => isRecording && recordingField === field.key ? stopRecording() : startRecording(field.key)} className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${isRecording && recordingField === field.key ? 'bg-rose-500 text-white animate-pulse' : 'bg-gray-50 text-gray-400 hover:text-indigo-600'}`}>
                    <i className={`fas ${isRecording && recordingField === field.key ? 'fa-stop' : 'fa-microphone'}`}></i>
                  </button>
                </div>
              </div>
              <div className="relative">
                <textarea value={(reflection as any)[field.key]} onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} placeholder={field.placeholder} className="w-full h-32 p-6 rounded-3xl border-2 border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50 focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none resize-none font-medium text-gray-700"></textarea>
                {isTranscribing && recordingField === field.key && <div className="absolute inset-0 bg-white/60 backdrop-blur-sm rounded-3xl flex items-center justify-center font-black text-indigo-600 text-xs tracking-widest uppercase">Perrašoma...</div>}
              </div>

              {/* AI Suggestions for this field */}
              {field.suggestionsKey && aiSuggestions[field.suggestionsKey]?.length > 0 && (
                <div className="bg-indigo-50/50 p-6 rounded-[2rem] border border-indigo-100/50 space-y-4">
                  <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                    <i className="fas fa-magic"></i> Mentoriaus pasiūlymai
                  </div>
                  <div className="grid gap-2">
                    {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                      <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-xs bg-white p-3 rounded-xl border border-indigo-100/30 hover:border-indigo-300 hover:shadow-md transition-all text-gray-600 leading-relaxed group">
                        <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500"></i> {s}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          ))}
        </div>

        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={prev} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>
          <button onClick={() => { if (currentStep < steps.length - 1) { setAnimating(true); setTimeout(() => { setCurrentStep(currentStep + 1); setAnimating(false); }, 200); } else onComplete(); }} className="bg-indigo-600 text-white font-black px-12 py-5 rounded-2xl shadow-xl hover:shadow-indigo-100 transition-all active:scale-95 flex items-center gap-3">
            {currentStep === steps.length - 1 ? 'Baigti' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import { GoogleGenAI, Type } from "@google/genai";
import { QuestionSummary } from "../types";

// Fix: Strictly following initialization guidelines by using process.env.API_KEY directly
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAIInsights = async (summaries: QuestionSummary[], openFeedback: string[]) => {
  const prompt = `
    Esi švietimo ekspertas ir duomenų analitikas. Tau pateikiama mokslo metų pabaigos mokinių apklausos santrauka. 
    Analizuok šiuos duomenis itin išsamiai.

    KIEKYBINIAI DUOMENYS (Skalės 1-5):
    ${JSON.stringify(summaries)}

    KOKYBINIAI DUOMENYS (Mokinių tekstiniai atsakymai, jausmai, mintys):
    ${openFeedback.join("\n")}

    Remiantis šiais duomenimis, sugeneruok išsamią analizę JSON formatu lietuvių kalba:
    1. "strengths": Pagrindinės stiprybės.
    2. "improvements": Sritys, kurias mokiniai norėtų keisti.
    3. "insights": Gilios pedagoginės įžvalgos apie pamokų dėsningumus.
    4. "themes": Išskirk 3-4 pagrindines temas iš tekstinių atsakymų (pvz., "Emocinis saugumas", "Mokymo tempas"). Kiekvienai temai pateik trumpą aprašymą ir vyraujančią nuotaiką (teigiama/neutrali/neigiama).
    5. "sentimentScore": Bendras mokslo metų emocinis fonas procentais (nuo 0 iki 100).
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            strengths: { type: Type.STRING },
            improvements: { type: Type.STRING },
            insights: { type: Type.STRING },
            sentimentScore: { type: Type.NUMBER },
            themes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  label: { type: Type.STRING },
                  description: { type: Type.STRING },
                  sentiment: { type: Type.STRING }
                },
                required: ["label", "description", "sentiment"]
              }
            }
          },
          required: ["strengths", "improvements", "insights", "themes", "sentimentScore"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini AI error:", error);
    return {
      strengths: "Nepavyko sugeneruoti įžvalgų.",
      improvements: "Peržiūrėkite duomenis rankiniu būdu.",
      insights: "",
      sentimentScore: 50,
      themes: []
    };
  }
};

export const getReflectionSuggestions = async (observations: string, strengths: string, improvements: string, surprises: string) => {
  const prompt = `
    Esi pedagoginis mentorius. Mokytojas atlieka mokslo metų savirefleksiją.
    Remdamasis jo užrašais, pasiūlyk konkrečių įžvalgų visiems refleksijos etapams.

    MOKYTOJO IKI ŠIOL UŽFIKSUOTI UŽRAŠAI:
    Pastebėjimai: ${observations}
    Stiprybės: ${strengths}
    Tobulintinos sritys: ${improvements}
    Netikėtumai: ${surprises}

    Sugeneruok trumpus, po 1-2 sakinius, pasiūlymus šioms sritims:
    1. "observationSuggestions": 3 patarimai, į ką dar vertėtų atkreipti dėmesį duomenyse.
    2. "analysisSuggestions": 3 įžvalgos apie gilesnes priežastis (stiprybes/tobulėjimą).
    3. "bestPracticeSuggestions": 3 konkretūs metodai tęstinumui.
    4. "emotionSuggestions": 3 idėjos, kaip įvardinti savo profesinius jausmus.
    5. "actionSuggestions": 3 konkretūs pokyčiai (nustoti/pradėti/tęsti).
    6. "nextStepSuggestions": 3 būdai matuoti sėkmę.

    Atsakymą pateik JSON formatu lietuvių kalba.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            observationSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            analysisSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            bestPracticeSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            emotionSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            actionSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            nextStepSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: [
            "observationSuggestions", 
            "analysisSuggestions", 
            "bestPracticeSuggestions", 
            "emotionSuggestions", 
            "actionSuggestions", 
            "nextStepSuggestions"
          ]
        }
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Suggestions error:", error);
