import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const recordingTimerRef = useRef<number>(0);
  const [recordingDuration, setRecordingDuration] = useState(0);

  // Quick Emotions Menu
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];

  // AI Suggestions State
  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      e.preventDefault();
      e.returnValue = '';
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    const draft = { reflection, currentStep, timestamp: new Date().getTime() };
    localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
    setLastSaved(new Date());
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection, currentStep]);

  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => val === '');
        if (isCurrentlyEmpty && Object.values(parsed.reflection).some(val => val !== '')) {
          setShowResumePrompt(true);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  // Trigger AI suggestions when entering specific steps
  useEffect(() => {
    if (currentStep > 0) {
      generateAIPrompts();
    }
  }, [currentStep]);

  const generateAIPrompts = async () => {
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises
      );
      setAiSuggestions(suggestions);
    } catch (e) { console.error(e); } finally { setIsLoadingSuggestions(false); }
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (event) => { if (event.data.size > 0) audioChunksRef.current.push(event.data); };
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        setIsTranscribing(true);
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          const transcription = await transcribeAudio(base64Audio, 'audio/webm');
          if (transcription) {
            setReflection(prevRef => ({ ...prevRef, [field]: prevRef[field as keyof ReflectionData] ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription}` : transcription }));
          }
          setIsTranscribing(false);
        };
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
      setRecordingDuration(0);
      recordingTimerRef.current = window.setInterval(() => setRecordingDuration(prevDur => prevDur + 1), 1000);
    } catch (err) { alert("Nepavyko pasiekti mikrofono."); }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
      if (recordingTimerRef.current) clearInterval(recordingTimerRef.current);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal ? `${currentVal.trim()}\n• ${suggestion}` : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const prev = () => {
    if (currentStep > 0) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep - 1);
        setAnimating(false);
      }, 200);
    } else {
      onBack();
    }
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu didelį atotrūkį...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai",
      fields: [
        { key: 'strengths', label: "Kas džiugina?", placeholder: "Didžiuojuosi tuo...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Kur augti?", placeholder: "Norėčiau skirti...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Buvo netikėta...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Grįžtamasis ryšys pasiteisino...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į rezultatus",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Sėkmę matysiu per...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {showResumePrompt && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight">Tęsti nebaigtą darbą?</h3>
            <div className="flex flex-col gap-4">
              <button onClick={() => { const d = JSON.parse(localStorage.getItem(DRAFT_KEY)!); setReflection(d.reflection); setCurrentStep(d.currentStep); setShowResumePrompt(false); }} className="bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Tęsti</button>
              <button onClick={() => { localStorage.removeItem(DRAFT_KEY); setShowResumePrompt(false); }} className="bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl hover:bg-gray-200 transition-all">Iš naujo</button>
            </div>
          </div>
        </div>
      )}

      {/* Progress */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => (
            <div key={field.key} className="space-y-4">
              <div className="flex items-center justify-between">
                <label className="font-black text-gray-800 flex items-center gap-3">
                  <i className={`fas ${field.icon} text-indigo-500`}></i> {field.label}
                </label>
                <div className="flex gap-2">
                  {field.hasEmotions && (
                    <div className="relative">
                      <button 
                        onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                        className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest"
                      >
                        <i className="fas fa-face-smile"></i>
                        <span>Nuotaikos</span>
                      </button>
                      {showEmotionsMenu && (
                        <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                          <p className="text-[9px] font-black uppercase tracking-[0.2em] text-gray-400 mb-3 px-2">Pasirinkite būseną:</p>
                          <div className="grid gap-1">
                            {emotionsList.map(emo => (
                              <button 
                                key={emo} 
                                onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} 
                                className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group"
                              >
                                {emo}
                                <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                              </button>
                            ))}
                          </div>
                        </div>
                      )}
                    </div>
                  )}
                  <button 
                    onClick={() => isRecording && recordingField === field.key ? stopRecording() : startRecording(field.key)} 
                    className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all shadow-sm ${isRecording && recordingField === field.key ? 'bg-rose-500 text-white animate-pulse' : 'bg-gray-50 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50'}`}
                    title="Įrašyti balsu"
                  >
                    <i className={`fas ${isRecording && recordingField === field.key ? 'fa-stop' : 'fa-microphone'}`}></i>
                  </button>
                </div>
              </div>
              <div className="relative">
                <textarea 
                  value={(reflection as any)[field.key]} 
                  onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                  placeholder={field.placeholder} 
                  className="w-full h-32 p-6 rounded-3xl border-2 border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50 focus:ring-4 focus:ring-indigo-500/5 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300"
                ></textarea>
                {isTranscribing && recordingField === field.key && (
                  <div className="absolute inset-0 bg-white/60 backdrop-blur-sm rounded-3xl flex items-center justify-center font-black text-indigo-600 text-[10px] tracking-[0.3em] uppercase">
                    Perrašoma...
                  </div>
                )}
              </div>

              {/* AI Suggestions for this field */}
              {field.suggestionsKey && aiSuggestions[field.suggestionsKey]?.length > 0 && (
                <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4 animate-fade-in">
                  <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                    <i className="fas fa-magic"></i> Mentoriaus pasiūlymai
                  </div>
                  <div className="grid gap-2">
                    {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                      <button 
                        key={idx} 
                        onClick={() => insertSuggestion(field.key as any, s)} 
                        className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]"
                      >
                        <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                      </button>
                    ))}
                  </div>
                </div>
              )}

              {isLoadingSuggestions && field.suggestionsKey && (
                <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                  <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiami pasiūlymai...</span>
                </div>
              )}
            </div>
          ))}
        </div>

        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={prev} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>
          <button 
            onClick={() => { if (currentStep < steps.length - 1) { setAnimating(true); setTimeout(() => { setCurrentStep(currentStep + 1); setAnimating(false); }, 200); } else onComplete(); }} 
            className="bg-indigo-600 text-white font-black px-12 py-5 rounded-2xl shadow-xl hover:shadow-indigo-100 transition-all active:scale-95 flex items-center gap-3"
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

