                          position="right" 
                          offset={12} 
                          style={{ fill: '#475569', fontSize: '10px', fontWeight: '900', fontFamily: 'monospace' }} 
                        />
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Raw Feedback Section */}
