      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
