import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData, CATEGORY_MAP, REVERSE_QUESTIONS } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showShareToast, setShowShareToast] = useState(false);
  const [history, setHistory] = useState<any[]>([]);

  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '', strengths: '', improvements: '', surprises: '',
    bestPractices: '', heartFeelings: '', headThoughts: '',
    actionStop: '', actionStart: '', actionContinue: '', nextSteps: ''
  });

  useEffect(() => {
    const savedHistory = localStorage.getItem('teacher_reflection_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const hash = window.location.hash;
    if (hash.startsWith('#data=')) {
      try {
        const base64 = hash.replace('#data=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(base64))));
        setReflection(decodedData);
        setStep(AppStep.REPORT);
        window.history.replaceState(null, '', window.location.pathname);
      } catch (e) { console.error(e); }
    }
  }, []);

  const saveToHistory = () => {
    const newEntry = {
      id: Date.now(),
      date: new Date().toISOString(),
      data: reflection,
      summary: summaries.length > 0 ? summaries[0].question.substring(0, 30) + '...' : 'Mokslo metų vertinimas'
    };
    const updated = [newEntry, ...history].slice(0, 20);
    setHistory(updated);
    localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
  };

  const handleDataParsed = (rows: SurveyRow[]) => {
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const handleNewAnalysis = () => {
    if (step !== AppStep.UPLOAD) {
      if (confirm('Ar tikrai norite pradėti naują analizę? Visi nebaigti refleksijos pokyčiai gali būti prarasti.')) {
        window.location.reload();
      }
    }
  };

  const cleanHeader = (header: string): string => {
    const match = header.match(/\[(.*?)\]/);
    if (match && match[1]) return match[1].trim();
    return header.replace(/^Prašome atsakyti į klausimus nuoširdžiai, taip, kaip manote ir jaučiatės\.\s*/i, '').trim();
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;
    const rawHeaders = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    rawHeaders.forEach(rawHeader => {
      if (rawHeader.toLowerCase().includes('laiko žymė')) return;
      const cleanedHeader = cleanHeader(rawHeader);
      const headerLower = rawHeader.toLowerCase();
      const isFeedbackField = headerLower.includes('idėja') || headerLower.includes('pasiūlymas') || headerLower.includes('komentar') || headerLower.includes('kodėl') || headerLower.includes('manote') || headerLower.includes('jaučiatės');

      let sum = 0, validCount = 0, isNumeric = false;
      const counts: { [val: string]: number } = {};

      rows.forEach(row => {
        const val = row[rawHeader]?.trim();
        if (val) {
          counts[val] = (counts[val] || 0) + 1;
          const normalizedVal = val.endsWith('.') ? val.slice(0, -1) : val;
          if (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]) { 
            sum += (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]); 
            validCount++; 
            isNumeric = true; 
          }
        }
      });

      if (isNumeric && validCount > 0) {
        const categoryKey = Object.keys(CATEGORY_MAP).find(k => cleanedHeader.toLowerCase().includes(k.toLowerCase()) || rawHeader.toLowerCase().includes(k.toLowerCase()));
        const category = categoryKey ? CATEGORY_MAP[categoryKey] : 'Kita';
        newSummaries.push({
          question: cleanedHeader,
          counts,
          total: rows.length,
          averageScore: sum / validCount,
          category,
          isReverse: REVERSE_QUESTIONS.some(q => cleanedHeader.toLowerCase().includes(q.toLowerCase()))
        });
      } else {
        rows.forEach(row => { 
          const val = row[rawHeader]?.trim();
          if (val && val.length > 5 && !LIKERT_VALUES[val] && !LIKERT_VALUES[val.slice(0, -1)]) feedback.push(val); 
        });
      }
    });
    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, aiInsights, openFeedback]);

  const handleShare = () => {
    const dataString = JSON.stringify(reflection);
    const base64 = btoa(unescape(encodeURIComponent(dataString)));
    const url = `${window.location.origin}${window.location.pathname}#data=${base64}`;
    navigator.clipboard.writeText(url).then(() => {
      setShowShareToast(true);
      setTimeout(() => setShowShareToast(false), 3000);
    });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 selection:bg-indigo-100">
      {showShareToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[200] bg-gray-900 text-white px-8 py-4 rounded-2xl shadow-2xl animate-slide-up flex items-center gap-4 border border-white/10">
          <i className="fas fa-check-circle text-emerald-400"></i> Nuoroda nukopijuota sėkmingai!
        </div>
      )}

      <header className="bg-white border-b border-gray-100 py-6 mb-8 print:hidden">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><i className="fas fa-graduation-cap"></i></div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">Refleksijos pagalbininkas</h1>
          </div>
          {step !== AppStep.UPLOAD && (
            <button onClick={handleNewAnalysis} className="text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-indigo-600 transition-colors">
              Nauja analizė
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-6">
        {step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-center space-y-4">
              <h2 className="text-5xl font-black text-gray-900 tracking-tight">Mokslo metų analizė</h2>
              <p className="text-gray-500 max-w-lg mx-auto text-lg font-medium">Įkelk apklausos rezultatus ir leisk DI mentorystei nukreipti tavo augimą.</p>
            </div>
            <CSVUpload onParsed={handleDataParsed} />
            {history.length > 0 && (
              <div className="space-y-4">
                <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 px-2">Ankstesnės refleksijos</h3>
                <div className="grid md:grid-cols-2 gap-4">
                  {history.map(item => (
                    <button key={item.id} onClick={() => { setReflection(item.data); setStep(AppStep.REPORT); }} className="bg-white p-6 rounded-[2rem] border border-gray-100 text-left flex items-center justify-between group hover:shadow-xl hover:border-indigo-100 transition-all">
                      <div><p className="font-black text-gray-800 text-lg">{new Date(item.date).toLocaleDateString('lt-LT')}</p><p className="text-xs text-gray-400 mt-1 uppercase font-bold tracking-wider">{item.summary}</p></div>
                      <i className="fas fa-chevron-right text-gray-200 group-hover:text-indigo-500 transition-all"></i>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {step === AppStep.ANALYSIS && <SummaryDashboard summaries={summaries} feedback={openFeedback} aiInsights={aiInsights} isAnalyzing={isAnalyzing} onNext={() => setStep(AppStep.REFLECTION)} />}

        {step === AppStep.REFLECTION && <ReflectionWizard reflection={reflection} setReflection={setReflection} aiInsights={aiInsights} onComplete={() => { saveToHistory(); setStep(AppStep.REPORT); }} onBack={() => setStep(AppStep.ANALYSIS)} />}

        {step === AppStep.REPORT && (
          <div className="max-w-4xl mx-auto bg-white p-10 md:p-16 rounded-[4rem] shadow-2xl animate-scale-in print:shadow-none print:p-0">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16 border-b border-gray-100 pb-12 print:hidden gap-6">
              <div>
                <h2 className="text-4xl font-black text-gray-900">Refleksijos rezultatas</h2>
                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs mt-2">{new Date().toLocaleDateString('lt-LT')}</p>
              </div>
              <div className="flex gap-3 w-full md:w-auto">
                <button onClick={handleShare} className="flex-1 px-6 py-4 rounded-2xl border-2 border-indigo-50 text-indigo-600 font-black text-sm flex items-center justify-center gap-2 transition-all active:scale-95"><i className="fas fa-share"></i> Dalintis</button>
                <button onClick={() => window.print()} className="flex-1 px-6 py-4 rounded-2xl bg-indigo-600 text-white font-black text-sm flex items-center justify-center gap-2 shadow-xl shadow-indigo-100 transition-all active:scale-95"><i className="fas fa-file-pdf"></i> Atsisiųsti PDF</button>
              </div>
            </div>

            <div className="space-y-16">
              <section className="grid md:grid-cols-2 gap-12">
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">Pastebėjimai</h4><p className="text-gray-700 italic text-xl">"{reflection.observations || '-'}"</p></div>
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-500">Stiprybės</h4><p className="text-gray-700 text-xl font-medium">{reflection.strengths || '-'}</p></div>
              </section>

              <section className="bg-slate-900 text-white p-12 rounded-[3rem] space-y-10 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-500/10 blur-[100px] rounded-full"></div>
                <h3 className="font-black text-2xl flex items-center gap-4 relative z-10"><i className="fas fa-rocket text-indigo-400"></i> Veiksmų planas kitais metais</h3>
                <div className="grid md:grid-cols-3 gap-10 relative z-10 text-indigo-50/80">
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-rose-400 border-b border-rose-400/20 pb-2">Nustosiu</h5><p className="text-sm">{reflection.actionStop || '-'}</p></div>
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-emerald-400 border-b border-emerald-400/20 pb-2">Pradėsiu</h5><p className="text-sm">{reflection.actionStart || '-'}</p></div>
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-indigo-400 border-b border-indigo-400/20 pb-2">Tęsiu</h5><p className="text-sm">{reflection.actionContinue || '-'}</p></div>
                </div>
                <div className="pt-8 border-t border-white/5 relative z-10 text-indigo-50/80">
                  <h5 className="text-[10px] font-black uppercase text-indigo-300 mb-2">Kaip žinosiu, kad vaikams sekasi geriau?</h5>
                  <p className="text-sm">{reflection.nextSteps || '-'}</p>
                </div>
              </section>

              <section className="grid md:grid-cols-2 gap-12">
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase text-gray-400">Geroji patirtis</h4><p className="text-gray-700">{reflection.bestPractices || '-'}</p></div>
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase text-gray-400">Refleksijos emocija</h4><p className="text-gray-700">{reflection.heartFeelings} • {reflection.headThoughts}</p></div>
              </section>

              <div className="text-center pt-10 border-t border-gray-100"><p className="text-[9px] text-gray-300 font-black uppercase tracking-[0.4em]">Refleksijos pagalbininkas • Profesinis augimas mokinio sėkmei</p></div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  aiInsights: any;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  aiInsights,
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [showFinalConfirm, setShowFinalConfirm] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [touchedSteps, setTouchedSteps] = useState<Set<number>>(new Set());
  const [focusedFieldKey, setFocusedFieldKey] = useState<string | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);

  // Moods / Emotions
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];

  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Auto-save effect
  useEffect(() => {
    setIsAutoSaving(true);
    const timeout = setTimeout(() => {
      const draft = { reflection, currentStep, timestamp: new Date().getTime() };
      localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
      setLastSaved(new Date());
      setIsAutoSaving(false);
    }, 1000);

    return () => clearTimeout(timeout);
  }, [reflection, currentStep]);

  // Tab close prevention
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      const hasContent = Object.values(reflection).some(v => (v as string).trim().length > 10);
      if (hasContent) {
        e.preventDefault();
        e.returnValue = 'Ar tikrai norite išeiti? Jūsų nebaigta refleksija yra išsaugota naršyklėje kaip juodraštis.';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection]);

  // Resume Draft Check
  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => (val as string).trim() === '');
        const draftHasContent = Object.values(parsed.reflection).some(val => (val as string).trim() !== '');
        if (isCurrentlyEmpty && draftHasContent) {
          setShowResumePrompt(true);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  // AI Suggestions Trigger
  useEffect(() => {
    // Generate suggestions if we have some manual input or just at key steps
    const isTriggerStep = currentStep >= 0; 

    if (isTriggerStep && aiInsights) {
      const timer = setTimeout(() => {
        generateAIPrompts();
      }, 500); // Small debounce
      return () => clearTimeout(timer);
    }
  }, [currentStep, reflection.observations, reflection.strengths, reflection.improvements]);

  const generateAIPrompts = async () => {
    if (isLoadingSuggestions) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises,
        aiInsights
      );
      setAiSuggestions(suggestions);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsLoadingSuggestions(false); 
    }
  };

  const handleFieldFocus = (fieldKey: string) => {
    setFocusedFieldKey(fieldKey);
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];
      mediaRecorder.ondataavailable = (event) => { if (event.data.size > 0) audioChunksRef.current.push(event.data); };
      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: 'audio/webm' });
        setIsTranscribing(true);
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          const base64Audio = (reader.result as string).split(',')[1];
          const transcription = await transcribeAudio(base64Audio, 'audio/webm');
          if (transcription) {
            setReflection(prevRef => ({ 
              ...prevRef, 
              [field]: prevRef[field as keyof ReflectionData] 
                ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription}` 
                : transcription 
            }));
          }
          setIsTranscribing(false);
        };
        stream.getTracks().forEach(track => track.stop());
      };
      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
    } catch (err) { alert("Nepavyko pasiekti mikrofono."); }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal && currentVal.trim().length > 0 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į mokinių duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu, kad mokiniai nurodė...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai mokinio akimis",
      fields: [
        { key: 'strengths', label: "Kuo mokiniai džiaugiasi?", placeholder: "Mokiniams patiko...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Ką vaikai norėtų keisti?", placeholder: "Mokiniai indikavo, kad...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Nebuvau pagalvojęs, kad mokiniai...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai, kuriuos vertina vaikai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į vaikų atvirumą",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Pamačius mokinių atsakymus, jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant mokinių poreikius...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais dėl savo mokinių?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Kitąmet mokiniai turėtų pajusti...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  const currentStepFields = steps[currentStep].fields;
  const isStepValid = currentStepFields.every(field => {
    const val = (reflection as any)[field.key];
    return val && val.trim().length > 0;
  });

  const next = () => {
    setTouchedSteps(prev => new Set(prev).add(currentStep));
    if (!isStepValid) return;

    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
      }, 200);
    } else {
      setShowFinalConfirm(true);
    }
  };

  const handleBackWithConfirm = () => {
    if (Object.values(reflection).some(v => (v as string).trim().length > 5)) {
      setShowExitConfirm(true);
    } else {
      onBack();
    }
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Resume Draft Prompt */}
      {showResumePrompt && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center animate-scale-in">
            <h3 className="text-2xl font-black mb-4 tracking-tight">Tęsti nebaigtą darbą?</h3>
            <p className="text-gray-500 mb-8 font-medium">Radome išsaugotą jūsų refleksijos juodraštį.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { 
                const d = JSON.parse(localStorage.getItem(DRAFT_KEY)!); 
                setReflection(d.reflection); 
                setCurrentStep(d.currentStep); 
                setShowResumePrompt(false); 
              }} className="bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Tęsti pildymą</button>
              <button onClick={() => { 
                localStorage.removeItem(DRAFT_KEY); 
                setShowResumePrompt(false); 
              }} className="bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl hover:bg-gray-200 transition-all">Pradėti iš naujo</button>
            </div>
          </div>
        </div>
      )}

      {/* Exit Confirmation */}
      {showExitConfirm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight text-rose-600">Išeiti iš refleksijos?</h3>
            <p className="text-gray-500 mb-8 font-medium">Jūsų progresas išsaugotas kaip juodraštis, bet grįšite į duomenų apžvalgą.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { setShowExitConfirm(false); onBack(); }} className="bg-gray-900 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Taip, išeiti</button>
              <button onClick={() => setShowExitConfirm(false)} className="bg-indigo-50 text-indigo-600 font-black py-4 rounded-2xl hover:bg-indigo-100 transition-all">Likti ir pildyti</button>
            </div>
          </div>
        </div>
      )}

      {/* Final Summary Confirmation Modal */}
      {showFinalConfirm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/70 backdrop-blur-lg">
          <div className="bg-white rounded-[3rem] p-8 md:p-12 max-w-2xl w-full shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="mb-8 shrink-0">
              <h3 className="text-3xl font-black text-gray-900 tracking-tight">Refleksijos santrauka</h3>
              <p className="text-gray-500 font-medium mt-2">Peržiūrėkite savo įžvalgas prieš generuojant galutinę ataskaitą.</p>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-8">
              {steps.map((step, idx) => (
                <div key={idx} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500 border-b border-indigo-50 pb-2">{step.title}</h4>
                  <div className="space-y-6">
                    {step.fields.map(field => (
                      <div key={field.key} className="bg-slate-50 p-6 rounded-2xl border border-gray-100">
                        <p className="text-[10px] font-black uppercase text-gray-400 mb-2 flex items-center gap-2">
                          <i className={`fas ${field.icon} text-[8px]`}></i> {field.label}
                        </p>
                        <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">{(reflection as any)[field.key] || '-'}</p>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-10 shrink-0 grid grid-cols-2 gap-4">
              <button 
                onClick={() => setShowFinalConfirm(false)} 
                className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-all active:scale-95 text-sm"
              >
                Grįžti ir taisyti
              </button>
              <button 
                onClick={() => { setShowFinalConfirm(false); onComplete(); }} 
                className="bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-95 text-sm"
              >
                Patvirtinti ir baigti
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Auto-save Status */}
      <div className="flex items-center justify-between mb-8 px-4">
        <div className="flex items-center gap-3">
           <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${isAutoSaving ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
             {isAutoSaving ? 'Išsaugoma...' : `Auto-išsaugota: ${lastSaved ? lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' }) : 'Ką tik'}`}
           </span>
        </div>
        <div className="text-[10px] font-black uppercase tracking-widest text-indigo-400">
          Žingsnis {currentStep + 1} iš {steps.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard Content Card */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const val = (reflection as any)[field.key];
            const isEmpty = !val || val.trim().length === 0;
            const showError = isEmpty && touchedSteps.has(currentStep);
            const isFocused = focusedFieldKey === field.key;
            const isThisRecording = isRecording && recordingField === field.key;

            return (
              <div key={field.key} className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="font-black text-gray-800 flex items-center gap-3">
                    <i className={`fas ${field.icon} ${showError ? 'text-rose-500' : 'text-indigo-500'}`}></i> 
                    {field.label}
                    {showError && <span className="text-[9px] text-rose-500 uppercase tracking-widest font-black bg-rose-50 px-2 py-0.5 rounded-full">Privaloma</span>}
                  </label>

                  <div className="flex gap-2">
                    {field.hasEmotions && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                          className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-face-smile"></i> Nuotaikos
                        </button>
                        {showEmotionsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {emotionsList.map(emo => (
                                <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {emo} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}
                    <button 
                      onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                      className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${isThisRecording ? 'bg-rose-500 text-white animate-pulse' : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'}`}
                      title={isThisRecording ? "Sustabdyti" : "Įrašyti balsu"}
                    >
                      <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'}`}></i>
                      <span>{isThisRecording ? 'Sustabdyti' : 'Įrašyti balsu'}</span>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea 
                    value={val} 
                    onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                    onFocus={() => handleFieldFocus(field.key)}
                    placeholder={field.placeholder} 
                    className={`w-full h-32 p-6 rounded-3xl border-2 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300 ${
                      showError ? 'border-rose-100 bg-rose-50/20 focus:border-rose-300' : 'border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50'
                    } ${isFocused ? 'ring-4 ring-indigo-500/5' : ''}`}
                  ></textarea>
                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 bg-white/60 backdrop-blur-sm rounded-3xl flex items-center justify-center font-black text-indigo-600 text-[10px] tracking-[0.3em] uppercase">
                      Perrašoma...
                    </div>
                  )}
                </div>

                {/* AI Suggestions Section */}
                {isFocused && field.suggestionsKey && (
                  <div className="space-y-4 animate-fade-in">
                    {aiSuggestions[field.suggestionsKey]?.length > 0 ? (
                      <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4">
                        <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <i className="fas fa-magic"></i> Mentoriaus įžvalgos pagal mokinius
                        </div>
                        <div className="grid gap-2">
                          {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                            <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]">
                              <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                            </button>
                          ))}
                        </div>
                      </div>
                    ) : isLoadingSuggestions ? (
                      <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiame pagalbą...</span>
                      </div>
                    ) : null}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Footer Navigation */}
        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={handleBackWithConfirm} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>

          <button 
            onClick={next} 
            disabled={!isStepValid}
            className={`font-black px-12 py-5 rounded-2xl shadow-xl transition-all active:scale-95 flex items-center gap-3 ${
              isStepValid ? 'bg-indigo-600 text-white hover:shadow-indigo-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'
            }`}
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  aiInsights: any;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  aiInsights,
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [showFinalConfirm, setShowFinalConfirm] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [touchedSteps, setTouchedSteps] = useState<Set<number>>(new Set());
  const [focusedFieldKey, setFocusedFieldKey] = useState<string | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  // Moods / Emotions
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];

  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Recording Timer
  useEffect(() => {
    if (isRecording) {
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setRecordingTime(0);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isRecording]);

  // Auto-save effect
  useEffect(() => {
    setIsAutoSaving(true);
    const timeout = setTimeout(() => {
      const draft = { reflection, currentStep, timestamp: new Date().getTime() };
      localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
      setLastSaved(new Date());
      setIsAutoSaving(false);
    }, 1000);

    return () => clearTimeout(timeout);
  }, [reflection, currentStep]);

  // Tab close prevention
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      const hasContent = Object.values(reflection).some(v => (v as string).trim().length > 10);
      if (hasContent) {
        e.preventDefault();
        e.returnValue = 'Ar tikrai norite išeiti? Jūsų nebaigta refleksija yra išsaugota naršyklėje kaip juodraštis.';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection]);

  // Resume Draft Check
  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => (val as string).trim() === '');
        const draftHasContent = Object.values(parsed.reflection).some(val => (val as string).trim() !== '');
        if (isCurrentlyEmpty && draftHasContent) {
          setShowResumePrompt(true);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  // AI Suggestions Trigger
  useEffect(() => {
    const isTriggerStep = currentStep >= 0; 
    if (isTriggerStep && aiInsights) {
      const timer = setTimeout(() => {
        generateAIPrompts();
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [currentStep, reflection.observations, reflection.strengths, reflection.improvements]);

  const generateAIPrompts = async () => {
    if (isLoadingSuggestions) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises,
        aiInsights
      );
      setAiSuggestions(suggestions);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsLoadingSuggestions(false); 
    }
  };

  const handleFieldFocus = (fieldKey: string) => {
    setFocusedFieldKey(fieldKey);
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => { 
        if (event.data.size > 0) audioChunksRef.current.push(event.data); 
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        setIsTranscribing(true);

        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          try {
            const base64Audio = (reader.result as string).split(',')[1];
            const transcription = await transcribeAudio(base64Audio, audioBlob.type);
            if (transcription && transcription.trim()) {
              setReflection(prevRef => ({ 
                ...prevRef, 
                [field]: prevRef[field as keyof ReflectionData] 
                  ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription.trim()}` 
                  : transcription.trim() 
              }));
            }
          } catch (err) {
            console.error("Transcription failed", err);
            alert("Nepavyko perrašyti garso. Bandykite dar kartą arba rašykite tekstą.");
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
    } catch (err) { 
      alert("Nepavyko pasiekti mikrofono. Patikrinkite naršyklės nustatymus."); 
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal && currentVal.trim().length > 0 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į mokinių duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu, kad mokiniai nurodė...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai mokinio akimis",
      fields: [
        { key: 'strengths', label: "Kuo mokiniai džiaugiasi?", placeholder: "Mokiniams patiko...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Ką vaikai norėtų keisti?", placeholder: "Mokiniai indikavo, kad...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Nebuvau pagalvojęs, kad mokiniai...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai, kuriuos vertina vaikai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į vaikų atvirumą",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Pamačius mokinių atsakymus, jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant mokinių poreikius...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais dėl savo mokinių?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Kitąmet mokiniai turėtų pajusti...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  const currentStepFields = steps[currentStep].fields;
  const isStepValid = currentStepFields.every(field => {
    const val = (reflection as any)[field.key];
    return val && val.trim().length > 0;
  });

  const next = () => {
    setTouchedSteps(prev => new Set(prev).add(currentStep));
    if (!isStepValid) return;

    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
      }, 200);
    } else {
      setShowFinalConfirm(true);
    }
  };

  const handleBackWithConfirm = () => {
    if (Object.values(reflection).some(v => (v as string).trim().length > 5)) {
      setShowExitConfirm(true);
    } else {
      onBack();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Resume Draft Prompt */}
      {showResumePrompt && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center animate-scale-in">
            <h3 className="text-2xl font-black mb-4 tracking-tight">Tęsti nebaigtą darbą?</h3>
            <p className="text-gray-500 mb-8 font-medium">Radome išsaugotą jūsų refleksijos juodraštį.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { 
                const d = JSON.parse(localStorage.getItem(DRAFT_KEY)!); 
                setReflection(d.reflection); 
                setCurrentStep(d.currentStep); 
                setShowResumePrompt(false); 
              }} className="bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Tęsti pildymą</button>
              <button onClick={() => { 
                localStorage.removeItem(DRAFT_KEY); 
                setShowResumePrompt(false); 
              }} className="bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl hover:bg-gray-200 transition-all">Pradėti iš naujo</button>
            </div>
          </div>
        </div>
      )}

      {/* Exit Confirmation */}
      {showExitConfirm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight text-rose-600">Išeiti iš refleksijos?</h3>
            <p className="text-gray-500 mb-8 font-medium">Jūsų progresas išsaugotas kaip juodraštis, bet grįšite į duomenų apžvalgą.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { setShowExitConfirm(false); onBack(); }} className="bg-gray-900 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Taip, išeiti</button>
              <button onClick={() => setShowExitConfirm(false)} className="bg-indigo-50 text-indigo-600 font-black py-4 rounded-2xl hover:bg-indigo-100 transition-all">Likti ir pildyti</button>
            </div>
          </div>
        </div>
      )}

      {/* Final Summary Confirmation Modal */}
      {showFinalConfirm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/70 backdrop-blur-lg">
          <div className="bg-white rounded-[3rem] p-8 md:p-12 max-w-2xl w-full shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="mb-8 shrink-0">
              <h3 className="text-3xl font-black text-gray-900 tracking-tight">Refleksijos santrauka</h3>
              <p className="text-gray-500 font-medium mt-2">Peržiūrėkite savo įžvalgas prieš generuojant galutinę ataskaitą.</p>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-8">
              {steps.map((step, idx) => (
                <div key={idx} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500 border-b border-indigo-50 pb-2">{step.title}</h4>
                  <div className="space-y-6">
                    {step.fields.map(field => (
                      <div key={field.key} className="bg-slate-50 p-6 rounded-2xl border border-gray-100">
                        <p className="text-[10px] font-black uppercase text-gray-400 mb-2 flex items-center gap-2">
                          <i className={`fas ${field.icon} text-[8px]`}></i> {field.label}
                        </p>
                        <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">{(reflection as any)[field.key] || '-'}</p>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-10 shrink-0 grid grid-cols-2 gap-4">
              <button 
                onClick={() => setShowFinalConfirm(false)} 
                className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-all active:scale-95 text-sm"
              >
                Grįžti ir taisyti
              </button>
              <button 
                onClick={() => { setShowFinalConfirm(false); onComplete(); }} 
                className="bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-95 text-sm"
              >
                Patvirtinti ir baigti
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Auto-save Status */}
      <div className="flex items-center justify-between mb-8 px-4">
        <div className="flex items-center gap-3">
           <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${isAutoSaving ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
             {isAutoSaving ? 'Išsaugoma...' : `Auto-išsaugota: ${lastSaved ? lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' }) : 'Ką tik'}`}
           </span>
        </div>
        <div className="text-[10px] font-black uppercase tracking-widest text-indigo-400">
          Žingsnis {currentStep + 1} iš {steps.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard Content Card */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const val = (reflection as any)[field.key];
            const isEmpty = !val || val.trim().length === 0;
            const showError = isEmpty && touchedSteps.has(currentStep);
            const isFocused = focusedFieldKey === field.key;
            const isThisRecording = isRecording && recordingField === field.key;

            return (
              <div key={field.key} className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="font-black text-gray-800 flex items-center gap-3">
                    <i className={`fas ${field.icon} ${showError ? 'text-rose-500' : 'text-indigo-500'}`}></i> 
                    {field.label}
                    {showError && <span className="text-[9px] text-rose-500 uppercase tracking-widest font-black bg-rose-50 px-2 py-0.5 rounded-full">Privaloma</span>}
                  </label>

                  <div className="flex gap-2">
                    {field.hasEmotions && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                          className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-face-smile"></i> Nuotaikos
                        </button>
                        {showEmotionsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {emotionsList.map(emo => (
                                <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {emo} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}
                    <button 
                      onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                      disabled={isTranscribing}
                      className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                        isThisRecording 
                          ? 'bg-rose-500 text-white shadow-rose-200' 
                          : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
                      } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      title={isThisRecording ? "Sustabdyti" : "Įrašyti balsu"}
                    >
                      <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                      <span>{isThisRecording ? `Sustabdyti (${formatTime(recordingTime)})` : 'Įrašyti balsu'}</span>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea 
                    value={val} 
                    onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                    onFocus={() => handleFieldFocus(field.key)}
                    placeholder={field.placeholder} 
                    className={`w-full h-32 p-6 rounded-3xl border-2 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300 ${
                      showError ? 'border-rose-100 bg-rose-50/20 focus:border-rose-300' : 'border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50'
                    } ${isFocused ? 'ring-4 ring-indigo-500/5' : ''}`}
                  ></textarea>
                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 bg-white/70 backdrop-blur-sm rounded-3xl flex flex-col items-center justify-center gap-3 animate-fade-in">
                      <div className="w-6 h-6 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                      <span className="font-black text-indigo-600 text-[9px] tracking-[0.3em] uppercase">Perrašoma...</span>
                    </div>
                  )}
                </div>

                {/* AI Suggestions Section */}
                {isFocused && field.suggestionsKey && (
                  <div className="space-y-4 animate-fade-in">
                    {aiSuggestions[field.suggestionsKey]?.length > 0 ? (
                      <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4">
                        <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <i className="fas fa-magic"></i> Mentoriaus įžvalgos pagal mokinius
                        </div>
                        <div className="grid gap-2">
                          {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                            <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]">
                              <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                            </button>
                          ))}
                        </div>
                      </div>
                    ) : isLoadingSuggestions ? (
                      <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiame pagalbą...</span>
                      </div>
                    ) : null}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Footer Navigation */}
        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={handleBackWithConfirm} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>

          <button 
            onClick={next} 
            disabled={!isStepValid}
            className={`font-black px-12 py-5 rounded-2xl shadow-xl transition-all active:scale-95 flex items-center gap-3 ${
              isStepValid ? 'bg-indigo-600 text-white hover:shadow-indigo-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'
            }`}
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  aiInsights: any;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  aiInsights,
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [showFinalConfirm, setShowFinalConfirm] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [touchedSteps, setTouchedSteps] = useState<Set<number>>(new Set());
  const [focusedFieldKey, setFocusedFieldKey] = useState<string | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  // Moods / Emotions
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];

  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Recording Timer
  useEffect(() => {
    if (isRecording) {
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setRecordingTime(0);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isRecording]);

  // Auto-save effect
  useEffect(() => {
    setIsAutoSaving(true);
    const timeout = setTimeout(() => {
      const draft = { reflection, currentStep, timestamp: new Date().getTime() };
      localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
      setLastSaved(new Date());
      setIsAutoSaving(false);
    }, 1000);

    return () => clearTimeout(timeout);
  }, [reflection, currentStep]);

  // Tab close prevention
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      const hasContent = Object.values(reflection).some(v => (v as string).trim().length > 10);
      if (hasContent) {
        e.preventDefault();
        e.returnValue = 'Ar tikrai norite išeiti? Jūsų nebaigta refleksija yra išsaugota naršyklėje kaip juodraštis.';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection]);

  // Resume Draft Check
  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => (val as string).trim() === '');
        const draftHasContent = Object.values(parsed.reflection).some(val => (val as string).trim() !== '');
        if (isCurrentlyEmpty && draftHasContent) {
          setShowResumePrompt(true);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  // AI Suggestions Trigger
  useEffect(() => {
    const isTriggerStep = currentStep >= 0; 
    if (isTriggerStep && aiInsights) {
      const timer = setTimeout(() => {
        generateAIPrompts();
      }, 500);
      return () => clearTimeout(timer);
    }
  }, [currentStep, reflection.observations, reflection.strengths, reflection.improvements]);

  const generateAIPrompts = async () => {
    if (isLoadingSuggestions) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises,
        aiInsights
      );
      setAiSuggestions(suggestions);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsLoadingSuggestions(false); 
    }
  };

  const handleFieldFocus = (fieldKey: string) => {
    setFocusedFieldKey(fieldKey);
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => { 
        if (event.data.size > 0) audioChunksRef.current.push(event.data); 
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        setIsTranscribing(true);

        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          try {
            const base64Audio = (reader.result as string).split(',')[1];
            const transcription = await transcribeAudio(base64Audio, audioBlob.type);
            if (transcription && transcription.trim()) {
              setReflection(prevRef => ({ 
                ...prevRef, 
                [field]: prevRef[field as keyof ReflectionData] 
                  ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription.trim()}` 
                  : transcription.trim() 
              }));
            }
          } catch (err) {
            console.error("Transcription failed", err);
            alert("Nepavyko perrašyti garso. Bandykite dar kartą arba rašykite tekstą.");
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
    } catch (err) { 
      alert("Nepavyko pasiekti mikrofono. Patikrinkite naršyklės nustatymus."); 
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal && currentVal.trim().length > 0 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į mokinių duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu, kad mokiniai nurodė...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai mokinio akimis",
      fields: [
        { key: 'strengths', label: "Kuo mokiniai džiaugiasi?", placeholder: "Mokiniams patiko...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Ką vaikai norėtų keisti?", placeholder: "Mokiniai indikavo, kad...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Nebuvau pagalvojęs, kad mokiniai...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai, kuriuos vertina vaikai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į vaikų atvirumą",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Pamačius mokinių atsakymus, jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant mokinių poreikius...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais dėl savo mokinių?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Kitąmet mokiniai turėtų pajusti...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  const currentStepFields = steps[currentStep].fields;
  const isStepValid = currentStepFields.every(field => {
    const val = (reflection as any)[field.key];
    return val && val.trim().length > 0;
  });

  const next = () => {
    setTouchedSteps(prev => new Set(prev).add(currentStep));
    if (!isStepValid) return;

    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
      }, 200);
    } else {
      setShowFinalConfirm(true);
    }
  };

  const handleBackWithConfirm = () => {
    if (Object.values(reflection).some(v => (v as string).trim().length > 5)) {
      setShowExitConfirm(true);
    } else {
      onBack();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Resume Draft Prompt */}
      {showResumePrompt && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center animate-scale-in">
            <h3 className="text-2xl font-black mb-4 tracking-tight">Tęsti nebaigtą darbą?</h3>
            <p className="text-gray-500 mb-8 font-medium">Radome išsaugotą jūsų refleksijos juodraštį.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { 
                const d = JSON.parse(localStorage.getItem(DRAFT_KEY)!); 
                setReflection(d.reflection); 
                setCurrentStep(d.currentStep); 
                setShowResumePrompt(false); 
              }} className="bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Tęsti pildymą</button>
              <button onClick={() => { 
                localStorage.removeItem(DRAFT_KEY); 
                setShowResumePrompt(false); 
              }} className="bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl hover:bg-gray-200 transition-all">Pradėti iš naujo</button>
            </div>
          </div>
        </div>
      )}

      {/* Exit Confirmation */}
      {showExitConfirm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight text-rose-600">Išeiti iš refleksijos?</h3>
            <p className="text-gray-500 mb-8 font-medium">Jūsų progresas išsaugotas kaip juodraštis, bet grįšite į duomenų apžvalgą.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { setShowExitConfirm(false); onBack(); }} className="bg-gray-900 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Taip, išeiti</button>
              <button onClick={() => setShowExitConfirm(false)} className="bg-indigo-50 text-indigo-600 font-black py-4 rounded-2xl hover:bg-indigo-100 transition-all">Likti ir pildyti</button>
            </div>
          </div>
        </div>
      )}

      {/* Final Summary Confirmation Modal */}
      {showFinalConfirm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/70 backdrop-blur-lg">
          <div className="bg-white rounded-[3rem] p-8 md:p-12 max-w-2xl w-full shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="mb-8 shrink-0">
              <h3 className="text-3xl font-black text-gray-900 tracking-tight">Refleksijos santrauka</h3>
              <p className="text-gray-500 font-medium mt-2">Peržiūrėkite savo įžvalgas prieš generuojant galutinę ataskaitą.</p>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-8">
              {steps.map((step, idx) => (
                <div key={idx} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500 border-b border-indigo-50 pb-2">{step.title}</h4>
                  <div className="space-y-6">
                    {step.fields.map(field => (
                      <div key={field.key} className="bg-slate-50 p-6 rounded-2xl border border-gray-100">
                        <p className="text-[10px] font-black uppercase text-gray-400 mb-2 flex items-center gap-2">
                          <i className={`fas ${field.icon} text-[8px]`}></i> {field.label}
                        </p>
                        <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">{(reflection as any)[field.key] || '-'}</p>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-10 shrink-0 grid grid-cols-2 gap-4">
              <button 
                onClick={() => setShowFinalConfirm(false)} 
                className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-all active:scale-95 text-sm"
              >
                Grįžti ir taisyti
              </button>
              <button 
                onClick={() => { setShowFinalConfirm(false); onComplete(); }} 
                className="bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-95 text-sm"
              >
                Patvirtinti ir baigti
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Auto-save Status */}
      <div className="flex items-center justify-between mb-8 px-4">
        <div className="flex items-center gap-3">
           <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${isAutoSaving ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
             {isAutoSaving ? 'Išsaugoma...' : `Auto-išsaugota: ${lastSaved ? lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' }) : 'Ką tik'}`}
           </span>
        </div>
        <div className="text-[10px] font-black uppercase tracking-widest text-indigo-400">
          Žingsnis {currentStep + 1} iš {steps.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard Content Card */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const val = (reflection as any)[field.key];
            const isEmpty = !val || val.trim().length === 0;
            const showError = isEmpty && touchedSteps.has(currentStep);
            const isFocused = focusedFieldKey === field.key;
            const isThisRecording = isRecording && recordingField === field.key;

            return (
              <div key={field.key} className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="font-black text-gray-800 flex items-center gap-3">
                    <i className={`fas ${field.icon} ${showError ? 'text-rose-500' : 'text-indigo-500'}`}></i> 
                    {field.label}
                    {showError && <span className="text-[9px] text-rose-500 uppercase tracking-widest font-black bg-rose-50 px-2 py-0.5 rounded-full">Privaloma</span>}
                  </label>

                  <div className="flex gap-2">
                    {field.hasEmotions && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                          className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-face-smile"></i> Nuotaikos
                        </button>
                        {showEmotionsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {emotionsList.map(emo => (
                                <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {emo} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    {/* Specific button for observations as requested */}
                    {field.key === 'observations' && (
                      <button 
                        onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                        disabled={isTranscribing}
                        className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                          isThisRecording 
                            ? 'bg-rose-500 text-white shadow-rose-200' 
                            : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'
                        } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      >
                        <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                        <span>{isThisRecording ? `Stop (${formatTime(recordingTime)})` : 'Record Observation'}</span>
                      </button>
                    )}

                    <button 
                      onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                      disabled={isTranscribing}
                      className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                        isThisRecording 
                          ? 'bg-rose-500 text-white shadow-rose-200' 
                          : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
                      } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      title={isThisRecording ? "Sustabdyti" : "Įrašyti balsu"}
                    >
                      <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                      <span>{isThisRecording ? `Sustabdyti (${formatTime(recordingTime)})` : 'Įrašyti balsu'}</span>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea 
                    value={val} 
                    onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                    onFocus={() => handleFieldFocus(field.key)}
                    placeholder={field.placeholder} 
                    className={`w-full h-32 p-6 rounded-3xl border-2 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300 ${
                      showError ? 'border-rose-100 bg-rose-50/20 focus:border-rose-300' : 'border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50'
                    } ${isFocused ? 'ring-4 ring-indigo-500/5' : ''}`}
                  ></textarea>
                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 bg-white/70 backdrop-blur-sm rounded-3xl flex flex-col items-center justify-center gap-3 animate-fade-in">
                      <div className="w-6 h-6 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                      <span className="font-black text-indigo-600 text-[9px] tracking-[0.3em] uppercase">Perrašoma...</span>
                    </div>
                  )}
                </div>

                {/* AI Suggestions Section */}
                {isFocused && field.suggestionsKey && (
                  <div className="space-y-4 animate-fade-in">
                    {aiSuggestions[field.suggestionsKey]?.length > 0 ? (
                      <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4">
                        <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <i className="fas fa-magic"></i> Mentoriaus įžvalgos pagal mokinius
                        </div>
                        <div className="grid gap-2">
                          {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                            <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]">
                              <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                            </button>
                          ))}
                        </div>
                      </div>
                    ) : isLoadingSuggestions ? (
                      <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiame pagalbą...</span>
                      </div>
                    ) : null}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Footer Navigation */}
        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={handleBackWithConfirm} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>

          <button 
            onClick={next} 
            disabled={!isStepValid}
            className={`font-black px-12 py-5 rounded-2xl shadow-xl transition-all active:scale-95 flex items-center gap-3 ${
              isStepValid ? 'bg-indigo-600 text-white hover:shadow-indigo-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'
            }`}
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  aiInsights: any;
  onComplete: () => void;
  onBack: () => void;
}

const DRAFT_KEY = 'teacher_reflection_draft_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  aiInsights,
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showResumePrompt, setShowResumePrompt] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [showFinalConfirm, setShowFinalConfirm] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [touchedSteps, setTouchedSteps] = useState<Set<number>>(new Set());
  const [focusedFieldKey, setFocusedFieldKey] = useState<string | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  // Moods / Emotions
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];

  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Recording Timer
  useEffect(() => {
    if (isRecording) {
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setRecordingTime(0);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isRecording]);

  // Auto-save effect
  useEffect(() => {
    setIsAutoSaving(true);
    const timeout = setTimeout(() => {
      const draft = { reflection, currentStep, timestamp: new Date().getTime() };
      localStorage.setItem(DRAFT_KEY, JSON.stringify(draft));
      setLastSaved(new Date());
      setIsAutoSaving(false);
    }, 1000);

    return () => clearTimeout(timeout);
  }, [reflection, currentStep]);

  // Tab close prevention
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      const hasContent = Object.values(reflection).some(v => (v as string).trim().length > 10);
      if (hasContent) {
        e.preventDefault();
        e.returnValue = 'Ar tikrai norite išeiti? Jūsų nebaigta refleksija yra išsaugota naršyklėje kaip juodraštis.';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection]);

  // Resume Draft Check
  useEffect(() => {
    const savedDraft = localStorage.getItem(DRAFT_KEY);
    if (savedDraft) {
      try {
        const parsed = JSON.parse(savedDraft);
        const isCurrentlyEmpty = Object.values(reflection).every(val => (val as string).trim() === '');
        const draftHasContent = Object.values(parsed.reflection).some(val => (val as string).trim() !== '');
        if (isCurrentlyEmpty && draftHasContent) {
          setShowResumePrompt(true);
        }
      } catch (e) { console.error(e); }
    }
  }, []);

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į mokinių duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu, kad mokiniai nurodė...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai mokinio akimis",
      fields: [
        { key: 'strengths', label: "Kuo mokiniai džiaugiasi?", placeholder: "Mokiniams patiko...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Ką vaikai norėtų keisti?", placeholder: "Mokiniai indikavo, kad...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Nebuvau pagalvojęs, kad mokiniai...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai, kuriuos vertina vaikai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į vaikų atvirumą",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Pamačius mokinių atsakymus, jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant mokinių poreikius...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais dėl savo mokinių?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Kitąmet mokiniai turėtų pajusti...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  // AI Suggestions Trigger - Modified to be focus-centric and dynamic
  useEffect(() => {
    const currentStepFields = steps[currentStep].fields;
    const focusedField = currentStepFields.find(f => f.key === focusedFieldKey);

    // Only fetch if a field with a suggestionsKey is focused
    if (focusedField?.suggestionsKey && aiInsights) {
      const timer = setTimeout(() => {
        generateAIPrompts();
      }, 400); // Slight delay for smoother UI transitions
      return () => clearTimeout(timer);
    }
  }, [focusedFieldKey, currentStep, reflection.observations, reflection.strengths, reflection.improvements]);

  const generateAIPrompts = async () => {
    if (isLoadingSuggestions) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises,
        aiInsights
      );
      setAiSuggestions(suggestions);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsLoadingSuggestions(false); 
    }
  };

  const handleFieldFocus = (fieldKey: string) => {
    setFocusedFieldKey(fieldKey);
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => { 
        if (event.data.size > 0) audioChunksRef.current.push(event.data); 
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        setIsTranscribing(true);

        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          try {
            const base64Audio = (reader.result as string).split(',')[1];
            const transcription = await transcribeAudio(base64Audio, audioBlob.type);
            if (transcription && transcription.trim()) {
              setReflection(prevRef => ({ 
                ...prevRef, 
                [field]: prevRef[field as keyof ReflectionData] 
                  ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription.trim()}` 
                  : transcription.trim() 
              }));
            }
          } catch (err) {
            console.error("Transcription failed", err);
            alert("Nepavyko perrašyti garso. Bandykite dar kartą arba rašykite tekstą.");
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
    } catch (err) { 
      alert("Nepavyko pasiekti mikrofono. Patikrinkite naršyklės nustatymus."); 
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal && currentVal.trim().length > 0 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const currentStepFields = steps[currentStep].fields;
  const isStepValid = currentStepFields.every(field => {
    const val = (reflection as any)[field.key];
    return val && val.trim().length > 0;
  });

  const next = () => {
    setTouchedSteps(prev => new Set(prev).add(currentStep));
    if (!isStepValid) return;

    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
      }, 200);
    } else {
      setShowFinalConfirm(true);
    }
  };

  const handleBackWithConfirm = () => {
    if (Object.values(reflection).some(v => (v as string).trim().length > 5)) {
      setShowExitConfirm(true);
    } else {
      onBack();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Resume Draft Prompt */}
      {showResumePrompt && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center animate-scale-in">
            <h3 className="text-2xl font-black mb-4 tracking-tight">Tęsti nebaigtą darbą?</h3>
            <p className="text-gray-500 mb-8 font-medium">Radome išsaugotą jūsų refleksijos juodraštį.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { 
                const d = JSON.parse(localStorage.getItem(DRAFT_KEY)!); 
                setReflection(d.reflection); 
                setCurrentStep(d.currentStep); 
                setShowResumePrompt(false); 
              }} className="bg-indigo-600 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Tęsti pildymą</button>
              <button onClick={() => { 
                localStorage.removeItem(DRAFT_KEY); 
                setShowResumePrompt(false); 
              }} className="bg-gray-100 text-gray-500 font-bold py-4 rounded-2xl hover:bg-gray-200 transition-all">Pradėti iš naujo</button>
            </div>
          </div>
        </div>
      )}

      {/* Exit Confirmation */}
      {showExitConfirm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight text-rose-600">Išeiti iš refleksijos?</h3>
            <p className="text-gray-500 mb-8 font-medium">Jūsų progresas išsaugotas kaip juodraštis, bet grįšite į duomenų apžvalgą.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { setShowExitConfirm(false); onBack(); }} className="bg-gray-900 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Taip, išeiti</button>
              <button onClick={() => setShowExitConfirm(false)} className="bg-indigo-50 text-indigo-600 font-black py-4 rounded-2xl hover:bg-indigo-100 transition-all">Likti ir pildyti</button>
            </div>
          </div>
        </div>
      )}

      {/* Final Summary Confirmation Modal */}
      {showFinalConfirm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/70 backdrop-blur-lg">
          <div className="bg-white rounded-[3rem] p-8 md:p-12 max-w-2xl w-full shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="mb-8 shrink-0">
              <h3 className="text-3xl font-black text-gray-900 tracking-tight">Refleksijos santrauka</h3>
              <p className="text-gray-500 font-medium mt-2">Peržiūrėkite savo įžvalgas prieš generuojant galutinę ataskaitą.</p>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-8">
              {steps.map((step, idx) => (
                <div key={idx} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500 border-b border-indigo-50 pb-2">{step.title}</h4>
                  <div className="space-y-6">
                    {step.fields.map(field => (
                      <div key={field.key} className="bg-slate-50 p-6 rounded-2xl border border-gray-100">
                        <p className="text-[10px] font-black uppercase text-gray-400 mb-2 flex items-center gap-2">
                          <i className={`fas ${field.icon} text-[8px]`}></i> {field.label}
                        </p>
                        <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">{(reflection as any)[field.key] || '-'}</p>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-10 shrink-0 grid grid-cols-2 gap-4">
              <button 
                onClick={() => setShowFinalConfirm(false)} 
                className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-all active:scale-95 text-sm"
              >
                Grįžti ir taisyti
              </button>
              <button 
                onClick={() => { setShowFinalConfirm(false); onComplete(); }} 
                className="bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-95 text-sm"
              >
                Patvirtinti ir baigti
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Auto-save Status */}
      <div className="flex items-center justify-between mb-8 px-4">
        <div className="flex items-center gap-3">
           <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${isAutoSaving ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
             {isAutoSaving ? 'Išsaugoma...' : `Auto-išsaugota: ${lastSaved ? lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' }) : 'Ką tik'}`}
           </span>
        </div>
        <div className="text-[10px] font-black uppercase tracking-widest text-indigo-400">
          Žingsnis {currentStep + 1} iš {steps.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard Content Card */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const val = (reflection as any)[field.key];
            const isEmpty = !val || val.trim().length === 0;
            const showError = isEmpty && touchedSteps.has(currentStep);
            const isFocused = focusedFieldKey === field.key;
            const isThisRecording = isRecording && recordingField === field.key;

            return (
              <div key={field.key} className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="font-black text-gray-800 flex items-center gap-3">
                    <i className={`fas ${field.icon} ${showError ? 'text-rose-500' : 'text-indigo-500'}`}></i> 
                    {field.label}
                    {showError && <span className="text-[9px] text-rose-500 uppercase tracking-widest font-black bg-rose-50 px-2 py-0.5 rounded-full">Privaloma</span>}
                  </label>

                  <div className="flex gap-2">
                    {field.hasEmotions && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                          className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-face-smile"></i> Nuotaikos
                        </button>
                        {showEmotionsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {emotionsList.map(emo => (
                                <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {emo} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    {field.key === 'observations' && (
                      <button 
                        onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                        disabled={isTranscribing}
                        className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                          isThisRecording 
                            ? 'bg-rose-500 text-white shadow-rose-200' 
                            : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'
                        } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      >
                        <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                        <span>{isThisRecording ? `Stop (${formatTime(recordingTime)})` : 'Record Observation'}</span>
                      </button>
                    )}

                    <button 
                      onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                      disabled={isTranscribing}
                      className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                        isThisRecording 
                          ? 'bg-rose-500 text-white shadow-rose-200' 
                          : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
                      } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      title={isThisRecording ? "Sustabdyti" : "Įrašyti balsu"}
                    >
                      <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                      <span>{isThisRecording ? `Sustabdyti (${formatTime(recordingTime)})` : 'Įrašyti balsu'}</span>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea 
                    value={val} 
                    onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                    onFocus={() => handleFieldFocus(field.key)}
                    placeholder={field.placeholder} 
                    className={`w-full h-32 p-6 rounded-3xl border-2 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300 ${
                      showError ? 'border-rose-100 bg-rose-50/20 focus:border-rose-300' : 'border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50'
                    } ${isFocused ? 'ring-4 ring-indigo-500/5' : ''}`}
                  ></textarea>
                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 bg-white/70 backdrop-blur-sm rounded-3xl flex flex-col items-center justify-center gap-3 animate-fade-in">
                      <div className="w-6 h-6 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                      <span className="font-black text-indigo-600 text-[9px] tracking-[0.3em] uppercase">Perrašoma...</span>
                    </div>
                  )}
                </div>

                {/* AI Suggestions Section - Visible only when focused */}
                {isFocused && field.suggestionsKey && (
                  <div className="space-y-4 animate-fade-in">
                    {aiSuggestions[field.suggestionsKey]?.length > 0 ? (
                      <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4">
                        <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <i className="fas fa-magic"></i> Mentoriaus įžvalgos pagal mokinius
                        </div>
                        <div className="grid gap-2">
                          {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                            <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]">
                              <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                            </button>
                          ))}
                        </div>
                      </div>
                    ) : isLoadingSuggestions ? (
                      <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiame pagalbą...</span>
                      </div>
                    ) : null}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Footer Navigation */}
        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={handleBackWithConfirm} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>

          <button 
            onClick={next} 
            disabled={!isStepValid}
            className={`font-black px-12 py-5 rounded-2xl shadow-xl transition-all active:scale-95 flex items-center gap-3 ${
              isStepValid ? 'bg-indigo-600 text-white hover:shadow-indigo-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'
            }`}
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData, CATEGORY_MAP, REVERSE_QUESTIONS } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const SESSION_DRAFT_KEY = 'teacher_reflection_session_v1';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showShareToast, setShowShareToast] = useState(false);
  const [history, setHistory] = useState<any[]>([]);
  const [hasDraft, setHasDraft] = useState(false);
  const [initialWizardStep, setInitialWizardStep] = useState(0);

  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '', strengths: '', improvements: '', surprises: '',
    bestPractices: '', heartFeelings: '', headThoughts: '',
    actionStop: '', actionStart: '', actionContinue: '', nextSteps: ''
  });

  // Load history and check for draft on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('teacher_reflection_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const draft = localStorage.getItem(SESSION_DRAFT_KEY);
    if (draft) {
      setHasDraft(true);
    }

    const hash = window.location.hash;
    if (hash.startsWith('#data=')) {
      try {
        const base64 = hash.replace('#data=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(base64))));
        setReflection(decodedData);
        setStep(AppStep.REPORT);
        window.history.replaceState(null, '', window.location.pathname);
      } catch (e) { console.error(e); }
    }
  }, []);

  // Auto-save session state
  useEffect(() => {
    if (step !== AppStep.UPLOAD && step !== AppStep.REPORT) {
      const stateToSave = {
        step,
        summaries,
        openFeedback,
        aiInsights,
        reflection,
        timestamp: Date.now()
      };
      localStorage.setItem(SESSION_DRAFT_KEY, JSON.stringify(stateToSave));
    }
  }, [step, summaries, openFeedback, aiInsights, reflection]);

  const handleResumeSession = () => {
    const draftJson = localStorage.getItem(SESSION_DRAFT_KEY);
    if (draftJson) {
      try {
        const draft = JSON.parse(draftJson);
        setSummaries(draft.summaries || []);
        setOpenFeedback(draft.openFeedback || []);
        setAiInsights(draft.aiInsights || null);
        setReflection(draft.reflection);
        setStep(draft.step);
        // If they were in reflection, the wizard will handle its own currentStep from localStorage or props
        setHasDraft(false);
      } catch (e) {
        console.error("Failed to resume session", e);
        localStorage.removeItem(SESSION_DRAFT_KEY);
      }
    }
  };

  const handleClearDraft = () => {
    localStorage.removeItem(SESSION_DRAFT_KEY);
    setHasDraft(false);
  };

  const saveToHistory = () => {
    const newEntry = {
      id: Date.now(),
      date: new Date().toISOString(),
      data: reflection,
      summary: summaries.length > 0 ? summaries[0].question.substring(0, 30) + '...' : 'Mokslo metų vertinimas'
    };
    const updated = [newEntry, ...history].slice(0, 20);
    setHistory(updated);
    localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
    // Clear draft once complete
    localStorage.removeItem(SESSION_DRAFT_KEY);
  };

  const handleDataParsed = (rows: SurveyRow[]) => {
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const handleNewAnalysis = () => {
    if (step !== AppStep.UPLOAD) {
      if (confirm('Ar tikrai norite pradėti naują analizę? Visi nebaigti refleksijos pokyčiai bus prarasti.')) {
        localStorage.removeItem(SESSION_DRAFT_KEY);
        window.location.reload();
      }
    }
  };

  const cleanHeader = (header: string): string => {
    const match = header.match(/\[(.*?)\]/);
    if (match && match[1]) return match[1].trim();
    return header.replace(/^Prašome atsakyti į klausimus nuoširdžiai, taip, kaip manote ir jaučiatės\.\s*/i, '').trim();
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;
    const rawHeaders = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    rawHeaders.forEach(rawHeader => {
      if (rawHeader.toLowerCase().includes('laiko žymė')) return;
      const cleanedHeader = cleanHeader(rawHeader);

      let sum = 0, validCount = 0, isNumeric = false;
      const counts: { [val: string]: number } = {};

      rows.forEach(row => {
        const val = row[rawHeader]?.trim();
        if (val) {
          counts[val] = (counts[val] || 0) + 1;
          const normalizedVal = val.endsWith('.') ? val.slice(0, -1) : val;
          if (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]) { 
            sum += (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]); 
            validCount++; 
            isNumeric = true; 
          }
        }
      });

      if (isNumeric && validCount > 0) {
        const categoryKey = Object.keys(CATEGORY_MAP).find(k => cleanedHeader.toLowerCase().includes(k.toLowerCase()) || rawHeader.toLowerCase().includes(k.toLowerCase()));
        const category = categoryKey ? CATEGORY_MAP[categoryKey] : 'Kita';
        newSummaries.push({
          question: cleanedHeader,
          counts,
          total: rows.length,
          averageScore: sum / validCount,
          category,
          isReverse: REVERSE_QUESTIONS.some(q => cleanedHeader.toLowerCase().includes(q.toLowerCase()))
        });
      } else {
        rows.forEach(row => { 
          const val = row[rawHeader]?.trim();
          if (val && val.length > 5 && !LIKERT_VALUES[val] && !LIKERT_VALUES[val.slice(0, -1)]) feedback.push(val); 
        });
      }
    });
    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, aiInsights, openFeedback]);

  const handleShare = () => {
    const dataString = JSON.stringify(reflection);
    const base64 = btoa(unescape(encodeURIComponent(dataString)));
    const url = `${window.location.origin}${window.location.pathname}#data=${base64}`;
    navigator.clipboard.writeText(url).then(() => {
      setShowShareToast(true);
      setTimeout(() => setShowShareToast(false), 3000);
    });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 selection:bg-indigo-100">
      {showShareToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[200] bg-gray-900 text-white px-8 py-4 rounded-2xl shadow-2xl animate-slide-up flex items-center gap-4 border border-white/10">
          <i className="fas fa-check-circle text-emerald-400"></i> Nuoroda nukopijuota sėkmingai!
        </div>
      )}

      <header className="bg-white border-b border-gray-100 py-6 mb-8 print:hidden">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><i className="fas fa-graduation-cap"></i></div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">Refleksijos pagalbininkas</h1>
          </div>
          {step !== AppStep.UPLOAD && (
            <button onClick={handleNewAnalysis} className="text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-indigo-600 transition-colors">
              Nauja analizė
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-6">
        {step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-center space-y-4">
              <h2 className="text-5xl font-black text-gray-900 tracking-tight">Mokslo metų analizė</h2>
              <p className="text-gray-500 max-w-lg mx-auto text-lg font-medium">Įkelk apklausos rezultatus ir leisk DI mentorystei nukreipti tavo augimą.</p>
            </div>

            {hasDraft && (
              <div className="bg-indigo-600 rounded-[2.5rem] p-8 text-white shadow-2xl animate-scale-in flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="flex items-center gap-6">
                  <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md">
                    <i className="fas fa-rotate-left text-xl"></i>
                  </div>
                  <div>
                    <h3 className="text-xl font-black">Tęsti nebaigtą sesiją?</h3>
                    <p className="text-indigo-100/80 text-sm font-medium">Radome jūsų paskutinę nebaigtą refleksiją.</p>
                  </div>
                </div>
                <div className="flex gap-3 w-full md:w-auto">
                  <button onClick={handleClearDraft} className="flex-1 px-6 py-4 rounded-2xl bg-white/10 hover:bg-white/20 font-black text-xs uppercase tracking-widest transition-all">Ištrinti</button>
                  <button onClick={handleResumeSession} className="flex-1 px-10 py-4 rounded-2xl bg-white text-indigo-600 font-black text-xs uppercase tracking-widest shadow-xl transition-all active:scale-95">Tęsti pildymą</button>
                </div>
              </div>
            )}

            <CSVUpload onParsed={handleDataParsed} />

            {history.length > 0 && (
              <div className="space-y-4">
                <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 px-2">Ankstesnės refleksijos</h3>
                <div className="grid md:grid-cols-2 gap-4">
                  {history.map(item => (
                    <button key={item.id} onClick={() => { setReflection(item.data); setStep(AppStep.REPORT); }} className="bg-white p-6 rounded-[2rem] border border-gray-100 text-left flex items-center justify-between group hover:shadow-xl hover:border-indigo-100 transition-all">
                      <div><p className="font-black text-gray-800 text-lg">{new Date(item.date).toLocaleDateString('lt-LT')}</p><p className="text-xs text-gray-400 mt-1 uppercase font-bold tracking-wider">{item.summary}</p></div>
                      <i className="fas fa-chevron-right text-gray-200 group-hover:text-indigo-500 transition-all"></i>
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {step === AppStep.ANALYSIS && <SummaryDashboard summaries={summaries} feedback={openFeedback} aiInsights={aiInsights} isAnalyzing={isAnalyzing} onNext={() => setStep(AppStep.REFLECTION)} />}

        {step === AppStep.REFLECTION && <ReflectionWizard reflection={reflection} setReflection={setReflection} aiInsights={aiInsights} onComplete={() => { saveToHistory(); setStep(AppStep.REPORT); }} onBack={() => setStep(AppStep.ANALYSIS)} />}

        {step === AppStep.REPORT && (
          <div className="max-w-4xl mx-auto bg-white p-10 md:p-16 rounded-[4rem] shadow-2xl animate-scale-in print:shadow-none print:p-0">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16 border-b border-gray-100 pb-12 print:hidden gap-6">
              <div>
                <h2 className="text-4xl font-black text-gray-900">Refleksijos rezultatas</h2>
                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs mt-2">{new Date().toLocaleDateString('lt-LT')}</p>
              </div>
              <div className="flex gap-3 w-full md:w-auto">
                <button onClick={handleShare} className="flex-1 px-6 py-4 rounded-2xl border-2 border-indigo-50 text-indigo-600 font-black text-sm flex items-center justify-center gap-2 transition-all active:scale-95"><i className="fas fa-share"></i> Dalintis</button>
                <button onClick={() => window.print()} className="flex-1 px-6 py-4 rounded-2xl bg-indigo-600 text-white font-black text-sm flex items-center justify-center gap-2 shadow-xl shadow-indigo-100 transition-all active:scale-95"><i className="fas fa-file-pdf"></i> Atsisiųsti PDF</button>
              </div>
            </div>

            <div className="space-y-16">
              <section className="grid md:grid-cols-2 gap-12">
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">Pastebėjimai</h4><p className="text-gray-700 italic text-xl">"{reflection.observations || '-'}"</p></div>
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-500">Stiprybės</h4><p className="text-gray-700 text-xl font-medium">{reflection.strengths || '-'}</p></div>
              </section>

              <section className="bg-slate-900 text-white p-12 rounded-[3rem] space-y-10 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-500/10 blur-[100px] rounded-full"></div>
                <h3 className="font-black text-2xl flex items-center gap-4 relative z-10"><i className="fas fa-rocket text-indigo-400"></i> Veiksmų planas kitais metais</h3>
                <div className="grid md:grid-cols-3 gap-10 relative z-10 text-indigo-50/80">
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-rose-400 border-b border-rose-400/20 pb-2">Nustosiu</h5><p className="text-sm">{reflection.actionStop || '-'}</p></div>
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-emerald-400 border-b border-emerald-400/20 pb-2">Pradėsiu</h5><p className="text-sm">{reflection.actionStart || '-'}</p></div>
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-indigo-400 border-b border-indigo-400/20 pb-2">Tęsiu</h5><p className="text-sm">{reflection.actionContinue || '-'}</p></div>
                </div>
                <div className="pt-8 border-t border-white/5 relative z-10 text-indigo-50/80">
                  <h5 className="text-[10px] font-black uppercase text-indigo-300 mb-2">Kaip žinosiu, kad vaikams sekasi geriau?</h5>
                  <p className="text-sm">{reflection.nextSteps || '-'}</p>
                </div>
              </section>

              <section className="grid md:grid-cols-2 gap-12">
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase text-gray-400">Geroji patirtis</h4><p className="text-gray-700">{reflection.bestPractices || '-'}</p></div>
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase text-gray-400">Refleksijos emocija</h4><p className="text-gray-700">{reflection.heartFeelings} • {reflection.headThoughts}</p></div>
              </section>

              <div className="text-center pt-10 border-t border-gray-100"><p className="text-[9px] text-gray-300 font-black uppercase tracking-[0.4em]">Refleksijos pagalbininkas • Profesinis augimas mokinio sėkmei</p></div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  aiInsights: any;
  onComplete: () => void;
  onBack: () => void;
}

const WIZARD_STEP_KEY = 'teacher_reflection_wizard_step_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  aiInsights,
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [showFinalConfirm, setShowFinalConfirm] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [touchedSteps, setTouchedSteps] = useState<Set<number>>(new Set());
  const [focusedFieldKey, setFocusedFieldKey] = useState<string | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  // Moods / Emotions
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];

  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Restore wizard step on mount
  useEffect(() => {
    const savedStep = localStorage.getItem(WIZARD_STEP_KEY);
    if (savedStep) {
      setCurrentStep(parseInt(savedStep, 10));
    }
  }, []);

  // Persist wizard step whenever it changes
  useEffect(() => {
    localStorage.setItem(WIZARD_STEP_KEY, currentStep.toString());
  }, [currentStep]);

  // Recording Timer
  useEffect(() => {
    if (isRecording) {
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setRecordingTime(0);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isRecording]);

  // Visual auto-save feedback
  useEffect(() => {
    setIsAutoSaving(true);
    const timeout = setTimeout(() => {
      setLastSaved(new Date());
      setIsAutoSaving(false);
    }, 1000);
    return () => clearTimeout(timeout);
  }, [reflection, currentStep]);

  // Tab close prevention
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      const hasContent = Object.values(reflection).some(v => (v as string).trim().length > 10);
      if (hasContent) {
        e.preventDefault();
        e.returnValue = 'Ar tikrai norite išeiti? Jūsų progresas yra išsaugotas.';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection]);

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į mokinių duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu, kad mokiniai nurodė...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai mokinio akimis",
      fields: [
        { key: 'strengths', label: "Kuo mokiniai džiaugiasi?", placeholder: "Mokiniams patiko...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Ką vaikai norėtų keisti?", placeholder: "Mokiniai indikavo, kad...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Nebuvau pagalvojęs, kad mokiniai...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai, kuriuos vertina vaikai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į vaikų atvirumą",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Pamačius mokinių atsakymus, jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant mokinių poreikius...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais dėl savo mokinių?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Kitąmet mokiniai turėtų pajusti...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  // AI Suggestions Trigger
  useEffect(() => {
    const currentStepFields = steps[currentStep].fields;
    const focusedField = currentStepFields.find(f => f.key === focusedFieldKey);

    if (focusedField?.suggestionsKey && aiInsights) {
      const timer = setTimeout(() => {
        generateAIPrompts();
      }, 400);
      return () => clearTimeout(timer);
    }
  }, [focusedFieldKey, currentStep, reflection.observations, reflection.strengths, reflection.improvements]);

  const generateAIPrompts = async () => {
    if (isLoadingSuggestions) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises,
        aiInsights
      );
      setAiSuggestions(suggestions);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsLoadingSuggestions(false); 
    }
  };

  const handleFieldFocus = (fieldKey: string) => {
    setFocusedFieldKey(fieldKey);
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => { 
        if (event.data.size > 0) audioChunksRef.current.push(event.data); 
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        setIsTranscribing(true);

        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          try {
            const base64Audio = (reader.result as string).split(',')[1];
            const transcription = await transcribeAudio(base64Audio, audioBlob.type);
            if (transcription && transcription.trim()) {
              setReflection(prevRef => ({ 
                ...prevRef, 
                [field]: prevRef[field as keyof ReflectionData] 
                  ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription.trim()}` 
                  : transcription.trim() 
              }));
            }
          } catch (err) {
            console.error("Transcription failed", err);
            alert("Nepavyko perrašyti garso. Bandykite dar kartą.");
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
    } catch (err) { 
      alert("Nepavyko pasiekti mikrofono."); 
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal && currentVal.trim().length > 0 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const currentStepFields = steps[currentStep].fields;
  const isStepValid = currentStepFields.every(field => {
    const val = (reflection as any)[field.key];
    return val && val.trim().length > 0;
  });

  const next = () => {
    setTouchedSteps(prev => new Set(prev).add(currentStep));
    if (!isStepValid) return;

    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
      }, 200);
    } else {
      setShowFinalConfirm(true);
    }
  };

  const handleBackWithConfirm = () => {
    if (Object.values(reflection).some(v => (v as string).trim().length > 5)) {
      setShowExitConfirm(true);
    } else {
      onBack();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleWizardComplete = () => {
    localStorage.removeItem(WIZARD_STEP_KEY);
    onComplete();
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Exit Confirmation */}
      {showExitConfirm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight text-rose-600">Išeiti iš refleksijos?</h3>
            <p className="text-gray-500 mb-8 font-medium">Jūsų progresas yra išsaugotas, bet grįšite į duomenų apžvalgą.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { setShowExitConfirm(false); onBack(); }} className="bg-gray-900 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Taip, išeiti</button>
              <button onClick={() => setShowExitConfirm(false)} className="bg-indigo-50 text-indigo-600 font-black py-4 rounded-2xl hover:bg-indigo-100 transition-all">Likti ir pildyti</button>
            </div>
          </div>
        </div>
      )}

      {/* Final Summary Confirmation Modal */}
      {showFinalConfirm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/70 backdrop-blur-lg">
          <div className="bg-white rounded-[3rem] p-8 md:p-12 max-w-2xl w-full shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="mb-8 shrink-0">
              <h3 className="text-3xl font-black text-gray-900 tracking-tight">Refleksijos santrauka</h3>
              <p className="text-gray-500 font-medium mt-2">Peržiūrėkite savo įžvalgas prieš generuojant galutinę ataskaitą.</p>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-8">
              {steps.map((step, idx) => (
                <div key={idx} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500 border-b border-indigo-50 pb-2">{step.title}</h4>
                  <div className="space-y-6">
                    {step.fields.map(field => (
                      <div key={field.key} className="bg-slate-50 p-6 rounded-2xl border border-gray-100">
                        <p className="text-[10px] font-black uppercase text-gray-400 mb-2 flex items-center gap-2">
                          <i className={`fas ${field.icon} text-[8px]`}></i> {field.label}
                        </p>
                        <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">{(reflection as any)[field.key] || '-'}</p>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-10 shrink-0 grid grid-cols-2 gap-4">
              <button 
                onClick={() => setShowFinalConfirm(false)} 
                className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-all active:scale-95 text-sm"
              >
                Grįžti ir taisyti
              </button>
              <button 
                onClick={handleWizardComplete} 
                className="bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-95 text-sm"
              >
                Patvirtinti ir baigti
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Auto-save Status */}
      <div className="flex items-center justify-between mb-8 px-4">
        <div className="flex items-center gap-3">
           <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${isAutoSaving ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
             {isAutoSaving ? 'Išsaugoma...' : `Auto-išsaugota: ${lastSaved ? lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' }) : 'Ką tik'}`}
           </span>
        </div>
        <div className="text-[10px] font-black uppercase tracking-widest text-indigo-400">
          Žingsnis {currentStep + 1} iš {steps.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard Content Card */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const val = (reflection as any)[field.key];
            const isEmpty = !val || val.trim().length === 0;
            const showError = isEmpty && touchedSteps.has(currentStep);
            const isFocused = focusedFieldKey === field.key;
            const isThisRecording = isRecording && recordingField === field.key;

            return (
              <div key={field.key} className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="font-black text-gray-800 flex items-center gap-3">
                    <i className={`fas ${field.icon} ${showError ? 'text-rose-500' : 'text-indigo-500'}`}></i> 
                    {field.label}
                    {showError && <span className="text-[9px] text-rose-500 uppercase tracking-widest font-black bg-rose-50 px-2 py-0.5 rounded-full">Privaloma</span>}
                  </label>

                  <div className="flex gap-2">
                    {field.hasEmotions && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                          className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-face-smile"></i> Nuotaikos
                        </button>
                        {showEmotionsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {emotionsList.map(emo => (
                                <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {emo} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    {field.key === 'observations' && (
                      <button 
                        onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                        disabled={isTranscribing}
                        className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                          isThisRecording 
                            ? 'bg-rose-500 text-white shadow-rose-200' 
                            : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'
                        } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      >
                        <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                        <span>{isThisRecording ? `Stop (${formatTime(recordingTime)})` : 'Record Observation'}</span>
                      </button>
                    )}

                    <button 
                      onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                      disabled={isTranscribing}
                      className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                        isThisRecording 
                          ? 'bg-rose-500 text-white shadow-rose-200' 
                          : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
                      } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      title={isThisRecording ? "Sustabdyti" : "Įrašyti balsu"}
                    >
                      <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                      <span>{isThisRecording ? `Sustabdyti (${formatTime(recordingTime)})` : 'Įrašyti balsu'}</span>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea 
                    value={val} 
                    onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                    onFocus={() => handleFieldFocus(field.key)}
                    placeholder={field.placeholder} 
                    className={`w-full h-32 p-6 rounded-3xl border-2 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300 ${
                      showError ? 'border-rose-100 bg-rose-50/20 focus:border-rose-300' : 'border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50'
                    } ${isFocused ? 'ring-4 ring-indigo-500/5' : ''}`}
                  ></textarea>
                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 bg-white/70 backdrop-blur-sm rounded-3xl flex flex-col items-center justify-center gap-3 animate-fade-in">
                      <div className="w-6 h-6 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                      <span className="font-black text-indigo-600 text-[9px] tracking-[0.3em] uppercase">Perrašoma...</span>
                    </div>
                  )}
                </div>

                {/* AI Suggestions Section - Visible only when focused */}
                {isFocused && field.suggestionsKey && (
                  <div className="space-y-4 animate-fade-in">
                    {aiSuggestions[field.suggestionsKey]?.length > 0 ? (
                      <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4">
                        <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <i className="fas fa-magic"></i> Mentoriaus įžvalgos pagal mokinius
                        </div>
                        <div className="grid gap-2">
                          {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                            <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]">
                              <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                            </button>
                          ))}
                        </div>
                      </div>
                    ) : isLoadingSuggestions ? (
                      <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiame pagalbą...</span>
                      </div>
                    ) : null}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Footer Navigation */}
        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={handleBackWithConfirm} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>

          <button 
            onClick={next} 
            disabled={!isStepValid}
            className={`font-black px-12 py-5 rounded-2xl shadow-xl transition-all active:scale-95 flex items-center gap-3 ${
              isStepValid ? 'bg-indigo-600 text-white hover:shadow-indigo-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'
            }`}
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  aiInsights: any;
  onComplete: () => void;
  onBack: () => void;
}

const WIZARD_STEP_KEY = 'teacher_reflection_wizard_step_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  aiInsights,
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [showFinalConfirm, setShowFinalConfirm] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [touchedSteps, setTouchedSteps] = useState<Set<number>>(new Set());
  const [focusedFieldKey, setFocusedFieldKey] = useState<string | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  // Menus / Options
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const [showObservationsMenu, setShowObservationsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];
  const observationsList = ['Klasės dinamika', 'Aktyvumas pamokoje', 'Motyvacija', 'Dalyko supratimas', 'Socialiniai įgūdžiai'];

  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Restore wizard step on mount
  useEffect(() => {
    const savedStep = localStorage.getItem(WIZARD_STEP_KEY);
    if (savedStep) {
      setCurrentStep(parseInt(savedStep, 10));
    }
  }, []);

  // Persist wizard step whenever it changes
  useEffect(() => {
    localStorage.setItem(WIZARD_STEP_KEY, currentStep.toString());
  }, [currentStep]);

  // Recording Timer
  useEffect(() => {
    if (isRecording) {
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setRecordingTime(0);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isRecording]);

  // Visual auto-save feedback
  useEffect(() => {
    setIsAutoSaving(true);
    const timeout = setTimeout(() => {
      setLastSaved(new Date());
      setIsAutoSaving(false);
    }, 1000);
    return () => clearTimeout(timeout);
  }, [reflection, currentStep]);

  // Tab close prevention
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      const hasContent = Object.values(reflection).some(v => (v as string).trim().length > 10);
      if (hasContent) {
        e.preventDefault();
        e.returnValue = 'Ar tikrai norite išeiti? Jūsų progresas yra išsaugotas.';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection]);

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į mokinių duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu, kad mokiniai nurodė...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai mokinio akimis",
      fields: [
        { key: 'strengths', label: "Kuo mokiniai džiaugiasi?", placeholder: "Mokiniams patiko...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Ką vaikai norėtų keisti?", placeholder: "Mokiniai indikavo, kad...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Nebuvau pagalvojęs, kad mokiniai...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai, kuriuos vertina vaikai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į vaikų atvirumą",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Pamačius mokinių atsakymus, jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant mokinių poreikius...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais dėl savo mokinių?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Kitąmet mokiniai turėtų pajusti...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  // AI Suggestions Trigger
  useEffect(() => {
    const currentStepFields = steps[currentStep].fields;
    const focusedField = currentStepFields.find(f => f.key === focusedFieldKey);

    if (focusedField?.suggestionsKey && aiInsights) {
      const timer = setTimeout(() => {
        generateAIPrompts();
      }, 400);
      return () => clearTimeout(timer);
    }
  }, [focusedFieldKey, currentStep, reflection.observations, reflection.strengths, reflection.improvements]);

  const generateAIPrompts = async () => {
    if (isLoadingSuggestions) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises,
        aiInsights
      );
      setAiSuggestions(suggestions);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsLoadingSuggestions(false); 
    }
  };

  const handleFieldFocus = (fieldKey: string) => {
    setFocusedFieldKey(fieldKey);
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => { 
        if (event.data.size > 0) audioChunksRef.current.push(event.data); 
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        setIsTranscribing(true);

        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          try {
            const base64Audio = (reader.result as string).split(',')[1];
            const transcription = await transcribeAudio(base64Audio, audioBlob.type);
            if (transcription && transcription.trim()) {
              setReflection(prevRef => ({ 
                ...prevRef, 
                [field]: prevRef[field as keyof ReflectionData] 
                  ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription.trim()}` 
                  : transcription.trim() 
              }));
            }
          } catch (err) {
            console.error("Transcription failed", err);
            alert("Nepavyko perrašyti garso. Bandykite dar kartą.");
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
    } catch (err) { 
      alert("Nepavyko pasiekti mikrofono."); 
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal && currentVal.trim().length > 0 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const currentStepFields = steps[currentStep].fields;
  const isStepValid = currentStepFields.every(field => {
    const val = (reflection as any)[field.key];
    return val && val.trim().length > 0;
  });

  const next = () => {
    setTouchedSteps(prev => new Set(prev).add(currentStep));
    if (!isStepValid) return;

    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
      }, 200);
    } else {
      setShowFinalConfirm(true);
    }
  };

  const handleBackWithConfirm = () => {
    if (Object.values(reflection).some(v => (v as string).trim().length > 5)) {
      setShowExitConfirm(true);
    } else {
      onBack();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleWizardComplete = () => {
    localStorage.removeItem(WIZARD_STEP_KEY);
    onComplete();
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Exit Confirmation */}
      {showExitConfirm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight text-rose-600">Išeiti iš refleksijos?</h3>
            <p className="text-gray-500 mb-8 font-medium">Jūsų progresas yra išsaugotas, bet grįšite į duomenų apžvalgą.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { setShowExitConfirm(false); onBack(); }} className="bg-gray-900 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Taip, išeiti</button>
              <button onClick={() => setShowExitConfirm(false)} className="bg-indigo-50 text-indigo-600 font-black py-4 rounded-2xl hover:bg-indigo-100 transition-all">Likti ir pildyti</button>
            </div>
          </div>
        </div>
      )}

      {/* Final Summary Confirmation Modal */}
      {showFinalConfirm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/70 backdrop-blur-lg">
          <div className="bg-white rounded-[3rem] p-8 md:p-12 max-w-2xl w-full shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="mb-8 shrink-0">
              <h3 className="text-3xl font-black text-gray-900 tracking-tight">Refleksijos santrauka</h3>
              <p className="text-gray-500 font-medium mt-2">Peržiūrėkite savo įžvalgas prieš generuojant galutinę ataskaitą.</p>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-8">
              {steps.map((step, idx) => (
                <div key={idx} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500 border-b border-indigo-50 pb-2">{step.title}</h4>
                  <div className="space-y-6">
                    {step.fields.map(field => (
                      <div key={field.key} className="bg-slate-50 p-6 rounded-2xl border border-gray-100">
                        <p className="text-[10px] font-black uppercase text-gray-400 mb-2 flex items-center gap-2">
                          <i className={`fas ${field.icon} text-[8px]`}></i> {field.label}
                        </p>
                        <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">{(reflection as any)[field.key] || '-'}</p>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-10 shrink-0 grid grid-cols-2 gap-4">
              <button 
                onClick={() => setShowFinalConfirm(false)} 
                className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-all active:scale-95 text-sm"
              >
                Grįžti ir taisyti
              </button>
              <button 
                onClick={handleWizardComplete} 
                className="bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-95 text-sm"
              >
                Patvirtinti ir baigti
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Auto-save Status */}
      <div className="flex items-center justify-between mb-8 px-4">
        <div className="flex items-center gap-3">
           <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${isAutoSaving ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
             {isAutoSaving ? 'Išsaugoma...' : `Auto-išsaugota: ${lastSaved ? lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' }) : 'Ką tik'}`}
           </span>
        </div>
        <div className="text-[10px] font-black uppercase tracking-widest text-indigo-400">
          Žingsnis {currentStep + 1} iš {steps.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard Content Card */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const val = (reflection as any)[field.key];
            const isEmpty = !val || val.trim().length === 0;
            const showError = isEmpty && touchedSteps.has(currentStep);
            const isFocused = focusedFieldKey === field.key;
            const isThisRecording = isRecording && recordingField === field.key;

            return (
              <div key={field.key} className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="font-black text-gray-800 flex items-center gap-3">
                    <i className={`fas ${field.icon} ${showError ? 'text-rose-500' : 'text-indigo-500'}`}></i> 
                    {field.label}
                    {showError && <span className="text-[9px] text-rose-500 uppercase tracking-widest font-black bg-rose-50 px-2 py-0.5 rounded-full">Privaloma</span>}
                  </label>

                  <div className="flex gap-2">
                    {field.hasEmotions && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                          className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-face-smile"></i> Nuotaikos
                        </button>
                        {showEmotionsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {emotionsList.map(emo => (
                                <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {emo} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    {field.key === 'observations' && (
                      <div className="flex gap-2">
                        <div className="relative">
                          <button 
                            onClick={() => setShowObservationsMenu(!showObservationsMenu)} 
                            className="h-10 px-4 rounded-xl bg-slate-100 text-slate-600 flex items-center justify-center gap-2 hover:bg-slate-200 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                          >
                            <i className="fas fa-list-check"></i> Komentuoti
                          </button>
                          {showObservationsMenu && (
                            <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                              <div className="grid gap-1">
                                {observationsList.map(obs => (
                                  <button key={obs} onClick={() => { insertSuggestion('observations', obs); setShowObservationsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                    {obs} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                  </button>
                                ))}
                              </div>
                            </div>
                          )}
                        </div>

                        <button 
                          onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                          disabled={isTranscribing}
                          className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                            isThisRecording 
                              ? 'bg-rose-500 text-white shadow-rose-200' 
                              : 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100'
                          } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                        >
                          <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                          <span>{isThisRecording ? `Stop (${formatTime(recordingTime)})` : 'Record Observation'}</span>
                        </button>
                      </div>
                    )}

                    <button 
                      onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                      disabled={isTranscribing}
                      className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                        isThisRecording 
                          ? 'bg-rose-500 text-white shadow-rose-200' 
                          : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
                      } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      title={isThisRecording ? "Sustabdyti" : "Įrašyti balsu"}
                    >
                      <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                      <span>{isThisRecording ? `Sustabdyti (${formatTime(recordingTime)})` : 'Įrašyti balsu'}</span>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea 
                    value={val} 
                    onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                    onFocus={() => handleFieldFocus(field.key)}
                    placeholder={field.placeholder} 
                    className={`w-full h-32 p-6 rounded-3xl border-2 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300 ${
                      showError ? 'border-rose-100 bg-rose-50/20 focus:border-rose-300' : 'border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50'
                    } ${isFocused ? 'ring-4 ring-indigo-500/5' : ''}`}
                  ></textarea>
                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 bg-white/70 backdrop-blur-sm rounded-3xl flex flex-col items-center justify-center gap-3 animate-fade-in">
                      <div className="w-6 h-6 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                      <span className="font-black text-indigo-600 text-[9px] tracking-[0.3em] uppercase">Perrašoma...</span>
                    </div>
                  )}
                </div>

                {/* AI Suggestions Section - Visible only when focused */}
                {isFocused && field.suggestionsKey && (
                  <div className="space-y-4 animate-fade-in">
                    {aiSuggestions[field.suggestionsKey]?.length > 0 ? (
                      <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4">
                        <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <i className="fas fa-magic"></i> Mentoriaus įžvalgos pagal mokinius
                        </div>
                        <div className="grid gap-2">
                          {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                            <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]">
                              <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                            </button>
                          ))}
                        </div>
                      </div>
                    ) : isLoadingSuggestions ? (
                      <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiame pagalbą...</span>
                      </div>
                    ) : null}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Footer Navigation */}
        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={handleBackWithConfirm} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>

          <button 
            onClick={next} 
            disabled={!isStepValid}
            className={`font-black px-12 py-5 rounded-2xl shadow-xl transition-all active:scale-95 flex items-center gap-3 ${
              isStepValid ? 'bg-indigo-600 text-white hover:shadow-indigo-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'
            }`}
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  aiInsights: any;
  onComplete: () => void;
  onBack: () => void;
}

const WIZARD_STEP_KEY = 'teacher_reflection_wizard_step_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  aiInsights,
  onComplete,
  onBack
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [showFinalConfirm, setShowFinalConfirm] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [touchedSteps, setTouchedSteps] = useState<Set<number>>(new Set());
  const [focusedFieldKey, setFocusedFieldKey] = useState<string | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  // Menus / Options
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const [showObservationsMenu, setShowObservationsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];
  const observationsList = ['Klasės dinamika', 'Aktyvumas pamokoje', 'Motyvacija', 'Dalyko supratimas', 'Socialiniai įgūdžiai'];

  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Restore wizard step on mount
  useEffect(() => {
    const savedStep = localStorage.getItem(WIZARD_STEP_KEY);
    if (savedStep) {
      setCurrentStep(parseInt(savedStep, 10));
    }
  }, []);

  // Persist wizard step whenever it changes
  useEffect(() => {
    localStorage.setItem(WIZARD_STEP_KEY, currentStep.toString());
  }, [currentStep]);

  // Recording Timer
  useEffect(() => {
    if (isRecording) {
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setRecordingTime(0);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isRecording]);

  // Visual auto-save feedback
  useEffect(() => {
    setIsAutoSaving(true);
    const timeout = setTimeout(() => {
      setLastSaved(new Date());
      setIsAutoSaving(false);
    }, 1000);
    return () => clearTimeout(timeout);
  }, [reflection, currentStep]);

  // Tab close prevention
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      const hasContent = Object.values(reflection).some(v => (v as string).trim().length > 10);
      if (hasContent) {
        e.preventDefault();
        e.returnValue = 'Ar tikrai norite išeiti? Jūsų progresas yra išsaugotas.';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection]);

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į mokinių duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu, kad mokiniai nurodė...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai mokinio akimis",
      fields: [
        { key: 'strengths', label: "Kuo mokiniai džiaugiasi?", placeholder: "Mokiniams patiko...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Ką vaikai norėtų keisti?", placeholder: "Mokiniai indikavo, kad...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Nebuvau pagalvojęs, kad mokiniai...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai, kuriuos vertina vaikai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į vaikų atvirumą",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Pamačius mokinių atsakymus, jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant mokinių poreikius...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais dėl savo mokinių?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Kitąmet mokiniai turėtų pajusti...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  // AI Suggestions Trigger
  useEffect(() => {
    const currentStepFields = steps[currentStep].fields;
    const focusedField = currentStepFields.find(f => f.key === focusedFieldKey);

    if (focusedField?.suggestionsKey && aiInsights) {
      const timer = setTimeout(() => {
        generateAIPrompts();
      }, 400);
      return () => clearTimeout(timer);
    }
  }, [focusedFieldKey, currentStep, reflection.observations, reflection.strengths, reflection.improvements]);

  const generateAIPrompts = async () => {
    if (isLoadingSuggestions) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises,
        aiInsights
      );
      setAiSuggestions(suggestions);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsLoadingSuggestions(false); 
    }
  };

  const handleFieldFocus = (fieldKey: string) => {
    setFocusedFieldKey(fieldKey);
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => { 
        if (event.data.size > 0) audioChunksRef.current.push(event.data); 
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        setIsTranscribing(true);

        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          try {
            const base64Audio = (reader.result as string).split(',')[1];
            const transcription = await transcribeAudio(base64Audio, audioBlob.type);
            if (transcription && transcription.trim()) {
              setReflection(prevRef => ({ 
                ...prevRef, 
                [field]: prevRef[field as keyof ReflectionData] 
                  ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription.trim()}` 
                  : transcription.trim() 
              }));
            }
          } catch (err) {
            console.error("Transcription failed", err);
            alert("Nepavyko perrašyti garso. Bandykite dar kartą.");
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
    } catch (err) { 
      alert("Nepavyko pasiekti mikrofono."); 
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal && currentVal.trim().length > 0 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const currentStepFields = steps[currentStep].fields;
  const isStepValid = currentStepFields.every(field => {
    const val = (reflection as any)[field.key];
    return val && val.trim().length > 0;
  });

  const next = () => {
    setTouchedSteps(prev => new Set(prev).add(currentStep));
    if (!isStepValid) return;

    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
      }, 200);
    } else {
      setShowFinalConfirm(true);
    }
  };

  const handleBackWithConfirm = () => {
    if (Object.values(reflection).some(v => (v as string).trim().length > 5)) {
      setShowExitConfirm(true);
    } else {
      onBack();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleWizardComplete = () => {
    localStorage.removeItem(WIZARD_STEP_KEY);
    onComplete();
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Exit Confirmation */}
      {showExitConfirm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight text-rose-600">Išeiti iš refleksijos?</h3>
            <p className="text-gray-500 mb-8 font-medium">Jūsų progresas yra išsaugotas, bet grįšite į duomenų apžvalgą.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { setShowExitConfirm(false); onBack(); }} className="bg-gray-900 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Taip, išeiti</button>
              <button onClick={() => setShowExitConfirm(false)} className="bg-indigo-50 text-indigo-600 font-black py-4 rounded-2xl hover:bg-indigo-100 transition-all">Likti ir pildyti</button>
            </div>
          </div>
        </div>
      )}

      {/* Final Summary Confirmation Modal */}
      {showFinalConfirm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/70 backdrop-blur-lg">
          <div className="bg-white rounded-[3rem] p-8 md:p-12 max-w-2xl w-full shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="mb-8 shrink-0">
              <h3 className="text-3xl font-black text-gray-900 tracking-tight">Refleksijos santrauka</h3>
              <p className="text-gray-500 font-medium mt-2">Peržiūrėkite savo įžvalgas prieš generuojant galutinę ataskaitą.</p>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-8">
              {steps.map((step, idx) => (
                <div key={idx} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500 border-b border-indigo-50 pb-2">{step.title}</h4>
                  <div className="space-y-6">
                    {step.fields.map(field => (
                      <div key={field.key} className="bg-slate-50 p-6 rounded-2xl border border-gray-100">
                        <p className="text-[10px] font-black uppercase text-gray-400 mb-2 flex items-center gap-2">
                          <i className={`fas ${field.icon} text-[8px]`}></i> {field.label}
                        </p>
                        <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">{(reflection as any)[field.key] || '-'}</p>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-10 shrink-0 grid grid-cols-2 gap-4">
              <button 
                onClick={() => setShowFinalConfirm(false)} 
                className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-all active:scale-95 text-sm"
              >
                Grįžti ir taisyti
              </button>
              <button 
                onClick={handleWizardComplete} 
                className="bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-95 text-sm"
              >
                Patvirtinti ir baigti
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Auto-save Status */}
      <div className="flex items-center justify-between mb-8 px-4">
        <div className="flex items-center gap-3">
           <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${isAutoSaving ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
             {isAutoSaving ? 'Išsaugoma...' : `Auto-išsaugota: ${lastSaved ? lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' }) : 'Ką tik'}`}
           </span>
        </div>
        <div className="text-[10px] font-black uppercase tracking-widest text-indigo-400">
          Žingsnis {currentStep + 1} iš {steps.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard Content Card */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const val = (reflection as any)[field.key];
            const isEmpty = !val || val.trim().length === 0;
            const showError = isEmpty && touchedSteps.has(currentStep);
            const isFocused = focusedFieldKey === field.key;
            const isThisRecording = isRecording && recordingField === field.key;

            return (
              <div key={field.key} className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="font-black text-gray-800 flex items-center gap-3">
                    <i className={`fas ${field.icon} ${showError ? 'text-rose-500' : 'text-indigo-500'}`}></i> 
                    {field.label}
                    {showError && <span className="text-[9px] text-rose-500 uppercase tracking-widest font-black bg-rose-50 px-2 py-0.5 rounded-full">Privaloma</span>}
                  </label>

                  <div className="flex gap-2">
                    {field.hasEmotions && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                          className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-face-smile"></i> Nuotaikos
                        </button>
                        {showEmotionsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {emotionsList.map(emo => (
                                <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {emo} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    {field.key === 'observations' && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowObservationsMenu(!showObservationsMenu)} 
                          className="h-10 px-4 rounded-xl bg-slate-100 text-slate-600 flex items-center justify-center gap-2 hover:bg-slate-200 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-list-check"></i> Komentuoti
                        </button>
                        {showObservationsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {observationsList.map(obs => (
                                <button key={obs} onClick={() => { insertSuggestion('observations', obs); setShowObservationsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {obs} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    <button 
                      onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                      disabled={isTranscribing}
                      className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                        isThisRecording 
                          ? 'bg-rose-500 text-white shadow-rose-200' 
                          : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
                      } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      title={isThisRecording ? "Sustabdyti" : "Įrašyti balsu"}
                    >
                      <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                      <span>{isThisRecording ? `Sustabdyti (${formatTime(recordingTime)})` : 'Įrašyti balsu'}</span>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea 
                    value={val} 
                    onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                    onFocus={() => handleFieldFocus(field.key)}
                    placeholder={field.placeholder} 
                    className={`w-full h-32 p-6 rounded-3xl border-2 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300 ${
                      showError ? 'border-rose-100 bg-rose-50/20 focus:border-rose-300' : 'border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50'
                    } ${isFocused ? 'ring-4 ring-indigo-500/5' : ''}`}
                  ></textarea>
                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 bg-white/70 backdrop-blur-sm rounded-3xl flex flex-col items-center justify-center gap-3 animate-fade-in">
                      <div className="w-6 h-6 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                      <span className="font-black text-indigo-600 text-[9px] tracking-[0.3em] uppercase">Perrašoma...</span>
                    </div>
                  )}
                </div>

                {/* AI Suggestions Section - Visible only when focused */}
                {isFocused && field.suggestionsKey && (
                  <div className="space-y-4 animate-fade-in">
                    {aiSuggestions[field.suggestionsKey]?.length > 0 ? (
                      <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4">
                        <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <i className="fas fa-magic"></i> Mentoriaus įžvalgos pagal mokinius
                        </div>
                        <div className="grid gap-2">
                          {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                            <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]">
                              <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                            </button>
                          ))}
                        </div>
                      </div>
                    ) : isLoadingSuggestions ? (
                      <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiame pagalbą...</span>
                      </div>
                    ) : null}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Footer Navigation */}
        <div className="flex justify-between mt-16 pt-8 border-t border-gray-50">
          <button onClick={handleBackWithConfirm} className="px-8 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
            <i className="fas fa-chevron-left"></i> Atgal
          </button>

          <button 
            onClick={next} 
            disabled={!isStepValid}
            className={`font-black px-12 py-5 rounded-2xl shadow-xl transition-all active:scale-95 flex items-center gap-3 ${
              isStepValid ? 'bg-indigo-600 text-white hover:shadow-indigo-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'
            }`}
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData, CATEGORY_MAP, REVERSE_QUESTIONS } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const SESSION_DRAFT_KEY = 'teacher_reflection_session_v1';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showShareToast, setShowShareToast] = useState(false);
  const [history, setHistory] = useState<any[]>([]);
  const [hasDraft, setHasDraft] = useState(false);

  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '', strengths: '', improvements: '', surprises: '',
    bestPractices: '', heartFeelings: '', headThoughts: '',
    actionStop: '', actionStart: '', actionContinue: '', nextSteps: ''
  });

  // Load history and check for draft on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('teacher_reflection_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const draft = localStorage.getItem(SESSION_DRAFT_KEY);
    if (draft) {
      setHasDraft(true);
    }

    const hash = window.location.hash;
    if (hash.startsWith('#data=')) {
      try {
        const base64 = hash.replace('#data=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(base64))));
        setReflection(decodedData);
        setStep(AppStep.REPORT);
        window.history.replaceState(null, '', window.location.pathname);
      } catch (e) { console.error(e); }
    }
  }, []);

  // Auto-save session state
  useEffect(() => {
    if (step !== AppStep.UPLOAD && step !== AppStep.REPORT) {
      const stateToSave = {
        step,
        summaries,
        openFeedback,
        aiInsights,
        reflection,
        timestamp: Date.now()
      };
      localStorage.setItem(SESSION_DRAFT_KEY, JSON.stringify(stateToSave));
    }
  }, [step, summaries, openFeedback, aiInsights, reflection]);

  const handleResumeSession = () => {
    const draftJson = localStorage.getItem(SESSION_DRAFT_KEY);
    if (draftJson) {
      try {
        const draft = JSON.parse(draftJson);
        setSummaries(draft.summaries || []);
        setOpenFeedback(draft.openFeedback || []);
        setAiInsights(draft.aiInsights || null);
        setReflection(draft.reflection);
        setStep(draft.step);
        setHasDraft(false);
      } catch (e) {
        console.error("Failed to resume session", e);
        localStorage.removeItem(SESSION_DRAFT_KEY);
      }
    }
  };

  const handleClearDraft = () => {
    localStorage.removeItem(SESSION_DRAFT_KEY);
    setHasDraft(false);
  };

  const saveToHistory = () => {
    const newEntry = {
      id: Date.now(),
      date: new Date().toISOString(),
      data: reflection,
      summary: summaries.length > 0 ? summaries[0].question.substring(0, 30) + '...' : 'Mokslo metų vertinimas'
    };
    const updated = [newEntry, ...history].slice(0, 20);
    setHistory(updated);
    localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
    localStorage.removeItem(SESSION_DRAFT_KEY);
  };

  const deleteFromHistory = (id: number, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Ar tikrai norite ištrinti šią refleksiją iš istorijos?')) {
      const updated = history.filter(item => item.id !== id);
      setHistory(updated);
      localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
    }
  };

  const handleDataParsed = (rows: SurveyRow[]) => {
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const handleNewAnalysis = () => {
    if (step !== AppStep.UPLOAD) {
      if (confirm('Ar tikrai norite pradėti naują analizę? Visi nebaigti refleksijos pokyčiai bus prarasti.')) {
        localStorage.removeItem(SESSION_DRAFT_KEY);
        window.location.reload();
      }
    }
  };

  const cleanHeader = (header: string): string => {
    const match = header.match(/\[(.*?)\]/);
    if (match && match[1]) return match[1].trim();
    return header.replace(/^Prašome atsakyti į klausimus nuoširdžiai, taip, kaip manote ir jaučiatės\.\s*/i, '').trim();
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;
    const rawHeaders = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    rawHeaders.forEach(rawHeader => {
      if (rawHeader.toLowerCase().includes('laiko žymė')) return;
      const cleanedHeader = cleanHeader(rawHeader);

      let sum = 0, validCount = 0, isNumeric = false;
      const counts: { [val: string]: number } = {};

      rows.forEach(row => {
        const val = row[rawHeader]?.trim();
        if (val) {
          counts[val] = (counts[val] || 0) + 1;
          const normalizedVal = val.endsWith('.') ? val.slice(0, -1) : val;
          if (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]) { 
            sum += (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]); 
            validCount++; 
            isNumeric = true; 
          }
        }
      });

      if (isNumeric && validCount > 0) {
        const categoryKey = Object.keys(CATEGORY_MAP).find(k => cleanedHeader.toLowerCase().includes(k.toLowerCase()) || rawHeader.toLowerCase().includes(k.toLowerCase()));
        const category = categoryKey ? CATEGORY_MAP[categoryKey] : 'Kita';
        newSummaries.push({
          question: cleanedHeader,
          counts,
          total: rows.length,
          averageScore: sum / validCount,
          category,
          isReverse: REVERSE_QUESTIONS.some(q => cleanedHeader.toLowerCase().includes(q.toLowerCase()))
        });
      } else {
        rows.forEach(row => { 
          const val = row[rawHeader]?.trim();
          if (val && val.length > 5 && !LIKERT_VALUES[val] && !LIKERT_VALUES[val.slice(0, -1)]) feedback.push(val); 
        });
      }
    });
    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, aiInsights, openFeedback]);

  const handleShare = () => {
    const dataString = JSON.stringify(reflection);
    const base64 = btoa(unescape(encodeURIComponent(dataString)));
    const url = `${window.location.origin}${window.location.pathname}#data=${base64}`;
    navigator.clipboard.writeText(url).then(() => {
      setShowShareToast(true);
      setTimeout(() => setShowShareToast(false), 3000);
    });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 selection:bg-indigo-100">
      {showShareToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[200] bg-gray-900 text-white px-8 py-4 rounded-2xl shadow-2xl animate-slide-up flex items-center gap-4 border border-white/10">
          <i className="fas fa-check-circle text-emerald-400"></i> Nuoroda nukopijuota sėkmingai!
        </div>
      )}

      <header className="bg-white border-b border-gray-100 py-6 mb-8 print:hidden">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><i className="fas fa-graduation-cap"></i></div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">Refleksijos pagalbininkas</h1>
          </div>
          {step !== AppStep.UPLOAD && (
            <button onClick={handleNewAnalysis} className="text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-indigo-600 transition-colors">
              Nauja analizė
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-6">
        {step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-center space-y-4">
              <h2 className="text-5xl font-black text-gray-900 tracking-tight">Mokslo metų analizė</h2>
              <p className="text-gray-500 max-w-lg mx-auto text-lg font-medium">Įkelk apklausos rezultatus ir leisk DI mentorystei nukreipti tavo augimą.</p>
            </div>

            {hasDraft && (
              <div className="bg-indigo-600 rounded-[2.5rem] p-8 text-white shadow-2xl animate-scale-in flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="flex items-center gap-6">
                  <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md">
                    <i className="fas fa-rotate-left text-xl"></i>
                  </div>
                  <div>
                    <h3 className="text-xl font-black">Tęsti nebaigtą sesiją?</h3>
                    <p className="text-indigo-100/80 text-sm font-medium">Radome jūsų paskutinę nebaigtą refleksiją.</p>
                  </div>
                </div>
                <div className="flex gap-3 w-full md:w-auto">
                  <button onClick={handleClearDraft} className="flex-1 px-6 py-4 rounded-2xl bg-white/10 hover:bg-white/20 font-black text-xs uppercase tracking-widest transition-all">Ištrinti</button>
                  <button onClick={handleResumeSession} className="flex-1 px-10 py-4 rounded-2xl bg-white text-indigo-600 font-black text-xs uppercase tracking-widest shadow-xl transition-all active:scale-95">Tęsti pildymą</button>
                </div>
              </div>
            )}

            <CSVUpload onParsed={handleDataParsed} />

            {history.length > 0 && (
              <div className="space-y-4">
                <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 px-2">Ankstesnės refleksijos</h3>
                <div className="grid md:grid-cols-2 gap-4">
                  {history.map(item => (
                    <div key={item.id} className="relative group">
                      <button 
                        onClick={() => { setReflection(item.data); setStep(AppStep.REPORT); }} 
                        className="w-full bg-white p-6 rounded-[2rem] border border-gray-100 text-left flex items-center justify-between hover:shadow-xl hover:border-indigo-100 transition-all pr-16"
                      >
                        <div>
                          <p className="font-black text-gray-800 text-lg">{new Date(item.date).toLocaleDateString('lt-LT')}</p>
                          <p className="text-xs text-gray-400 mt-1 uppercase font-bold tracking-wider truncate max-w-[200px]">{item.summary}</p>
                        </div>
                        <i className="fas fa-chevron-right text-gray-200 group-hover:text-indigo-500 transition-all"></i>
                      </button>
                      <button 
                        onClick={(e) => deleteFromHistory(item.id, e)}
                        className="absolute right-4 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full flex items-center justify-center text-gray-200 hover:text-rose-500 hover:bg-rose-50 transition-all"
                        title="Ištrinti iš istorijos"
                      >
                        <i className="fas fa-trash-can text-sm"></i>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {step === AppStep.ANALYSIS && <SummaryDashboard summaries={summaries} feedback={openFeedback} aiInsights={aiInsights} isAnalyzing={isAnalyzing} onNext={() => setStep(AppStep.REFLECTION)} />}

        {step === AppStep.REFLECTION && <ReflectionWizard reflection={reflection} setReflection={setReflection} aiInsights={aiInsights} onComplete={() => { saveToHistory(); setStep(AppStep.REPORT); }} onBack={() => setStep(AppStep.ANALYSIS)} onSaveAndExit={() => setStep(AppStep.UPLOAD)} />}

        {step === AppStep.REPORT && (
          <div className="max-w-4xl mx-auto bg-white p-10 md:p-16 rounded-[4rem] shadow-2xl animate-scale-in print:shadow-none print:p-0">
            {/* Report view code... */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16 border-b border-gray-100 pb-12 print:hidden gap-6">
              <div>
                <h2 className="text-4xl font-black text-gray-900">Refleksijos rezultatas</h2>
                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs mt-2">{new Date().toLocaleDateString('lt-LT')}</p>
              </div>
              <div className="flex gap-3 w-full md:w-auto">
                <button onClick={handleShare} className="flex-1 px-6 py-4 rounded-2xl border-2 border-indigo-50 text-indigo-600 font-black text-sm flex items-center justify-center gap-2 transition-all active:scale-95"><i className="fas fa-share"></i> Dalintis</button>
                <button onClick={() => window.print()} className="flex-1 px-6 py-4 rounded-2xl bg-indigo-600 text-white font-black text-sm flex items-center justify-center gap-2 shadow-xl shadow-indigo-100 transition-all active:scale-95"><i className="fas fa-file-pdf"></i> Atsisiųsti PDF</button>
              </div>
            </div>

            <div className="space-y-16">
              <section className="grid md:grid-cols-2 gap-12">
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">Pastebėjimai</h4><p className="text-gray-700 italic text-xl">"{reflection.observations || '-'}"</p></div>
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-500">Stiprybės</h4><p className="text-gray-700 text-xl font-medium">{reflection.strengths || '-'}</p></div>
              </section>

              <section className="bg-slate-900 text-white p-12 rounded-[3rem] space-y-10 relative overflow-hidden">
                <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-500/10 blur-[100px] rounded-full"></div>
                <h3 className="font-black text-2xl flex items-center gap-4 relative z-10"><i className="fas fa-rocket text-indigo-400"></i> Veiksmų planas kitais metais</h3>
                <div className="grid md:grid-cols-3 gap-10 relative z-10 text-indigo-50/80">
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-rose-400 border-b border-rose-400/20 pb-2">Nustosiu</h5><p className="text-sm">{reflection.actionStop || '-'}</p></div>
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-emerald-400 border-b border-emerald-400/20 pb-2">Pradėsiu</h5><p className="text-sm">{reflection.actionStart || '-'}</p></div>
                  <div className="space-y-2"><h5 className="text-[10px] font-black uppercase tracking-widest text-indigo-400 border-b border-indigo-400/20 pb-2">Tęsiu</h5><p className="text-sm">{reflection.actionContinue || '-'}</p></div>
                </div>
                <div className="pt-8 border-t border-white/5 relative z-10 text-indigo-50/80">
                  <h5 className="text-[10px] font-black uppercase text-indigo-300 mb-2">Kaip žinosiu, kad vaikams sekasi geriau?</h5>
                  <p className="text-sm">{reflection.nextSteps || '-'}</p>
                </div>
              </section>

              <section className="grid md:grid-cols-2 gap-12">
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase text-gray-400">Geroji patirtis</h4><p className="text-gray-700">{reflection.bestPractices || '-'}</p></div>
                <div className="space-y-4"><h4 className="text-[10px] font-black uppercase text-gray-400">Refleksijos emocija</h4><p className="text-gray-700">{reflection.heartFeelings} • {reflection.headThoughts}</p></div>
              </section>

              <div className="text-center pt-10 border-t border-gray-100"><p className="text-[9px] text-gray-300 font-black uppercase tracking-[0.4em]">Refleksijos pagalbininkas • Profesinis augimas mokinio sėkmei</p></div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { ReflectionData } from '../types';
import { transcribeAudio, getReflectionSuggestions } from '../services/geminiService';

interface ReflectionWizardProps {
  reflection: ReflectionData;
  setReflection: React.Dispatch<React.SetStateAction<ReflectionData>>;
  aiInsights: any;
  onComplete: () => void;
  onBack: () => void;
  onSaveAndExit: () => void;
}

const WIZARD_STEP_KEY = 'teacher_reflection_wizard_step_v1';

const ReflectionWizard: React.FC<ReflectionWizardProps> = ({ 
  reflection, 
  setReflection, 
  aiInsights,
  onComplete,
  onBack,
  onSaveAndExit
}) => {
  const [currentStep, setCurrentStep] = useState(0);
  const [animating, setAnimating] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);
  const [showFinalConfirm, setShowFinalConfirm] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [isAutoSaving, setIsAutoSaving] = useState(false);
  const [touchedSteps, setTouchedSteps] = useState<Set<number>>(new Set());
  const [focusedFieldKey, setFocusedFieldKey] = useState<string | null>(null);

  // Audio Recording States
  const [isRecording, setIsRecording] = useState(false);
  const [recordingField, setRecordingField] = useState<string | null>(null);
  const [recordingTime, setRecordingTime] = useState(0);
  const [isTranscribing, setIsTranscribing] = useState(false);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioChunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  // Menus / Options
  const [showEmotionsMenu, setShowEmotionsMenu] = useState(false);
  const [showObservationsMenu, setShowObservationsMenu] = useState(false);
  const emotionsList = ['Džiaugsmas', 'Liūdesys', 'Skausmas', 'Apmąstymai', 'Nuobodulys', 'Įkvėpimas', 'Nerimas', 'Pasididžiavimas', 'Nuovargis'];
  const observationsList = ['Klasės dinamika', 'Aktyvumas pamokoje', 'Motyvacija', 'Dalyko supratimas', 'Socialiniai įgūdžiai'];

  const [aiSuggestions, setAiSuggestions] = useState<any>({
    observationSuggestions: [],
    analysisSuggestions: [],
    bestPracticeSuggestions: [],
    emotionSuggestions: [],
    actionSuggestions: [],
    nextStepSuggestions: []
  });
  const [isLoadingSuggestions, setIsLoadingSuggestions] = useState(false);

  // Restore wizard step on mount
  useEffect(() => {
    const savedStep = localStorage.getItem(WIZARD_STEP_KEY);
    if (savedStep) {
      setCurrentStep(parseInt(savedStep, 10));
    }
  }, []);

  // Persist wizard step whenever it changes
  useEffect(() => {
    localStorage.setItem(WIZARD_STEP_KEY, currentStep.toString());
  }, [currentStep]);

  // Recording Timer
  useEffect(() => {
    if (isRecording) {
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setRecordingTime(0);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isRecording]);

  // Visual auto-save feedback
  useEffect(() => {
    setIsAutoSaving(true);
    const timeout = setTimeout(() => {
      setLastSaved(new Date());
      setIsAutoSaving(false);
    }, 1000);
    return () => clearTimeout(timeout);
  }, [reflection, currentStep]);

  // Tab close prevention
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      const hasContent = Object.values(reflection).some(v => (v as string).trim().length > 10);
      if (hasContent) {
        e.preventDefault();
        e.returnValue = 'Ar tikrai norite išeiti? Jūsų progresas yra išsaugotas.';
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, [reflection]);

  const steps = [
    {
      title: "1. Pastebėjimai",
      description: "Kas krenta į akis žiūrint į mokinių duomenis?",
      fields: [
        { key: 'observations', label: "Objektyvūs pastebėjimai", placeholder: "Pvz.: Pastebiu, kad mokiniai nurodė...", icon: "fa-eye", suggestionsKey: 'observationSuggestions' }
      ]
    },
    {
      title: "2. Analizė",
      description: "Stiprybės, kryptys ir netikėtumai mokinio akimis",
      fields: [
        { key: 'strengths', label: "Kuo mokiniai džiaugiasi?", placeholder: "Mokiniams patiko...", icon: "fa-star", suggestionsKey: 'analysisSuggestions' },
        { key: 'improvements', label: "Ką vaikai norėtų keisti?", placeholder: "Mokiniai indikavo, kad...", icon: "fa-chart-line", suggestionsKey: 'analysisSuggestions' },
        { key: 'surprises', label: "Kas nustebino?", placeholder: "Nebuvau pagalvojęs, kad mokiniai...", icon: "fa-bolt", suggestionsKey: 'analysisSuggestions' }
      ]
    },
    {
      title: "3. Geroji patirtis",
      description: "Sėkmingi metodai, kuriuos vertina vaikai",
      fields: [
        { key: 'bestPractices', label: "Gerąsios praktikos", placeholder: "Pvz.: Mokiniai itin vertina grįžtamąjį ryšį...", icon: "fa-thumbs-up", suggestionsKey: 'bestPracticeSuggestions' }
      ]
    },
    {
      title: "4. Galva ir Širdis",
      description: "Tavo reakcija į vaikų atvirumą",
      fields: [
        { key: 'heartFeelings', label: "Kaip reaguoja ŠIRDIS?", placeholder: "Pamačius mokinių atsakymus, jaučiuosi...", icon: "fa-heart", suggestionsKey: 'emotionSuggestions', hasEmotions: true },
        { key: 'headThoughts', label: "Ką sako GALVA?", placeholder: "Racionaliai vertinant mokinių poreikius...", icon: "fa-brain", suggestionsKey: 'emotionSuggestions' }
      ]
    },
    {
      title: "5. Veiksmų planas",
      description: "Ką darysi kitaip kitais metais dėl savo mokinių?",
      fields: [
        { key: 'actionStop', label: "Ką nustosi daryti?", placeholder: "Nustosiu...", icon: "fa-circle-stop", suggestionsKey: 'actionSuggestions' },
        { key: 'actionStart', label: "Ką pradėsi daryti?", placeholder: "Pradėsiu...", icon: "fa-circle-play", suggestionsKey: 'actionSuggestions' },
        { key: 'actionContinue', label: "Ką tęsi?", placeholder: "Tęsiu...", icon: "fa-rotate", suggestionsKey: 'actionSuggestions' },
        { key: 'nextSteps', label: "Kaip matuosi sėkmę?", placeholder: "Kitąmet mokiniai turėtų pajusti...", icon: "fa-bullseye", suggestionsKey: 'nextStepSuggestions' }
      ]
    }
  ];

  // AI Suggestions Trigger
  useEffect(() => {
    const currentStepFields = steps[currentStep].fields;
    const focusedField = currentStepFields.find(f => f.key === focusedFieldKey);

    if (focusedField?.suggestionsKey && aiInsights) {
      const timer = setTimeout(() => {
        generateAIPrompts();
      }, 400);
      return () => clearTimeout(timer);
    }
  }, [focusedFieldKey, currentStep, reflection.observations, reflection.strengths, reflection.improvements]);

  const generateAIPrompts = async () => {
    if (isLoadingSuggestions) return;
    setIsLoadingSuggestions(true);
    try {
      const suggestions = await getReflectionSuggestions(
        reflection.observations,
        reflection.strengths,
        reflection.improvements,
        reflection.surprises,
        aiInsights
      );
      setAiSuggestions(suggestions);
    } catch (e) { 
      console.error(e); 
    } finally { 
      setIsLoadingSuggestions(false); 
    }
  };

  const handleFieldFocus = (fieldKey: string) => {
    setFocusedFieldKey(fieldKey);
  };

  const startRecording = async (field: string) => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      audioChunksRef.current = [];

      mediaRecorder.ondataavailable = (event) => { 
        if (event.data.size > 0) audioChunksRef.current.push(event.data); 
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(audioChunksRef.current, { type: mediaRecorder.mimeType });
        setIsTranscribing(true);

        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = async () => {
          try {
            const base64Audio = (reader.result as string).split(',')[1];
            const transcription = await transcribeAudio(base64Audio, audioBlob.type);
            if (transcription && transcription.trim()) {
              setReflection(prevRef => ({ 
                ...prevRef, 
                [field]: prevRef[field as keyof ReflectionData] 
                  ? `${prevRef[field as keyof ReflectionData].trim()}\n${transcription.trim()}` 
                  : transcription.trim() 
              }));
            }
          } catch (err) {
            console.error("Transcription failed", err);
            alert("Nepavyko perrašyti garso. Bandykite dar kartą.");
          } finally {
            setIsTranscribing(false);
          }
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      setRecordingField(field);
    } catch (err) { 
      alert("Nepavyko pasiekti mikrofono."); 
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
      setRecordingField(null);
    }
  };

  const insertSuggestion = (field: keyof ReflectionData, suggestion: string) => {
    setReflection(prevRef => {
      const currentVal = prevRef[field];
      const newVal = currentVal && currentVal.trim().length > 0 
        ? `${currentVal.trim()}\n• ${suggestion}` 
        : `• ${suggestion}`;
      return { ...prevRef, [field]: newVal };
    });
  };

  const currentStepFields = steps[currentStep].fields;
  const isStepValid = currentStepFields.every(field => {
    const val = (reflection as any)[field.key];
    return val && val.trim().length > 0;
  });

  const next = () => {
    setTouchedSteps(prev => new Set(prev).add(currentStep));
    if (!isStepValid) return;

    if (currentStep < steps.length - 1) {
      setAnimating(true);
      setTimeout(() => {
        setCurrentStep(currentStep + 1);
        setAnimating(false);
      }, 200);
    } else {
      setShowFinalConfirm(true);
    }
  };

  const handleBackWithConfirm = () => {
    if (Object.values(reflection).some(v => (v as string).trim().length > 5)) {
      setShowExitConfirm(true);
    } else {
      onBack();
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handleWizardComplete = () => {
    localStorage.removeItem(WIZARD_STEP_KEY);
    onComplete();
  };

  return (
    <div className="max-w-4xl mx-auto px-4 pb-12 relative">
      {/* Exit Confirmation */}
      {showExitConfirm && (
        <div className="fixed inset-0 z-[150] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-4 tracking-tight text-rose-600">Išeiti iš refleksijos?</h3>
            <p className="text-gray-500 mb-8 font-medium">Jūsų progresas yra automatiškai išsaugotas.</p>
            <div className="flex flex-col gap-4">
              <button onClick={() => { setShowExitConfirm(false); onBack(); }} className="bg-gray-900 text-white font-black py-4 rounded-2xl shadow-lg active:scale-95 transition-all">Taip, išeiti</button>
              <button onClick={() => setShowExitConfirm(false)} className="bg-indigo-50 text-indigo-600 font-black py-4 rounded-2xl hover:bg-indigo-100 transition-all">Likti ir pildyti</button>
            </div>
          </div>
        </div>
      )}

      {/* Final Summary Confirmation Modal */}
      {showFinalConfirm && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-gray-900/70 backdrop-blur-lg">
          <div className="bg-white rounded-[3rem] p-8 md:p-12 max-w-2xl w-full shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="mb-8 shrink-0">
              <h3 className="text-3xl font-black text-gray-900 tracking-tight">Refleksijos santrauka</h3>
              <p className="text-gray-500 font-medium mt-2">Peržiūrėkite savo įžvalgas prieš generuojant galutinę ataskaitą.</p>
            </div>

            <div className="flex-1 overflow-y-auto pr-4 custom-scrollbar space-y-8">
              {steps.map((step, idx) => (
                <div key={idx} className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500 border-b border-indigo-50 pb-2">{step.title}</h4>
                  <div className="space-y-6">
                    {step.fields.map(field => (
                      <div key={field.key} className="bg-slate-50 p-6 rounded-2xl border border-gray-100">
                        <p className="text-[10px] font-black uppercase text-gray-400 mb-2 flex items-center gap-2">
                          <i className={`fas ${field.icon} text-[8px]`}></i> {field.label}
                        </p>
                        <p className="text-gray-700 text-sm leading-relaxed whitespace-pre-wrap">{(reflection as any)[field.key] || '-'}</p>
                      </div>
                    ))}
                  </div>
                </div>
              ))}
            </div>

            <div className="mt-10 shrink-0 grid grid-cols-2 gap-4">
              <button 
                onClick={() => setShowFinalConfirm(false)} 
                className="bg-gray-100 text-gray-500 font-black py-5 rounded-2xl hover:bg-gray-200 transition-all active:scale-95 text-sm"
              >
                Grįžti ir taisyti
              </button>
              <button 
                onClick={handleWizardComplete} 
                className="bg-indigo-600 text-white font-black py-5 rounded-2xl shadow-xl shadow-indigo-100 transition-all active:scale-95 text-sm"
              >
                Patvirtinti ir baigti
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Auto-save Status */}
      <div className="flex items-center justify-between mb-8 px-4">
        <div className="flex items-center gap-3">
           <div className={`w-2 h-2 rounded-full transition-colors duration-500 ${isAutoSaving ? 'bg-amber-400 animate-pulse' : 'bg-emerald-500'}`}></div>
           <span className="text-[10px] font-black uppercase tracking-widest text-gray-400">
             {isAutoSaving ? 'Išsaugoma...' : `Auto-išsaugota: ${lastSaved ? lastSaved.toLocaleTimeString('lt-LT', { hour: '2-digit', minute: '2-digit' }) : 'Ką tik'}`}
           </span>
        </div>
        <div className="text-[10px] font-black uppercase tracking-widest text-indigo-400">
          Žingsnis {currentStep + 1} iš {steps.length}
        </div>
      </div>

      {/* Progress Bar */}
      <div className="flex justify-between mb-16 relative px-4">
        <div className="absolute top-1/2 left-0 w-full h-1 bg-gray-100 -translate-y-1/2 -z-10 rounded-full"></div>
        <div className="absolute top-1/2 left-0 h-1 bg-indigo-600 -translate-y-1/2 -z-10 rounded-full transition-all duration-500" style={{ width: `${(currentStep / (steps.length - 1)) * 100}%` }}></div>
        {steps.map((_, idx) => (
          <button key={idx} onClick={() => idx < currentStep && setCurrentStep(idx)} className={`w-10 h-10 rounded-xl flex items-center justify-center font-black transition-all ${idx === currentStep ? 'bg-indigo-600 text-white shadow-xl scale-110' : idx < currentStep ? 'bg-indigo-100 text-indigo-600' : 'bg-white text-gray-300 border border-gray-100'}`}>
            {idx < currentStep ? <i className="fas fa-check"></i> : idx + 1}
          </button>
        ))}
      </div>

      {/* Wizard Content Card */}
      <div className={`bg-white p-8 md:p-12 rounded-[3rem] shadow-xl transition-all duration-300 ${animating ? 'opacity-0 translate-y-4' : 'opacity-100'}`}>
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 bg-indigo-50 text-indigo-600 text-[10px] font-black px-4 py-1.5 rounded-full uppercase tracking-widest mb-4">
            Profesinė savirefleksija
          </div>
          <h2 className="text-3xl font-black text-gray-900 tracking-tight">{steps[currentStep].title}</h2>
          <p className="text-gray-500 font-medium">{steps[currentStep].description}</p>
        </header>

        <div className="space-y-12">
          {steps[currentStep].fields.map((field) => {
            const val = (reflection as any)[field.key];
            const isEmpty = !val || val.trim().length === 0;
            const showError = isEmpty && touchedSteps.has(currentStep);
            const isFocused = focusedFieldKey === field.key;
            const isThisRecording = isRecording && recordingField === field.key;

            return (
              <div key={field.key} className="space-y-4">
                <div className="flex items-center justify-between">
                  <label className="font-black text-gray-800 flex items-center gap-3">
                    <i className={`fas ${field.icon} ${showError ? 'text-rose-500' : 'text-indigo-500'}`}></i> 
                    {field.label}
                    {showError && <span className="text-[9px] text-rose-500 uppercase tracking-widest font-black bg-rose-50 px-2 py-0.5 rounded-full">Privaloma</span>}
                  </label>

                  <div className="flex gap-2">
                    {field.hasEmotions && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowEmotionsMenu(!showEmotionsMenu)} 
                          className="px-4 h-10 rounded-xl bg-rose-50 text-rose-600 flex items-center justify-center gap-2 hover:bg-rose-100 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-face-smile"></i> Nuotaikos
                        </button>
                        {showEmotionsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {emotionsList.map(emo => (
                                <button key={emo} onClick={() => { insertSuggestion(field.key as any, emo); setShowEmotionsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {emo} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    {field.key === 'observations' && (
                      <div className="relative">
                        <button 
                          onClick={() => setShowObservationsMenu(!showObservationsMenu)} 
                          className="h-10 px-4 rounded-xl bg-slate-100 text-slate-600 flex items-center justify-center gap-2 hover:bg-slate-200 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95"
                        >
                          <i className="fas fa-list-check"></i> Komentuoti
                        </button>
                        {showObservationsMenu && (
                          <div className="absolute right-0 top-12 z-[100] bg-white border border-gray-100 shadow-2xl rounded-2xl p-4 w-52 animate-fade-in">
                            <div className="grid gap-1">
                              {observationsList.map(obs => (
                                <button key={obs} onClick={() => { insertSuggestion('observations', obs); setShowObservationsMenu(false); }} className="w-full text-left px-3 py-2 text-xs hover:bg-indigo-50 hover:text-indigo-600 rounded-lg font-bold transition-all flex items-center justify-between group">
                                  {obs} <i className="fas fa-plus opacity-0 group-hover:opacity-100 text-[10px]"></i>
                                </button>
                              ))}
                            </div>
                          </div>
                        )}
                      </div>
                    )}

                    <button 
                      onClick={() => isThisRecording ? stopRecording() : startRecording(field.key)} 
                      disabled={isTranscribing}
                      className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm font-black text-[10px] uppercase tracking-widest active:scale-95 ${
                        isThisRecording 
                          ? 'bg-rose-500 text-white shadow-rose-200' 
                          : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100'
                      } ${isTranscribing ? 'opacity-50 cursor-not-allowed' : ''}`}
                      title={isThisRecording ? "Sustabdyti" : "Įrašyti balsu"}
                    >
                      <i className={`fas ${isThisRecording ? 'fa-stop' : 'fa-microphone'} ${isThisRecording ? 'animate-pulse' : ''}`}></i>
                      <span>{isThisRecording ? `Sustabdyti (${formatTime(recordingTime)})` : 'Įrašyti balsu'}</span>
                    </button>
                  </div>
                </div>

                <div className="relative">
                  <textarea 
                    value={val} 
                    onChange={(e) => setReflection({ ...reflection, [field.key]: e.target.value })} 
                    onFocus={() => handleFieldFocus(field.key)}
                    placeholder={field.placeholder} 
                    className={`w-full h-32 p-6 rounded-3xl border-2 transition-all outline-none resize-none font-medium text-gray-700 leading-relaxed placeholder:italic placeholder:text-gray-300 ${
                      showError ? 'border-rose-100 bg-rose-50/20 focus:border-rose-300' : 'border-gray-50 bg-gray-50/30 focus:bg-white focus:border-indigo-500/50'
                    } ${isFocused ? 'ring-4 ring-indigo-500/5' : ''}`}
                  ></textarea>
                  {isTranscribing && recordingField === field.key && (
                    <div className="absolute inset-0 bg-white/70 backdrop-blur-sm rounded-3xl flex flex-col items-center justify-center gap-3 animate-fade-in">
                      <div className="w-6 h-6 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin"></div>
                      <span className="font-black text-indigo-600 text-[9px] tracking-[0.3em] uppercase">Perrašoma...</span>
                    </div>
                  )}
                </div>

                {/* AI Suggestions Section - Visible only when focused */}
                {isFocused && field.suggestionsKey && (
                  <div className="space-y-4 animate-fade-in">
                    {aiSuggestions[field.suggestionsKey]?.length > 0 ? (
                      <div className="bg-indigo-50/40 p-6 rounded-[2rem] border border-indigo-100/30 space-y-4">
                        <div className="flex items-center gap-2 text-[10px] font-black text-indigo-400 uppercase tracking-widest">
                          <i className="fas fa-magic"></i> Mentoriaus įžvalgos pagal mokinius
                        </div>
                        <div className="grid gap-2">
                          {aiSuggestions[field.suggestionsKey].map((s: string, idx: number) => (
                            <button key={idx} onClick={() => insertSuggestion(field.key as any, s)} className="text-left text-[11px] bg-white p-3.5 rounded-xl border border-indigo-100/30 hover:border-indigo-400 hover:shadow-md transition-all text-gray-600 leading-relaxed group active:scale-[0.98]">
                              <i className="fas fa-plus mr-2 opacity-0 group-hover:opacity-100 text-indigo-500 transition-opacity"></i> {s}
                            </button>
                          ))}
                        </div>
                      </div>
                    ) : isLoadingSuggestions ? (
                      <div className="h-20 bg-gray-50/50 rounded-[2rem] border border-gray-100 animate-pulse flex items-center justify-center">
                        <span className="text-[10px] font-black uppercase tracking-widest text-gray-300">Ruošiame pagalbą...</span>
                      </div>
                    ) : null}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Footer Navigation */}
        <div className="flex justify-between items-center mt-16 pt-8 border-t border-gray-50">
          <div className="flex gap-4">
            <button onClick={handleBackWithConfirm} className="px-6 py-4 text-gray-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95">
              <i className="fas fa-chevron-left"></i> Atgal
            </button>
            <button onClick={onSaveAndExit} className="px-6 py-4 text-indigo-400 font-black hover:text-indigo-600 transition-all flex items-center gap-2 active:scale-95 text-xs uppercase tracking-widest">
              <i className="fas fa-save"></i> Išsaugoti ir išeiti
            </button>
          </div>

          <button 
            onClick={next} 
            disabled={!isStepValid}
            className={`font-black px-12 py-5 rounded-2xl shadow-xl transition-all active:scale-95 flex items-center gap-3 ${
              isStepValid ? 'bg-indigo-600 text-white hover:shadow-indigo-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'
            }`}
          >
            {currentStep === steps.length - 1 ? 'Baigti ir generuoti ataskaitą' : 'Toliau'} <i className="fas fa-arrow-right"></i>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReflectionWizard;

import { GoogleGenAI, Type } from "@google/genai";
import { QuestionSummary } from "../types";

// Init Gemini API with key from environment
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAIInsights = async (summaries: QuestionSummary[], openFeedback: string[]) => {
  const prompt = `
    Esi pedagoginis mentorius ir duomenų analitikas. Tau pateikiama mokslo metų pabaigos apklausos santrauka, kurią pildė MOKINIAI (kartais padedami tėvų). 
    Tavo užduotis - analizuoti duomenis iš mokinio perspektyvos: kaip jie jaučiasi pamokose, ar jiems suprantamas turinys, koks jų santykis su mokytoju.

    KIEKYBINIAI DUOMENYS (Mokinių vertinimai 1-5 skalėje):
    ${JSON.stringify(summaries)}

    KOKYBINIAI DUOMENYS (Mokinių tekstiniai atsakymai, jų mintys ir jausmai):
    ${openFeedback.join("\n")}

    Remiantis šiais duomenimas, sugeneruok išsamią analizę JSON formatu lietuvių kalba:
    1. "strengths": Mokinių labiausiai vertinamos mokytojo savybės ar metodai.
    2. "improvements": Sritys, kurias mokiniai (vaikai) indikavo kaip sunkias, neaiškias ar nemalonias.
    3. "insights": Gilios pedagoginės įžvalgos apie tai, kaip mokiniai priima mokymosi procesą.
    4. "themes": Išskirk 3-4 pagrindines temas iš tekstinių atsakymų (pvz., "Emocinis saugumas", "Namų darbų krūvis"). Kiekvienai temai pateik aprašymą ir vyraujančią mokinių nuotaiką.
    5. "sentimentScore": Bendras mokslo metų emocinis fonas mokinio akimis (nuo 0 iki 100).
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            strengths: { type: Type.STRING },
            improvements: { type: Type.STRING },
            insights: { type: Type.STRING },
            sentimentScore: { type: Type.NUMBER },
            themes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  label: { type: Type.STRING },
                  description: { type: Type.STRING },
                  sentiment: { type: Type.STRING }
                },
                required: ["label", "description", "sentiment"]
              }
            }
          },
          required: ["strengths", "improvements", "insights", "themes", "sentimentScore"]
        }
      }
    });

    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Gemini AI error:", error);
    return {
      strengths: "Nepavyko sugeneruoti įžvalgų.",
      improvements: "Peržiūrėkite mokinių duomenis rankiniu būdu.",
      insights: "",
      sentimentScore: 50,
      themes: []
    };
  }
};

export const getReflectionSuggestions = async (
  observations: string, 
  strengths: string, 
  improvements: string, 
  surprises: string,
  aiInsights: any
) => {
  const prompt = `
    Esi aukšto lygio pedagoginis mentorius. Mokytojas atlieka mokslo metų savirefleksiją.
    Tavo užduotis: pateikti personalizuotus pasiūlymus, kurie būtų TIESIOGIAI susieti su mokinio duomenų analizėje išskirtomis temomis.

    DUOMENŲ ANALIZĖ (MOKINIŲ BALSAS):
    - Išskirtos temos (themes): ${JSON.stringify(aiInsights?.themes || [])}
    - Mokinių vertinamos stiprybės: ${aiInsights?.strengths || 'Nenurodyta'}
    - Mokinių indikacijas tobulėjimui: ${aiInsights?.improvements || 'Nenurodyta'}

    DABARTINIS MOKYTOJO TEKSTAS:
    - Pastebėjimai: ${observations}
    - Stiprybės: ${strengths}
    - Tobulėjimas: ${improvements}
    - Netikėtumai: ${surprises}

    Sugeneruok trumpus (1-2 sakiniai), itin konkrečius pasiūlymus lietuvių kalba JSON formatu. 
    KIEKVIENAS pasiūlymas privalo padėti mokytojui suprasti ar spręsti konkrečias temas (themes). 
    Pvz., jei viena iš temų yra „Namų darbų krūvis“, pasiūlymas „actionSuggestions“ turi siūlyti konkretų krūvio mažinimo ar optimizavimo metodą.

    Struktūra:
    1. "observationSuggestions": Kaip interpretuoti duomenis per išskirtų temų prizmę (gilinkis į priežastis).
    2. "analysisSuggestions": Kaip mokytojo metodai tiesiogiai veikia išskirtas temas.
    3. "bestPracticeSuggestions": Sėkmingos praktikos, kurios palaiko teigiamas temas.
    4. "emotionSuggestions": Profesinė empatija, atitinkanti mokinių jausmus pagal identifikuotas temas.
    5. "actionSuggestions": Konkretūs veiksmai (start/stop/continue), sprendžiantys temines problemas.
    6. "nextStepSuggestions": Kaip pamatuoti specifinių temų pokytį kitoje apklausoje.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            observationSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            analysisSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            bestPracticeSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            emotionSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            actionSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
            nextStepSuggestions: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: [
            "observationSuggestions", 
            "analysisSuggestions", 
            "bestPracticeSuggestions", 
            "emotionSuggestions", 
            "actionSuggestions", 
            "nextStepSuggestions"
          ]
        }
      }
    });
    return JSON.parse(response.text || "{}");
  } catch (error) {
    console.error("Suggestions error:", error);
    return { 
      observationSuggestions: [], 
      analysisSuggestions: [], 
      bestPracticeSuggestions: [], 
      emotionSuggestions: [], 
      actionSuggestions: [], 
      nextStepSuggestions: [] 
    };
  }
};

export const transcribeAudio = async (base64Audio: string, mimeType: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Audio
            }
          },
          { text: "Tiksliai perrašyk šį garso įrašą į tekstą lietuvių kalba. Pateik tik patį perrašytą tekstą." }
        ]
      }
    });

    return response.text || "";
  } catch (error) {
    console.error("Transcription error:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData, CATEGORY_MAP, REVERSE_QUESTIONS } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const SESSION_DRAFT_KEY = 'teacher_reflection_session_v1';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showShareToast, setShowShareToast] = useState(false);
  const [history, setHistory] = useState<any[]>([]);
  const [hasDraft, setHasDraft] = useState(false);

  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '', strengths: '', improvements: '', surprises: '',
    bestPractices: '', heartFeelings: '', headThoughts: '',
    actionStop: '', actionStart: '', actionContinue: '', nextSteps: ''
  });

  // Load history and check for draft on mount
  useEffect(() => {
    const savedHistory = localStorage.getItem('teacher_reflection_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const draft = localStorage.getItem(SESSION_DRAFT_KEY);
    if (draft) {
      setHasDraft(true);
    }

    const hash = window.location.hash;
    if (hash.startsWith('#data=')) {
      try {
        const base64 = hash.replace('#data=', '');
        const decodedData = JSON.parse(decodeURIComponent(escape(atob(base64))));
        setReflection(decodedData);
        setStep(AppStep.REPORT);
        window.history.replaceState(null, '', window.location.pathname);
      } catch (e) { console.error(e); }
    }
  }, []);

  // Auto-save session state
  useEffect(() => {
    if (step !== AppStep.UPLOAD && step !== AppStep.REPORT) {
      const stateToSave = {
        step,
        summaries,
        openFeedback,
        aiInsights,
        reflection,
        timestamp: Date.now()
      };
      localStorage.setItem(SESSION_DRAFT_KEY, JSON.stringify(stateToSave));
    }
  }, [step, summaries, openFeedback, aiInsights, reflection]);

  const handleResumeSession = () => {
    const draftJson = localStorage.getItem(SESSION_DRAFT_KEY);
    if (draftJson) {
      try {
        const draft = JSON.parse(draftJson);
        setSummaries(draft.summaries || []);
        setOpenFeedback(draft.openFeedback || []);
        setAiInsights(draft.aiInsights || null);
        setReflection(draft.reflection);
        setStep(draft.step);
        setHasDraft(false);
      } catch (e) {
        console.error("Failed to resume session", e);
        localStorage.removeItem(SESSION_DRAFT_KEY);
      }
    }
  };

  const handleClearDraft = () => {
    localStorage.removeItem(SESSION_DRAFT_KEY);
    setHasDraft(false);
  };

  const saveToHistory = () => {
    const newEntry = {
      id: Date.now(),
      date: new Date().toISOString(),
      data: reflection,
      summary: summaries.length > 0 ? summaries[0].question.substring(0, 30) + '...' : 'Mokslo metų vertinimas'
    };
    const updated = [newEntry, ...history].slice(0, 20);
    setHistory(updated);
    localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
    localStorage.removeItem(SESSION_DRAFT_KEY);
  };

  const deleteFromHistory = (id: number, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Ar tikrai norite ištrinti šią refleksiją iš istorijos?')) {
      const updated = history.filter(item => item.id !== id);
      setHistory(updated);
      localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
    }
  };

  const handleDataParsed = (rows: SurveyRow[]) => {
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const handleNewAnalysis = () => {
    if (step !== AppStep.UPLOAD) {
      if (confirm('Ar tikrai norite pradėti naują analizę? Visi nebaigti refleksijos pokyčiai bus prarasti.')) {
        localStorage.removeItem(SESSION_DRAFT_KEY);
        window.location.reload();
      }
    }
  };

  const cleanHeader = (header: string): string => {
    const match = header.match(/\[(.*?)\]/);
    if (match && match[1]) return match[1].trim();
    return header.replace(/^Prašome atsakyti į klausimus nuoširdžiai, taip, kaip manote ir jaučiatės\.\s*/i, '').trim();
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;
    const rawHeaders = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    rawHeaders.forEach(rawHeader => {
      if (rawHeader.toLowerCase().includes('laiko žymė')) return;
      const cleanedHeader = cleanHeader(rawHeader);

      let sum = 0, validCount = 0, isNumeric = false;
      const counts: { [val: string]: number } = {};

      rows.forEach(row => {
        const val = row[rawHeader]?.trim();
        if (val) {
          counts[val] = (counts[val] || 0) + 1;
          const normalizedVal = val.endsWith('.') ? val.slice(0, -1) : val;
          if (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]) { 
            sum += (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]); 
            validCount++; 
            isNumeric = true; 
          }
        }
      });

      if (isNumeric && validCount > 0) {
        const categoryKey = Object.keys(CATEGORY_MAP).find(k => cleanedHeader.toLowerCase().includes(k.toLowerCase()) || rawHeader.toLowerCase().includes(k.toLowerCase()));
        const category = categoryKey ? CATEGORY_MAP[categoryKey] : 'Kita';
        newSummaries.push({
          question: cleanedHeader,
          counts,
          total: rows.length,
          averageScore: sum / validCount,
          category,
          isReverse: REVERSE_QUESTIONS.some(q => cleanedHeader.toLowerCase().includes(q.toLowerCase()))
        });
      } else {
        rows.forEach(row => { 
          const val = row[rawHeader]?.trim();
          if (val && val.length > 5 && !LIKERT_VALUES[val] && !LIKERT_VALUES[val.slice(0, -1)]) feedback.push(val); 
        });
      }
    });
    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, aiInsights, openFeedback]);

  const handleShare = () => {
    const dataString = JSON.stringify(reflection);
    const base64 = btoa(unescape(encodeURIComponent(dataString)));
    const url = `${window.location.origin}${window.location.pathname}#data=${base64}`;
    navigator.clipboard.writeText(url).then(() => {
      setShowShareToast(true);
      setTimeout(() => setShowShareToast(false), 3000);
    });
  };

  return (
    <div className="min-h-screen bg-slate-50 pb-20 selection:bg-indigo-100 print:bg-white print:pb-0">
      {showShareToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[200] bg-gray-900 text-white px-8 py-4 rounded-2xl shadow-2xl animate-slide-up flex items-center gap-4 border border-white/10 print:hidden">
          <i className="fas fa-check-circle text-emerald-400"></i> Nuoroda nukopijuota sėkmingai!
        </div>
      )}

      <header className="bg-white border-b border-gray-100 py-6 mb-8 print:hidden">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><i className="fas fa-graduation-cap"></i></div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">Refleksijos pagalbininkas</h1>
          </div>
          {step !== AppStep.UPLOAD && (
            <button onClick={handleNewAnalysis} className="text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-indigo-600 transition-colors">
              Nauja analizė
            </button>
          )}
        </div>
      </header>

      <main className="container mx-auto px-6 print:px-0">
        {step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-center space-y-4">
              <h2 className="text-5xl font-black text-gray-900 tracking-tight">Mokslo metų analizė</h2>
              <p className="text-gray-500 max-w-lg mx-auto text-lg font-medium">Įkelk apklausos rezultatus ir leisk DI mentorystei nukreipti tavo augimą.</p>
            </div>

            {hasDraft && (
              <div className="bg-indigo-600 rounded-[2.5rem] p-8 text-white shadow-2xl animate-scale-in flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="flex items-center gap-6">
                  <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md">
                    <i className="fas fa-rotate-left text-xl"></i>
                  </div>
                  <div>
                    <h3 className="text-xl font-black">Tęsti nebaigtą sesiją?</h3>
                    <p className="text-indigo-100/80 text-sm font-medium">Radome jūsų paskutinę nebaigtą refleksiją.</p>
                  </div>
                </div>
                <div className="flex gap-3 w-full md:w-auto">
                  <button onClick={handleClearDraft} className="flex-1 px-6 py-4 rounded-2xl bg-white/10 hover:bg-white/20 font-black text-xs uppercase tracking-widest transition-all">Ištrinti</button>
                  <button onClick={handleResumeSession} className="flex-1 px-10 py-4 rounded-2xl bg-white text-indigo-600 font-black text-xs uppercase tracking-widest shadow-xl transition-all active:scale-95">Tęsti pildymą</button>
                </div>
              </div>
            )}

            <CSVUpload onParsed={handleDataParsed} />

            {history.length > 0 && (
              <div className="space-y-4">
                <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 px-2">Ankstesnės refleksijos</h3>
                <div className="grid md:grid-cols-2 gap-4">
                  {history.map(item => (
                    <div key={item.id} className="relative group">
                      <button 
                        onClick={() => { setReflection(item.data); setStep(AppStep.REPORT); }} 
                        className="w-full bg-white p-6 rounded-[2rem] border border-gray-100 text-left flex items-center justify-between hover:shadow-xl hover:border-indigo-100 transition-all pr-16"
                      >
                        <div>
                          <p className="font-black text-gray-800 text-lg">{new Date(item.date).toLocaleDateString('lt-LT')}</p>
                          <p className="text-xs text-gray-400 mt-1 uppercase font-bold tracking-wider truncate max-w-[200px]">{item.summary}</p>
                        </div>
                        <i className="fas fa-chevron-right text-gray-200 group-hover:text-indigo-500 transition-all"></i>
                      </button>
                      <button 
                        onClick={(e) => deleteFromHistory(item.id, e)}
                        className="absolute right-4 top-1/2 -translate-y-1/2 w-10 h-10 rounded-full flex items-center justify-center text-gray-200 hover:text-rose-500 hover:bg-rose-50 transition-all"
                        title="Ištrinti iš istorijos"
                      >
                        <i className="fas fa-trash-can text-sm"></i>
                      </button>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {step === AppStep.ANALYSIS && <SummaryDashboard summaries={summaries} feedback={openFeedback} aiInsights={aiInsights} isAnalyzing={isAnalyzing} onNext={() => setStep(AppStep.REFLECTION)} />}

        {step === AppStep.REFLECTION && <ReflectionWizard reflection={reflection} setReflection={setReflection} aiInsights={aiInsights} onComplete={() => { saveToHistory(); setStep(AppStep.REPORT); }} onBack={() => setStep(AppStep.ANALYSIS)} onSaveAndExit={() => setStep(AppStep.UPLOAD)} />}

        {step === AppStep.REPORT && (
          <div className="max-w-4xl mx-auto bg-white p-10 md:p-16 rounded-[4rem] shadow-2xl animate-scale-in print:shadow-none print:p-0 print:m-0 print:rounded-none print:max-w-none">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-16 border-b border-gray-100 pb-12 print:pb-8 print:mb-10 gap-6">
              <div>
                <h2 className="text-4xl font-black text-gray-900 print:text-2xl">Refleksijos rezultatas</h2>
                <p className="text-gray-400 font-bold uppercase tracking-widest text-xs mt-2">{new Date().toLocaleDateString('lt-LT')}</p>
              </div>
              <div className="flex gap-3 w-full md:w-auto print:hidden">
                <button onClick={handleShare} className="flex-1 px-6 py-4 rounded-2xl border-2 border-indigo-50 text-indigo-600 font-black text-sm flex items-center justify-center gap-2 transition-all active:scale-95"><i className="fas fa-share"></i> Dalintis</button>
                <button onClick={() => window.print()} className="flex-1 px-6 py-4 rounded-2xl bg-indigo-600 text-white font-black text-sm flex items-center justify-center gap-2 shadow-xl shadow-indigo-100 transition-all active:scale-95"><i className="fas fa-file-pdf"></i> Atsisiųsti PDF</button>
              </div>
            </div>

            <div className="space-y-16 print:space-y-10">
              <section className="report-section grid md:grid-cols-2 gap-12 print:grid-cols-1 print:gap-8">
                <div className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-indigo-500">Pastebėjimai</h4>
                  <p className="text-gray-700 italic text-xl print:text-base leading-relaxed">"{reflection.observations || '-'}"</p>
                </div>
                <div className="space-y-4">
                  <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-emerald-500">Stiprybės</h4>
                  <p className="text-gray-700 text-xl font-medium print:text-base leading-relaxed">{reflection.strengths || '-'}</p>
