import React from 'react';
import { QuestionSummary } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LabelList } from 'recharts';

interface SummaryDashboardProps {
  summaries: QuestionSummary[];
  feedback: string[];
  aiInsights: any;
  isAnalyzing: boolean;
  onNext: () => void;
  onFinish: () => void;
}

const CustomYAxisTick = (props: any) => {
  const { x, y, payload } = props;
  const text = payload.value;
  const maxLength = 22;
  const displayValue = text.length > maxLength ? text.substring(0, maxLength) + '...' : text;

  return (
    <g transform={`translate(${x},${y})`}>
      <text x={-12} y={0} dy={4} textAnchor="end" fill="#64748b" fontSize={9} fontWeight={700} className="font-sans uppercase tracking-tight">
        <title>{text}</title>
        {displayValue}
      </text>
    </g>
  );
};

const SummaryDashboard: React.FC<SummaryDashboardProps> = ({ 
  summaries, 
  feedback, 
  aiInsights, 
  isAnalyzing,
  onNext,
  onFinish
}) => {
  const categories = [
    { name: 'Įsitraukimas', icon: 'fa-bolt-lightning' },
    { name: 'Mokymas', icon: 'fa-chalkboard-user' },
    { name: 'Klimatas', icon: 'fa-sun' },
    { name: 'Grįžtamasis ryšys', icon: 'fa-comments' },
    { name: 'Kita', icon: 'fa-ellipsis' }
  ];

  const getBarColor = (avg: number, isReverse?: boolean) => {
    if (isReverse) return avg > 3.5 ? '#f43f5e' : '#10b981';
    if (avg >= 4.5) return '#059669';
    if (avg >= 4.0) return '#10b981';
    if (avg >= 3.0) return '#6366f1';
    return '#f59e0b';
  };

  const getSentimentLabel = (score: number) => {
    if (score > 80) return { label: 'Itin pozityvus', color: 'text-emerald-500', icon: 'fa-laugh-beam' };
    if (score > 60) return { label: 'Pozityvus', color: 'text-green-500', icon: 'fa-smile' };
    if (score > 40) return { label: 'Neutralus', color: 'text-amber-500', icon: 'fa-meh' };
    return { label: 'Reikalaujantis dėmesio', color: 'text-rose-500', icon: 'fa-frown' };
  };

  return (
    <div className="max-w-4xl mx-auto space-y-12 animate-slide-up pb-20">
      <div className="grid md:grid-cols-4 gap-6">
        <div className="md:col-span-3 bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-6">
            <div className="w-16 h-16 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg shrink-0">
              <i className="fas fa-chart-pie text-2xl"></i>
            </div>
            <div>
              <h2 className="text-2xl font-black text-gray-900 tracking-tight">Analizės apžvalga</h2>
              <p className="text-gray-400 font-bold text-xs uppercase tracking-widest mt-1">
                {summaries[0]?.total || 0} mokinių atsakymai
              </p>
            </div>
          </div>
          <div className="flex gap-3 w-full md:w-auto">
             <button onClick={onFinish} className="flex-1 md:flex-none px-6 py-4 rounded-2xl border-2 border-indigo-50 text-indigo-600 font-black text-xs uppercase tracking-widest transition-all hover:bg-indigo-50">
               Baigti čia
             </button>
             <button 
              onClick={onNext}
              className="flex-1 md:flex-none bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-4 rounded-2xl font-black transition-all shadow-lg active:scale-95 flex items-center justify-center gap-3 text-xs uppercase tracking-widest"
            >
              Tęsti refleksiją <i className="fas fa-arrow-right"></i>
            </button>
          </div>
        </div>

        <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 flex flex-col justify-center items-center text-center">
          {isAnalyzing ? (
            <div className="animate-pulse flex flex-col items-center">
              <div className="w-8 h-8 bg-gray-100 rounded-full mb-2"></div>
              <div className="h-2 w-12 bg-gray-100 rounded"></div>
            </div>
          ) : (
            <>
              <div className={`text-2xl mb-1 ${getSentimentLabel(aiInsights?.sentimentScore || 50).color}`}>
                <i className={`fas ${getSentimentLabel(aiInsights?.sentimentScore || 50).icon}`}></i>
              </div>
              <h4 className="font-black text-gray-900 text-[11px] leading-tight">{getSentimentLabel(aiInsights?.sentimentScore || 50).label}</h4>
              <p className="text-[9px] text-gray-400 uppercase font-black tracking-widest mt-1">{aiInsights?.sentimentScore || 50}% Balas</p>
            </>
          )}
        </div>
      </div>

      <div className="bg-slate-900 rounded-[3rem] p-10 text-white shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 right-0 w-80 h-80 bg-indigo-500/10 blur-[100px] rounded-full"></div>
        <h3 className="text-xl font-black flex items-center gap-4 mb-8 relative z-10 uppercase tracking-widest text-[11px]">
          <i className="fas fa-wand-magic-sparkles text-indigo-400"></i> Dirbtinio intelekto įžvalgos
        </h3>

        {isAnalyzing ? (
          <div className="flex items-center gap-6 py-4 relative z-10">
            <div className="w-8 h-8 border-4 border-white/20 border-t-indigo-400 rounded-full animate-spin"></div>
            <p className="font-bold text-indigo-100">Analizuojama...</p>
          </div>
        ) : aiInsights && (
          <div className="space-y-12 relative z-10">
            <div className="grid md:grid-cols-2 gap-8">
              <div className="space-y-3">
                <h4 className="text-[10px] uppercase font-black tracking-widest text-emerald-400 flex items-center gap-2">
                  <i className="fas fa-check-circle"></i> Stipriosios vietos
                </h4>
                <p className="text-sm leading-relaxed text-indigo-50/90 font-medium">{aiInsights.strengths}</p>
              </div>
              <div className="space-y-3">
                <h4 className="text-[10px] uppercase font-black tracking-widest text-rose-400 flex items-center gap-2">
                  <i className="fas fa-arrow-trend-up"></i> Kur pasitempti?
                </h4>
                <p className="text-sm leading-relaxed text-indigo-50/90 font-medium">{aiInsights.improvements}</p>
              </div>
            </div>

            <div>
              <h4 className="text-[10px] uppercase font-black tracking-widest text-indigo-300 mb-6 flex items-center gap-2">
                <i className="fas fa-layer-group"></i> Tendencijos
              </h4>
              <div className="grid md:grid-cols-3 gap-4">
                {aiInsights.themes?.map((theme: any, idx: number) => (
                  <div key={idx} className="bg-white/5 p-4 rounded-2xl border border-white/5 backdrop-blur-sm">
                    <h5 className="font-black text-[11px] text-white leading-tight mb-2">{theme.label}</h5>
                    <p className="text-[10px] text-indigo-100/60 leading-normal">{theme.description}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}
      </div>

      <div className="space-y-8 max-w-2xl mx-auto">
        <div className="flex items-center gap-4 px-2">
          <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-[0.3em]">Statistika</h3>
          <div className="h-px flex-1 bg-gray-200/60"></div>
        </div>

        <div className="grid gap-10">
          {categories.map(cat => {
            const catData = summaries
              .filter(s => s.category === cat.name)
              .map(s => ({
                name: s.question,
                avg: parseFloat(s.averageScore.toFixed(2)),
                full: 5,
                isReverse: s.isReverse
              }))
              .sort((a, b) => b.avg - a.avg);

            if (catData.length === 0) return null;
            const chartHeight = Math.max(140, catData.length * 48);

            return (
              <div key={cat.name} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100">
                <h3 className="text-sm font-black text-gray-800 flex items-center gap-3 mb-8">
                  <i className={`fas ${cat.icon} text-indigo-500 text-xs`}></i> {cat.name}
                </h3>
                <div style={{ height: `${chartHeight}px` }}>
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={catData} layout="vertical" margin={{ left: 0, right: 40 }}>
                      <XAxis type="number" domain={[0, 5]} hide />
                      <YAxis dataKey="name" type="category" width={140} tick={<CustomYAxisTick />} axisLine={false} tickLine={false} />
                      <Tooltip />
                      <Bar dataKey="full" fill="#f1f5f9" radius={[0, 4, 4, 0]} barSize={14} isAnimationActive={false} />
                      <Bar dataKey="avg" radius={[0, 4, 4, 0]} barSize={14}>
                        {catData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={getBarColor(entry.avg, entry.isReverse)} />
                        ))}
                        <LabelList dataKey="avg" position="right" offset={12} style={{ fill: '#475569', fontSize: '10px', fontWeight: '900' }} />
                      </Bar>
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      <div className="flex justify-center pt-8 gap-4">
        <button 
          onClick={onFinish}
          className="bg-white border-2 border-indigo-100 text-indigo-600 px-12 py-6 rounded-[2rem] font-black transition-all shadow-xl active:scale-95"
        >
          Baigti ir išsaugoti tik analizę
        </button>
        <button 
          onClick={onNext}
          className="bg-indigo-600 hover:bg-indigo-700 text-white px-16 py-6 rounded-[2rem] font-black transition-all shadow-2xl shadow-indigo-200 active:scale-95 flex items-center gap-4 text-lg"
        >
          Tęsti refleksiją <i className="fas fa-chevron-right"></i>
        </button>
      </div>
    </div>
  );
};

export default SummaryDashboard;

import React, { useState, useEffect } from 'react';
import { AppStep, SurveyRow, QuestionSummary, LIKERT_VALUES, ReflectionData, CATEGORY_MAP, REVERSE_QUESTIONS } from './types';
import CSVUpload from './components/CSVUpload';
import SummaryDashboard from './components/SummaryDashboard';
import ReflectionWizard from './components/ReflectionWizard';
import { getAIInsights } from './services/geminiService';

const SESSION_DRAFT_KEY = 'teacher_reflection_session_v1';
const EXTERNAL_LINK = "https://sites.google.com/antakalnio.lt/ugdymokokybe/pagrindinis-puslapis";

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>(AppStep.UPLOAD);
  const [summaries, setSummaries] = useState<QuestionSummary[]>([]);
  const [openFeedback, setOpenFeedback] = useState<string[]>([]);
  const [aiInsights, setAiInsights] = useState<any>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [history, setHistory] = useState<any[]>([]);
  const [hasDraft, setHasDraft] = useState(false);
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [customTitle, setCustomTitle] = useState('');

  const [reflection, setReflection] = useState<ReflectionData>({
    observations: '', strengths: '', improvements: '', surprises: '',
    bestPractices: '', heartFeelings: '', headThoughts: '',
    actionStop: '', actionStart: '', actionContinue: '', nextSteps: ''
  });

  useEffect(() => {
    const savedHistory = localStorage.getItem('teacher_reflection_history');
    if (savedHistory) setHistory(JSON.parse(savedHistory));

    const draft = localStorage.getItem(SESSION_DRAFT_KEY);
    if (draft) setHasDraft(true);
  }, []);

  useEffect(() => {
    if (step !== AppStep.UPLOAD && step !== AppStep.REPORT) {
      const stateToSave = {
        step, summaries, openFeedback, aiInsights, reflection, timestamp: Date.now()
      };
      localStorage.setItem(SESSION_DRAFT_KEY, JSON.stringify(stateToSave));
    }
  }, [step, summaries, openFeedback, aiInsights, reflection]);

  const handleResumeSession = () => {
    const draftJson = localStorage.getItem(SESSION_DRAFT_KEY);
    if (draftJson) {
      try {
        const draft = JSON.parse(draftJson);
        setSummaries(draft.summaries || []);
        setOpenFeedback(draft.openFeedback || []);
        setAiInsights(draft.aiInsights || null);
        setReflection(draft.reflection);
        setStep(draft.step);
        setHasDraft(false);
      } catch (e) {
        localStorage.removeItem(SESSION_DRAFT_KEY);
      }
    }
  };

  const handleClearDraft = () => {
    localStorage.removeItem(SESSION_DRAFT_KEY);
    setHasDraft(false);
  };

  const saveToHistory = (title: string) => {
    const dateStr = new Date().toLocaleDateString('lt-LT');
    const newEntry = {
      id: Date.now(),
      date: new Date().toISOString(),
      displayDate: dateStr,
      title: title || `Refleksija ${dateStr}`,
      data: reflection,
      aiInsights: aiInsights,
      summaries: summaries,
      feedback: openFeedback
    };
    const updated = [newEntry, ...history].slice(0, 30);
    setHistory(updated);
    localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
    localStorage.removeItem(SESSION_DRAFT_KEY);
    setStep(AppStep.REPORT);
  };

  const deleteFromHistory = (id: number, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('Ar tikrai norite ištrinti šį įrašą?')) {
      const updated = history.filter(item => item.id !== id);
      setHistory(updated);
      localStorage.setItem('teacher_reflection_history', JSON.stringify(updated));
    }
  };

  const handleDataParsed = (rows: SurveyRow[]) => {
    processData(rows);
    setStep(AppStep.ANALYSIS);
  };

  const processData = (rows: SurveyRow[]) => {
    if (rows.length === 0) return;
    const rawHeaders = Object.keys(rows[0]);
    const newSummaries: QuestionSummary[] = [];
    const feedback: string[] = [];

    rawHeaders.forEach(rawHeader => {
      if (rawHeader.toLowerCase().includes('laiko žymė')) return;
      const cleanedHeader = rawHeader.match(/\[(.*?)\]/)?.[1] || rawHeader.trim();

      let sum = 0, validCount = 0, isNumeric = false;
      const counts: { [val: string]: number } = {};

      rows.forEach(row => {
        const val = row[rawHeader]?.trim();
        if (val) {
          counts[val] = (counts[val] || 0) + 1;
          const normalizedVal = val.endsWith('.') ? val.slice(0, -1) : val;
          if (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]) { 
            sum += (LIKERT_VALUES[normalizedVal] || LIKERT_VALUES[val]); 
            validCount++; 
            isNumeric = true; 
          }
        }
      });

      if (isNumeric && validCount > 0) {
        const categoryKey = Object.keys(CATEGORY_MAP).find(k => cleanedHeader.toLowerCase().includes(k.toLowerCase()));
        newSummaries.push({
          question: cleanedHeader,
          counts,
          total: rows.length,
          averageScore: sum / validCount,
          category: categoryKey ? CATEGORY_MAP[categoryKey] : 'Kita',
          isReverse: REVERSE_QUESTIONS.some(q => cleanedHeader.toLowerCase().includes(q.toLowerCase()))
        });
      } else {
        rows.forEach(row => { 
          const val = row[rawHeader]?.trim();
          if (val && val.length > 5 && !LIKERT_VALUES[val]) feedback.push(val); 
        });
      }
    });
    setSummaries(newSummaries);
    setOpenFeedback(feedback);
  };

  useEffect(() => {
    if (step === AppStep.ANALYSIS && summaries.length > 0 && !aiInsights) {
      setIsAnalyzing(true);
      getAIInsights(summaries, openFeedback).then(res => {
        setAiInsights(res);
        setIsAnalyzing(false);
      });
    }
  }, [step, summaries, aiInsights, openFeedback]);

  // Fix: Explicitly cast value to string to resolve trim() error on unknown type
  const hasReflectionContent = Object.values(reflection).some(v => (v as string).trim().length > 0);

  return (
    <div className="min-h-screen bg-slate-50 pb-20 print:bg-white print:pb-0">
      {/* Save Modal */}
      {showSaveModal && (
        <div className="fixed inset-0 z-[300] flex items-center justify-center p-4 bg-gray-900/60 backdrop-blur-md">
          <div className="bg-white rounded-[2.5rem] p-10 max-w-md w-full shadow-2xl animate-scale-in">
            <h3 className="text-2xl font-black mb-2 tracking-tight">Išsaugoti įrašą</h3>
            <p className="text-gray-500 mb-6 text-sm">Suteikite pavadinimą šiai analizei. Data bus pridėta automatiškai.</p>
            <input 
              type="text" 
              placeholder="Pvz.: 8A klasės apklausa" 
              className="w-full p-4 bg-gray-50 border-2 border-indigo-50 rounded-2xl mb-6 outline-none focus:border-indigo-500 transition-all font-bold"
              value={customTitle}
              onChange={(e) => setCustomTitle(e.target.value)}
              autoFocus
            />
            <div className="flex gap-3">
              <button onClick={() => setShowSaveModal(false)} className="flex-1 py-4 rounded-2xl bg-gray-100 font-black text-xs uppercase tracking-widest transition-all">Atšaukti</button>
              <button 
                onClick={() => { saveToHistory(customTitle); setShowSaveModal(false); }} 
                className="flex-1 py-4 rounded-2xl bg-indigo-600 text-white font-black text-xs uppercase tracking-widest shadow-xl transition-all"
              >
                Išsaugoti
              </button>
            </div>
          </div>
        </div>
      )}

      <header className="bg-white border-b border-gray-100 py-6 mb-8 print:hidden">
        <div className="container mx-auto px-6 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg"><i className="fas fa-graduation-cap"></i></div>
            <h1 className="text-xl font-black text-gray-900 tracking-tight">Refleksijos pagalbininkas</h1>
          </div>
          <div className="flex items-center gap-6">
            <a href={EXTERNAL_LINK} target="_blank" rel="noopener noreferrer" className="hidden md:flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-indigo-500 hover:text-indigo-700 transition-all">
              <i className="fas fa-external-link-alt"></i> Ugdymo kokybė
            </a>
            {step !== AppStep.UPLOAD && (
              <button onClick={() => window.location.reload()} className="text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-indigo-600 transition-colors">
                Nauja analizė
              </button>
            )}
          </div>
        </div>
      </header>

      <main className="container mx-auto px-6 print:px-0">
        {step === AppStep.UPLOAD && (
          <div className="max-w-4xl mx-auto space-y-12">
            <div className="text-center space-y-4">
              <h2 className="text-5xl font-black text-gray-900 tracking-tight">Mokslo metų analizė</h2>
              <p className="text-gray-500 max-w-lg mx-auto text-lg font-medium">Įkelk apklausos rezultatus ir leisk DI mentorystei nukreipti tavo augimą.</p>
            </div>

            {hasDraft && (
              <div className="bg-indigo-600 rounded-[2.5rem] p-8 text-white shadow-2xl animate-scale-in flex flex-col md:flex-row items-center justify-between gap-6">
                <div className="flex items-center gap-6">
                  <div className="w-14 h-14 bg-white/20 rounded-2xl flex items-center justify-center backdrop-blur-md"><i className="fas fa-rotate-left"></i></div>
                  <div>
                    <h3 className="text-xl font-black">Tęsti nebaigtą sesiją?</h3>
                    <p className="text-indigo-100/80 text-sm font-medium">Radome jūsų paskutinį nebaigtą darbą.</p>
                  </div>
                </div>
                <div className="flex gap-3">
                  <button onClick={handleClearDraft} className="px-6 py-4 rounded-2xl bg-white/10 font-black text-xs uppercase tracking-widest">Ištrinti</button>
                  <button onClick={handleResumeSession} className="px-10 py-4 rounded-2xl bg-white text-indigo-600 font-black text-xs uppercase tracking-widest shadow-xl">Tęsti</button>
                </div>
              </div>
            )}

            <CSVUpload onParsed={handleDataParsed} />

            {history.length > 0 && (
              <div className="space-y-4">
                <h3 className="text-xs font-black uppercase tracking-widest text-gray-400 px-2">Išsaugotos refleksijos</h3>
                <div className="grid md:grid-cols-2 gap-4">
                  {history.map(item => (
                    <div key={item.id} className="relative group">
                      <button 
                        onClick={() => { 
                          setReflection(item.data); 
                          setAiInsights(item.aiInsights); 
                          setSummaries(item.summaries);
                          setStep(AppStep.REPORT); 
                        }} 
                        className="w-full bg-white p-6 rounded-[2rem] border border-gray-100 text-left flex items-center justify-between hover:shadow-xl hover:border-indigo-100 transition-all pr-16"
                      >
                        <div>
                          <p className="font-black text-gray-800 text-lg leading-tight">{item.title}</p>
                          <p className="text-[10px] text-indigo-500 mt-1 uppercase font-black tracking-widest">{item.displayDate}</p>
                        </div>
                        <i className="fas fa-chevron-right text-gray-200 group-hover:text-indigo-500 transition-all"></i>
                      </button>
                      <button 
                        onClick={(e) => deleteFromHistory(item.id, e)}
